
/****** Object:  UserDefinedFunction [dbo].[billduration]    Script Date: 06-06-26 10:44:54 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[billduration] (@input VARCHAR(50))      
RETURNS VARCHAR(50)      
as begin      
declare @uid varchar(50)      
declare @out varchar(50)      
declare @cnt int      
declare @counter int      
declare @seconds int      
declare @total_seconds int    
set @total_seconds=0      
set @counter=1      
set @uid=@input  
DECLARE @bill TABLE    
 (    
    rn INT,    
    call_answer_time datetime,    
    call_end_time datetime    
 )  
 insert into @bill 
 select ROW_NUMBER() over(order by id asc) as rn, call_answer_time, call_end_time from Kit19CallsDialled where puniqueid=@uid and call_answer_time is not null and call_end_time is not null;       
select @cnt=COUNT(rn) from @bill   
if(@cnt>0)      
begin    
while (@counter <= @cnt)      
begin     
select @seconds=DATEDIFF(ss, call_answer_time, call_end_time) from @bill where rn=@counter;  
set @total_seconds=@total_seconds+@seconds;  
set @counter=@counter+1;      
end      
end    
SELECT @out=CAST(@total_seconds as varchar(50))      
return @out;      
END
GO

/****** Object:  UserDefinedFunction [dbo].[billduration1]    Script Date: 06-06-26 10:44:55 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[billduration1] (@input VARCHAR(50))        
RETURNS VARCHAR(50)        
as begin        
declare @uid varchar(50)        
declare @out varchar(50)        
declare @cnt int        
declare @counter int        
declare @seconds int        
declare @total_seconds int      
set @total_seconds=0        
set @counter=1        
set @uid=@input    
DECLARE @bill TABLE      
 (      
    rn INT,      
    call_answer_time datetime,      
    call_end_time datetime      
 )    
 insert into @bill   
 select ROW_NUMBER() over(order by id asc) as rn, call_answer_time, call_end_time from Kit19CallsDialled where puniqueid=@uid and call_answer_time is not null and call_end_time is not null and call_end_time>call_answer_time;         
select @cnt=COUNT(rn) from @bill  
if @cnt=0
begin
set @total_seconds=0
end   
else if(@cnt>0)        
begin      
select @total_seconds=sum(DATEDIFF(ss, call_answer_time,call_end_time)) from @bill where call_answer_time is not null and call_end_time is not null   
end        
      
SELECT @out=CAST(isnull(@total_seconds,0) as varchar(50))        
return @out;        
END
GO

