CREATE   FUNCTION [dbo].[build_mailContent]         
(        
 -- Add the parameters for the function here        
 @templateid BIGINT,        
 @CampaignID BIGINT,        
 @ParentID   BIGINT,         
 @MailContent     NVARCHAR(MAX),        
 @Mail_ToEmail   VARCHAR(MAX)      
 --@dbid int=null        
         
)        
RETURNS nvarchar(max)        
AS        
BEGIN        
--set @dbid=coalesce(@dbid,1)      
 -- Declare the return variable here        
 DECLARE @ResultVar nvarchar(max)   
 set @ResultVar = isnull('kit19.com/RedirectPage.aspx?TMPID='+        
 rtrim(Convert(nvarchar(100),@templateid))+'&cpmid='+        
 rtrim(Convert(nvarchar(100),@CampaignID))+'&pid='+rtrim(Convert(nvarchar(100),@ParentID))+'&mid='+        
 @Mail_ToEmail+'&','')        
 set @ResultVar = REPLACE(@MailContent,'RedirectPage.aspx?',@ResultVar)        
        
 -- Return the result of the function        
 RETURN @ResultVar        
        
END 
GO

