CREATE   FUNCTION [dbo].[callduration] (@inp VARCHAR(50))    
RETURNS VARCHAR(50)    
as begin    
declare @uid varchar(50)    
declare @out varchar(50)    
declare @st int    
set @out='0'    
set @uid=@inp;   
select @st=isnull(DATEDIFF(ss, call_start_time, call_end_time),0) from kit19calls where uniqueid=@uid and call_start_time is not null and call_start_time!='' and call_end_time is not null and call_end_time!='';
if(@st>0)
begin
set @out=CAST(@st as varchar(50))
end
return @out;    
END
