/****** Object:  UserDefinedFunction [dbo].[callstatus]    Script Date: 06-06-26 10:44:56 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[callstatus] (@inp VARCHAR(50))        
RETURNS VARCHAR(50)        
as begin        
declare @uid varchar(50)        
declare @out varchar(50)        
declare @cnt int        
declare @counter int        
set @counter=1        
set @uid=@inp;    
DECLARE @status TABLE      
 (      
    rn INT,      
    dialstatus varchar(50)     
 )    
 insert into @status 
 select ROW_NUMBER() over(order by id asc) as rn, case when call_answer_time is not null then 'ANSWER' else dialstatus end from Kit19CallsDialled where puniqueid=@uid;         
select @cnt=COUNT(rn) from @status     
if(@cnt>0)        
begin      
while (@counter <= @cnt)        
begin       
select @out=dialstatus from @status where rn=@counter;    
if(@out='ANSWER')    
begin    
break;    
end    
set @counter=@counter+1;        
end        
end      
if(@out is null)    
begin    
set @out='NOANSWER';    
end    
if(@out='')    
begin    
set @out='NETWORK ERROR';    
end   
return @out;        
END
GO

/****** Object:  UserDefinedFunction [dbo].[callstatus1]    Script Date: 06-06-26 10:44:56 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--select [dbo].[callstatus1] ('1616414881.1697297')
CREATE   FUNCTION [dbo].[callstatus1] --('1616414881.1697297')
 (@inp VARCHAR(50))            
RETURNS VARCHAR(50)            
as begin            
declare @uid varchar(50)            
declare @out varchar(50)            
declare @cnt int            
declare @counter int            
set @counter=1            
set @uid=@inp;        
DECLARE @status TABLE          
 (          
    rn INT,          
    dialstatus varchar(50)         
 )        
 declare @accountcode bigint,@record nvarchar(1000),@callsid bigint
 select @accountcode=accountcode,@record=recordurl,@callsid=id from kit19calls(nolock) where uniqueid=@uid
if isnull(@accountcode,'')<>''
begin
insert into @status     
select 1 as rn, disposition from DiallerCalls where kit19callsid=@callsid;             
end
else
begin
insert into @status     
select ROW_NUMBER() over(order by id asc) as rn, case when call_answer_time is not null then 'ANSWER' else dialstatus end from Kit19CallsDialled(nolock) where puniqueid=@uid order by id desc;             
end
select @cnt=COUNT(rn) from @status   
if @cnt=0  
begin  
set @out='NO ANSWER'  
end  
else if exists(select 1 from @status where dialstatus='ANSWER')        
begin  
set @out='ANSWER'  
end  
else   
begin          
select top 1 @out=dialstatus from @status order by rn;        
if(@out='')        
begin        
set @out='NETWORK ERROR';        
end  
end                
return @out;            
END

