CREATE   FUNCTION [dbo].[Cloud_CheckUserPhoneActivated]   
(  
 @userid bigint  
)  
RETURNS varchar(max)  
AS  
BEGIN  
declare @Result varchar(max)  
set @Result=''  
declare @Temp TABLE   
(  
PhoneNo varchar(20),  
notsubscribedNo varchar(20)  
 )  
  
declare @agentno float,@pid bigint  
select @agentno =  mobile,@pid=parentid from user_detail where USER_ID=@userid  
  
insert into @Temp  
select PhoneNo,0 notsubscribedNo from cloud_user_phone where Parentid=@pid  
  
update @Temp set notsubscribedNo=case when cast(cast(@agentno as bigint) as nvarchar) = c.Agent_No then 1 else 0 end    
 From @Temp t left join Cloud_DIDObtain c on   
   t.PhoneNo=c.DIDNo  
  
--select @return=case when 0 in ( select distinct issubscribed from cloud_user_phonetb) then 0 else 1 end  
  
SELECT  
    @Result = CASE  
        WHEN @Result =''  
        THEN T.PhoneNo  
        ELSE @Result + ',' + T.PhoneNo  
    END  
FROM  
    @Temp AS T  
WHERE  
    T.notsubscribedNo = 0;  
  
  -- Start New code included
 if( exists
  (
    --select 1 from @Temp as P where P.notsubscribedNo = 1)
   SELECT  1  
   From @Temp t  join Cloud_DIDObtain c on   
   t.PhoneNo=c.DIDNo 
   WHERE C.ParentId  = @pid
   and cast(cast(@agentno as bigint) as nvarchar ) =  (c.Agent_No)
  ))
  Begin
      set @Result = ''
  End
  -- End New code included
   
RETURN @Result  
  
END  
  
  
