/****** Object:  UserDefinedFunction [dbo].[Cloud_getvoicefl]    Script Date: 06-06-26 10:44:59 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[Cloud_getvoicefl] --18  
 (  
    @id int,  
    @user_id bigint ,  
    @opt int  
 )  
RETURNS varchar(32)  
AS  
BEGIN  
declare @vf int, @flow varchar(max)=''  
select @vf=CHARINDEX('filename', flow),@flow = flow from dbo.Cloud_flow_api where Appid= 18  
if @vf > 0  
begin  
select @flow =SUBSTRING( @flow, @vf, LEN(@flow)-@vf )  
  
select @vf=CHARINDEX(',', @flow)  
select @flow =SUBSTRING( @flow,1, @vf-2 )  
  
select @vf=CHARINDEX(':', @flow)  
select @flow =SUBSTRING( @flow, @vf+2, LEN(@flow)-(@vf) )  
if @opt = 0  
select @flow=R_url from dbo.Cloud_PlayFile where name =@flow and clientid = @user_id  
else  
select @flow=VText from dbo.Cloud_PlayFile where name =@flow and clientid = @user_id  
  
end  
RETURN   @flow  
  
END   
  
  
  
GO

