/****** Object:  UserDefinedFunction [dbo].[cnvt_todt]    Script Date: 06-06-26 10:44:59 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[cnvt_todt] 
(
	@dte varchar(20)
)
returns nvarchar(20)  
as 
begin
declare @dtel varchar(20) = '2017-08-18'
set @dtel= @dte

if @dte!= ''
begin
declare @sep as varchar(1) = '-'
--declare @dtel varchar(20) ='08-18-2017' -- '2017-08-18'
if  CHARINDEX(@sep, @dtel) <= 0
begin
set @sep = '/'
end 
declare @stpos int=0, @lpos int =0
select @stpos = CHARINDEX(@sep, @dtel)
declare @fdt varchar(4)= '',@sdt varchar(4)= '', @ldt varchar(4)= ''

set @fdt = LEFT(@dtel,@stpos-1)
--select @fdt
set @dtel = SUBSTRING(@dtel,@stpos+1,len(@dtel)-@stpos)
--select @dtel
select @lpos = CHARINDEX(@sep, @dtel)
set @sdt = LEFT(@dtel,@lpos-1)
set @ldt = SUBSTRING(@dtel,@lpos+1,len(@dtel)-@lpos)
--select @dtel,@stpos,@fdt,@sdt,@ldt

if LEN(@fdt) = 4
begin
set @dtel = @fdt+'-'+@ldt+'-'+@sdt
end
else
begin
	set @dtel = @ldt+'-'+@fdt+'-'+@sdt
end
end
return @dtel

end
GO

/****** Object:  UserDefinedFunction [dbo].[ConvertFBCreateTimeToIST]    Script Date: 06-06-26 10:45:00 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[ConvertFBCreateTimeToIST] (@UtcDateTimeString NVARCHAR(30))
RETURNS DATETIME
AS
BEGIN
    DECLARE @DateTimeUTC DATETIME;
    DECLARE @DateTimeIST DATETIME;
    
    -- Remove the timezone information (+0000) and convert to DATETIME
    SET @UtcDateTimeString = LEFT(@UtcDateTimeString, 19);
    SET @DateTimeUTC = CONVERT(DATETIME, @UtcDateTimeString, 126);

    -- Convert UTC to IST by adding 5 hours and 30 minutes
    SET @DateTimeIST = DATEADD(MINUTE, 330, @DateTimeUTC);

    RETURN @DateTimeIST;
END
GO

/****** Object:  UserDefinedFunction [dbo].[ConvertSecondsToHHmm]    Script Date: 06-06-26 10:45:00 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[ConvertSecondsToHHmm] (@TotalSeconds INT)
RETURNS VARCHAR(10)
AS
BEGIN
	--declare @TotalSeconds int = 648375
    DECLARE @Hours INT
    DECLARE @Minutes INT
    DECLARE @HHmm VARCHAR(10)

    -- Calculate the hours and minutes
    SET @Hours = @TotalSeconds / 3600
    SET @Minutes = (@TotalSeconds % 3600) / 60

	--print @Hours
	--print @Minutes

    -- Format the result as HH:mm
	--set @
    SET @HHmm =CAST(@Hours AS VARCHAR) + ':' + 
                RIGHT('00' + CAST(@Minutes AS VARCHAR(2)), 2)

	--select @HHmm
	--180:06

	RETURN @HHmm
	
END

GO

