CREATE   FUNCTION [dbo].[dateconvert1](@date1 DATETIME)
returns nvarchar(200)
as
begin
declare @return nvarchar(200)
SELECT @return=(select substring(convert(varchar(10),@date1,111),len(convert(varchar(10),@date1,111))-1,2) + '-'
+ substring(convert(varchar(20),@date1,0),1,3)+'-'+substring(convert(varchar(10),@date1,111),1,4)as Date)

return @return

end

