/****** Object:  UserDefinedFunction [dbo].[edit_distance_within]    Script Date: 06-06-26 10:45:01 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

  
CREATE   FUNCTION [dbo].[edit_distance_within](@s nvarchar(4000), @t nvarchar(4000), @d int)  
RETURNS int  
AS  
BEGIN  
  
  DECLARE @sl int, @tl int, @i int, @j int, @sc nchar, @c int, @c1 int,  
    @cv0 nvarchar(4000), @cv1 nvarchar(4000), @cmin int  
  SELECT @sl = LEN(@s), @tl = LEN(@t), @cv1 = '', @j = 1, @i = 1, @c = 0  
  WHILE @j <= @tl  
    SELECT @cv1 = @cv1 + NCHAR(@j), @j = @j + 1  
  WHILE @i <= @sl  
  BEGIN  
    SELECT @sc = SUBSTRING(@s, @i, 1), @c1 = @i, @c = @i, @cv0 = '', @j = 1, @cmin = 4000  
    WHILE @j <= @tl  
    BEGIN  
      SET @c = @c + 1  
      SET @c1 = @c1 - CASE WHEN @sc = SUBSTRING(@t, @j, 1) THEN 1 ELSE 0 END  
      IF @c > @c1 SET @c = @c1  
      SET @c1 = UNICODE(SUBSTRING(@cv1, @j, 1)) + 1  
      IF @c > @c1 SET @c = @c1  
      IF @c < @cmin SET @cmin = @c  
      SELECT @cv0 = @cv0 + NCHAR(@c), @j = @j + 1  
    END  
    IF @cmin > @d BREAK  
    SELECT @cv1 = @cv0, @i = @i + 1  
  END  
  --RETURN CASE WHEN @cmin <= @d AND @c <= @d THEN @c ELSE -1 END  
  --edited the above case to suit our use case  
  RETURN CASE WHEN @cmin <= @d AND @c <= @d THEN @c ELSE @d END  
END  
GO

/****** Object:  UserDefinedFunction [dbo].[edit_distance_within_withvariable]    Script Date: 06-06-26 10:45:01 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

    
CREATE   FUNCTION [dbo].[edit_distance_within_withvariable](@s nvarchar(4000), @t nvarchar(4000), @d int)    
RETURNS int    
AS    
BEGIN    
    
  DECLARE @sl int, @tl int, @i int, @j int, @sc nchar, @c int, @c1 int,    
    @cv0 nvarchar(4000), @cv1 nvarchar(4000), @cmin int    
  SELECT @sl = LEN(@s), @tl = LEN(@t), @cv1 = '', @j = 1, @i = 1, @c = 0    
  WHILE @j <= @tl    
    SELECT @cv1 = @cv1 + NCHAR(@j), @j = @j + 1    
  WHILE @i <= @sl    
  BEGIN    
    SELECT @sc = SUBSTRING(@s, @i, 1), @c1 = @i, @c = @i, @cv0 = '', @j = 1, @cmin = 4000    
    WHILE @j <= @tl    
    BEGIN    
      SET @c = @c + 1    
      SET @c1 = @c1 - CASE WHEN @sc = SUBSTRING(@t, @j, 1) THEN 1 ELSE 0 END    
      IF @c > @c1 SET @c = @c1    
      SET @c1 = UNICODE(SUBSTRING(@cv1, @j, 1)) + 1    
      IF @c > @c1 SET @c = @c1    
      IF @c < @cmin SET @cmin = @c    
      SELECT @cv0 = @cv0 + NCHAR(@c), @j = @j + 1    
    END    
    IF @cmin > @d BREAK    
    SELECT @cv1 = @cv0, @i = @i + 1    
  END    
  --RETURN CASE WHEN @cmin <= @d AND @c <= @d THEN @c ELSE -1 END    
  --edited the above case to suit our use case    
  RETURN CASE WHEN @cmin <= @d AND @c <= @d THEN @c ELSE @d END    
END 
GO

/****** Object:  UserDefinedFunction [dbo].[ExtractPlaceholders]    Script Date: 06-06-26 10:45:02 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[ExtractPlaceholders]
(
	@entity    NVARCHAR(20), 
	@inputText NVARCHAR(MAX)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @outputText NVARCHAR(MAX)= '';
    DECLARE @startPos INT;
    DECLARE @endPos INT;
    DECLARE @placeholder NVARCHAR(100);
    DECLARE @entity_offsetPos INT= LEN(@entity) + 2;

    -- Initialize the starting position     
    SET @startPos = CHARINDEX('#' + @entity + '.', @inputText);
    
	WHILE @startPos > 0
    BEGIN
        -- Find the end position of the placeholder
        SET @endPos = CHARINDEX('#', @inputText, @startPos + @entity_offsetPos);
        
		-- Skip past '#lead.'          
        -- Check if end position is valid
        IF @endPos > @startPos
        BEGIN
            -- Extract the placeholder
            SET @placeholder = SUBSTRING(@inputText, @startPos, @endPos - @startPos + 1);
            -- Add the placeholder to the output string, followed by a comma
            SET @outputText = @outputText + @placeholder + ',';
        END;
    
		-- Move to the next placeholder
        SET @startPos = CHARINDEX('#' + @entity + '.', @inputText, @endPos + 1);
    END;

    -- Remove the trailing comma
    IF LEN(@outputText) > 0
    BEGIN
        SET @outputText = LEFT(@outputText, LEN(@outputText) - 1);
    END;

    RETURN @outputText;
END;

GO

/****** Object:  UserDefinedFunction [dbo].[fn_Ai_GetFinalJsonByAgentId]    Script Date: 06-06-26 10:45:02 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_Ai_GetFinalJsonByAgentId]
(
    @agentId BIGINT
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @finalJson NVARCHAR(MAX) = '{}';
    DECLARE @goalId BIGINT;
    DECLARE @goalSetting NVARCHAR(MAX) = '{}';
    DECLARE @mileStone NVARCHAR(MAX) = '{}';
    DECLARE @goalSlots NVARCHAR(MAX) = '{}';
    DECLARE @fullfillmentTarget NVARCHAR(MAX) = '{}';

    -- Get Goal Setting JSON
    SELECT @goalSetting = DetailsJson
    FROM tbl_ai_Goals WITH (NOLOCK)
    WHERE AgentId = @agentId;

    SET @finalJson = @goalSetting;

    -- Get GoalId
    SELECT @goalId = GoalId
    FROM tbl_ai_Goals WITH (NOLOCK)
    WHERE AgentId = @agentId;

    -- Add GoalId
    SET @finalJson = JSON_MODIFY(@finalJson, '$.goalId', @goalId);

    -- Add Milestones
    SET @mileStone = (
        SELECT 
            MilestoneId AS [milestoneId],
            [Order] AS [order],
            [Name] AS [name],
            [Description] AS [description]
        FROM tbl_ai_GoalMilestones WITH (NOLOCK)
        WHERE GoalId = @goalId
        FOR JSON PATH
    );

    SET @finalJson = JSON_MODIFY(@finalJson, '$.milestones', JSON_QUERY(@mileStone));

    -- Add Goal Slots
    SET @goalSlots = (
        SELECT 
            SlotId AS [slotId],
            JSON_VALUE(DetailsJson, '$.name') AS [name],
            JSON_VALUE(DetailsJson, '$.label') AS [label],
            JSON_VALUE(DetailsJson, '$.mandatory') AS [mandatory],
            JSON_VALUE(DetailsJson, '$.updatable') AS [updatable]
        FROM dbo.tbl_ai_GoalSlots WITH (NOLOCK)
        WHERE GoalId = @goalId
        FOR JSON PATH
    );

    SET @finalJson = JSON_MODIFY(@finalJson, '$.slots', JSON_QUERY(@goalSlots));

    -- (Optional) You can add triggers or other sections here if needed
    -- Example:
    -- DECLARE @triggers NVARCHAR(MAX) = (
    --     SELECT TriggerId, Name, Condition
    --     FROM tbl_ai_Triggers WITH (NOLOCK)
    --     WHERE GoalId = @goalId
    --     FOR JSON PATH
    -- );
    -- SET @finalJson = JSON_MODIFY(@finalJson, '$.triggers', JSON_QUERY(@triggers));

    RETURN @finalJson;
END

GO

