/****** Object:  UserDefinedFunction [dbo].[fn_build_ps_mail_command]    Script Date: 06-06-26 10:45:03 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_build_ps_mail_command] (
    @to NVARCHAR(MAX),
    @subject NVARCHAR(MAX),
    @body NVARCHAR(MAX),
    @bcc NVARCHAR(MAX) = NULL,
    @cc NVARCHAR(MAX) = NULL,
    @from NVARCHAR(MAX) = NULL,
    @body_format NVARCHAR(20) = NULL,
    @csv_path NVARCHAR(400) = NULL,
    @attachment_name NVARCHAR(200) = NULL
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @ps NVARCHAR(MAX)
    SET @ps = 'powershell -ExecutionPolicy Bypass -File "C:\MailScripts\SendDynamicEmail.ps1"'
    SET @ps += ' -To "' + REPLACE(@to, ',', '","') + '"'
    SET @ps += ' -Subject "' + REPLACE(@subject, '"', '""') + '"'
    SET @ps += ' -Body "' + REPLACE(@body, '"', '""') + '"'
    IF @bcc IS NOT NULL AND LEN(@bcc) > 0 SET @ps += ' -Bcc "' + REPLACE(@bcc, ',', '","') + '"'
    IF @cc IS NOT NULL AND LEN(@cc) > 0 SET @ps += ' -Cc "' + REPLACE(@cc, ',', '","') + '"'
    IF @from IS NOT NULL AND LEN(@from) > 0 SET @ps += ' -From "' + @from + '"'
    IF @body_format IS NOT NULL AND UPPER(@body_format) = 'HTML' SET @ps += ' -BodyIsHtml'
    IF @csv_path IS NOT NULL AND LEN(@csv_path) > 0 SET @ps += ' -CsvPath "' + @csv_path + '"'
    IF @attachment_name IS NOT NULL AND LEN(@attachment_name) > 0 SET @ps += ' -AttachmentName "' + @attachment_name + '"'
    RETURN @ps
END

GO

