select @comparisonvalue=count(1) from kit19calls (nolock) k join Kit19CallsDialled(nolock) c on k.uniqueid=c.puniqueid where c.dialstatus='answer'              
end              
end              
else if @eventid in (9,17,18,19)--Lead edited/added/merged              
begin select @leadid=0   
declare @fieldtype nvarchar(10)              
select @fieldtype=case when exists (select 1 from sys.tables t join sys.columns c on t.object_id=c.object_id where t.name='userleads' and c.name=@Attribute) then 'main'               
else 'custom' end              
select @comparisonvalue=case when @fieldtype='main' then cast((select quotename(@attribute) from userleads(nolock) where id=@leadid) as nvarchar(max))              
else cast((select top 1 fieldvalue from customfieldLeadvalue(nolock) where leadid=@leadid and fieldID=(select fieldid from customfields(nolock) where ParentID=@parentid and isActive=1 and fieldname=@Attribute)) as nvarchar(max)) end               
end              
else if @eventid in (11,13,14)--lead raises,updates or resolves ticket               
begin               
select @comparisonvalue=(select [type_desc] from serv_tickethistory(nolock) h join Serv_TicketType_Mast t on t.Type_Desc=h.Ticket_type where TicketHistoryID=@refids)              
end              
--else if @eventid=13--lead updates ticket              
