select @comparisonvalue=(select  datediff(d,getdate(),isnull(scheduleddate,batchinserttime))from batchinfo(nolock) where batchid=@batchid)      
end      
else if @attribute='totalcount' and not exists(select 1 from lead_score_history(nolock) where leadid=@leadid and rule_id=@ruleid)      
begin      
select @comparisonvalue =(select count(distinct refids) from tbl_LeadEventHistory(nolock) where eventid=@eventid and LeadID=@leadid)      
end      
end      
else if @eventid=4--Lead Opens mail      
begin       
select @comparisonvalue=(select top 1 mailsubject from mysmst.dbo.tbl_email(nolock) where issent=1 and messageid=(select messageid from mysmst.dbo.Tbl_EmailTracking(nolock) where id=@refids) order by id desc)      
end      
else if @eventid=5--Lead visits a mail link      
begin       
select @comparisonvalue=(select RedirectUrl from mysmst.dbo.Tbl_EmaillinkTracking(nolock) where id=@refids)      
end      
else if @eventid in (6,7)--Voice sent/Call made to lead      
begin       
declare @uniqueid nvarchar(20)=(select uniqueid from kit19calls(nolock) where id=(select refids from tbl_LeadEventHistory(nolock) where id=@activityid))      
if exists(select 1 from Kit19CallsDialled(nolock) where dialstatus='answer' and puniqueid=@uniqueid)      
select @comparisonvalue=@Value      
end      
else if @eventid=8--Lead calls up      
begin select @leadid=0      
if @attribute='incoming call completed'      
begin      
declare @iuniqueid nvarchar(20)=(select uniqueid from kit19calls(nolock) where id=(select refids from tbl_LeadEventHistory(nolock) where id=@activityid))      
if exists(select 1 from Kit19CallsDialled(nolock) where dialstatus='answer' and puniqueid=@iuniqueid)      
select @comparisonvalue=@Value      
end      
else if @attribute='incoming call completed' and not exists(select 1 from lead_score_history(nolock) where rule_id=@ruleid and leadid=@leadid)      
begin      
select @comparisonvalue=count(1) from kit19calls (nolock) k join Kit19CallsDialled(nolock) c on k.uniqueid=c.puniqueid where c.dialstatus='answer'      
end      
end      
else if @eventid in (9,17,18,19)--Lead edited/added/merged      
begin select @leadid=0      
declare @fieldtype nvarchar(10)      
select @fieldtype=case when exists (select 1 from sys.tables t join sys.columns c on t.object_id=c.object_id where t.name='userleads' and c.name=@Attribute) then 'main'       
else 'custom' end      
select @comparisonvalue=case when @fieldtype='main' then cast((select quotename(@attribute) from userleads(nolock) where id=@leadid) as nvarchar(max))      
else cast((select top 1 fieldvalue from customfieldLeadvalue(nolock) where leadid=@leadid and fieldID=(select fieldid from customfields(nolock) where ParentID=@parentid and isActive=1 and fieldname=@Attribute)) as nvarchar(max)) end       
end      
else if @eventid in (11,13,14)--lead raises,updates or resolves ticket       
begin       
select @comparisonvalue=(select [type_desc] from serv_tickethistory(nolock) h join Serv_TicketType_Mast t on t.Type_Desc=h.Ticket_type where TicketHistoryID=@refids)      
end      
--else if @eventid=13--lead updates ticket      
--begin select @leadid=0      
      
--end      
--else if @eventid=14--lead's ticket resolved      
--begin select @leadid=0      
--end      
else if @eventid=16--lead signs up on eshop      
begin select @leadid=0      
end      
else if @eventid=20--lead places order      
begin select @leadid=0      
end      
else if @eventid=21--lead cancels order      
begin select @leadid=0      
end      
else if @eventid=25--lead reviewed product      
begin select @leadid=0      
end      
else if @eventid=27--lead filled webform      
begin select @leadid=0      
end      
else if @eventid=34--lead requested return      
begin select @leadid=0      
end      
else if @eventid=35--lead reviews ticket      
begin       
select @comparisonvalue=case when rating='excellent' then 5 when rating='very good' then 4 when rating='good' then 3 when rating='average' then 2 else 1 end from Serv_ticket_feedback_tbl(nolock) where id=@refids      
end      
else if @eventid in (38,39)--lead added to group/segment      
begin       
select @comparisonvalue=SearchName from UserSearchList(nolock) where id=@refids      
end      
/*      
else if @eventid=39--lead removed from group      
begin select @leadid=0      
end      
*/      
else if @eventid=40--lead unsubscribes mail      
begin     
select @comparisonvalue=@Value    
end      
else if @eventid in (41,45,50,42,43,45,51,44)--task added/deleted/edited      
begin       
declare @tasktype nvarchar(100),@taskstatus nvarchar(100)      
select @tasktype=Taskname,@taskstatus=isnull(u.OutcomeName,'')       
from tbl_tsk_TaskHistory(nolock) t join tbl_tsk_UserTaskMaster m(nolock) on m.id=t.TaskId       
left join tbl_tsk_UserOutcomeMaster u(nolock) on u.Id=t.OutcomesId      
where t.Id=@refids      
if @attribute='task type'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='task status'),@taskstatus)=@taskstatus then @tasktype       
else null end      
end      
if @Attribute='task status'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='task type'),@tasktype)=@tasktype then @taskstatus      
else null end      
end      
if @Attribute='count'  and not exists(select 1 from lead_score_history(nolock) where leadid=@leadid and rule_id=@ruleid )       
select @comparisonvalue=count(1) from tbl_tsk_TaskHistory(nolock) t join tbl_tsk_UserTaskMaster m(nolock) on m.id=t.TaskId       
left join tbl_tsk_UserOutcomeMaster u(nolock) on u.Id=t.OutcomesId where t.LeadId=@leadid and       
isnull((select value from @rulesparsed where attribute='task type'),m.taskname)=m.taskname and      
isnull((select value from @rulesparsed where attribute='task status'),u.OutcomeName)=u.OutcomeName       
and 1=case when @eventid in (42,44) and t.CompletedOn is null then 0 else 1 end      
end      
/*      
else if @eventid=42--task compeleted      
begin select @leadid=0      
end      
else if @eventid in (43,45,51,53)--appointment added/deleted/edited      
begin select @leadid=0      
end      
else if @eventid=44--appointment completed      
begin select @leadid=0      
end      
*/      
else if @eventid in (47,54,55,48)--add pipeline stage,deal added,dealupdated, deal deleted      
begin       
declare @dealvalue int,@pipelineid int,@pipelinestageid int      
select @pipelineid=PipelineID,@pipelinestageid=PipeLineStage,@dealvalue=Amount from LeadPipelineMapping(nolock) where id=@refids      
if @attribute='pipeline'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline stage'),@pipelinestageid)=@pipelinestageid      
and isnull((select value from @rulesparsed where attribute='deal value'),@dealvalue)>=@dealvalue then @pipelineid else null end      
end      
else if @attribute='pipeline stage'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline'),@pipelineid)=@pipelineid      
and isnull((select value from @rulesparsed where attribute='deal value'),@dealvalue)>=@dealvalue then @pipelinestageid else null end      
end      
else if @attribute='deal value'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline'),@pipelineid)=@pipelineid      
and isnull((select value from @rulesparsed where attribute='pipeline stage'),@pipelinestageid)=@pipelinestageid then @dealvalue else null end      
end      
else if @attribute='pipeline count' and not exists(select 1 from lead_score_history(nolock) where leadid=@leadid and rule_id=@ruleid)      
begin      
select @comparisonvalue=count(distinct pipelineid) from LeadPipelineMapping(nolock) where leadid=@leadid       
end      
if @attribute='pipeline deleted'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline stage deleted'),@pipelinestageid)=@pipelinestageid      
and isnull((select value from @rulesparsed where attribute='deal value'),@dealvalue)>=@dealvalue then @pipelineid else null end      
end      
else if @attribute='pipeline stage deleted'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline deleted'),@pipelineid)=@pipelineid      
and isnull((select value from @rulesparsed where attribute='deal value'),@dealvalue)>=@dealvalue then @pipelinestageid else null end      
end      
else if @attribute='deal value'      
begin      
select @comparisonvalue=case when isnull((select value from @rulesparsed where attribute='pipeline'),@pipelineid)=@pipelineid      
and isnull((select value from @rulesparsed where attribute='pipeline stage'),@pipelinestageid)=@pipelinestageid then @dealvalue else null end      
end      
else if @attribute='pipeline deleted count' and not exists(select 1 from lead_score_history(nolock) where leadid=@leadid and rule_id=@ruleid)      
begin      
select @comparisonvalue=count(distinct pipelineid) from LeadPipelineMapping(nolock) where leadid=@leadid and IsDeleted=1      
end      
end      
/*      
else if @attribute='total deal value' and not exists(select 1 from lead_score_history(nolock) where leadid=@leadid and rule_id=@ruleid)      
begin      
select @comparisonvalue=count(distinct pipelineid) from LeadPipelineMapping(nolock) where leadid=@leadid       
end      
*/      
/*      
else if @eventid=48--delete pipeline stage      
      
      
end      
else if @eventid=54--deal added      
begin select @leadid=0      
end      
else if @eventid=55--deal updated      
begin select @leadid=0      
end      
else if @eventid=56--deal deleted      
begin select @leadid=0      
end      
*/      
else if @eventid in (57,58)--lead sends mail,lead replies to mail      
begin       
select @comparisonvalue=(select MailSubject from mysmst.dbo.tbl_email(nolock) where id=@refids)      
end      
/*      
else if @eventid=57--lead sends mail      
begin       
select @leadid=0      
end      
*/      
select @comparisonvalue=isnull(@comparisonvalue,@value)      
select @matches=@matches+case when dbo.fnCompare2Values(@comparisonvalue,@op,@value)=1 then 1 else 0 end      
end 
     
  select @leadid=case when @matches =@id then 1 else 0 end      
 --    return @leadid      
	      
  End
 else
  Begin
    select @LeadId = 1
 --   return @leadid
  End

  return @leadid 
    
 end
	
	
	  
      
--select * from ActivityMaster where id>=57      
--insert into ActivityMaster(eventname,EventTemplate,EventType)      
--select 'Mail replied by Lead',eventtemplate ='#leadname# has replied to a mail sent by #username# with subject "#MailSubject#" to emailid #emailid# ',eventtype='email' --where id=57      
      
--select top 10 * from lead_scoring_rules      
--select top 10 * from Link_smsTrack      
--select top 10 * from Link_smsMobile      
      
      
      
--sp_depends serv_ticket_feedback_tbl      
      
--select top 10 * from VisitPageDetails(nolock) where pagename like '%mobile=%'      
--select top 10 * from WebFormTbl(nolock)  
  
  
 -- select quotename(personname) from userleads(nolock) where id=671791  
  
GO

/****** Object:  UserDefinedFunction [dbo].[fn_CheckPlanConstraints]    Script Date: 06-06-26 10:45:04 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_CheckPlanConstraints]
(
    @UserId BIGINT,
    @opt VARCHAR(50)
)
RETURNS INT
AS
BEGIN
    DECLARE @planid BIGINT;
    DECLARE @userCount INT = 0;
    DECLARE @actualCount INT = 0;
    DECLARE @ParentId BIGINT;
    DECLARE @virtualCount INT = 0;

        IF (@UserId = 335)
            RETURN 1;

        IF (@opt = 'user')
        BEGIN
            SELECT @planid = planid FROM Price_UserSubscriptionDetails (nolock) WHERE userid = @UserId;

            SELECT TOP 1 @userCount = ISNULL(AllowUserCount, 0) 
            FROM tbl_pt_AllowUserTransactions (nolock) WHERE UserID = @UserId ORDER BY CreatedOn DESC;

            SELECT @ParentId = ParentID  FROM user_detail (NOLOCK) WHERE user_id = @UserId;

            SELECT @actualCount = COUNT(1)  FROM User_Detail (nolock) WHERE ParentID = @ParentId AND Cloudrole <> 0 AND status = 1;

            SET @virtualCount = @userCount - @actualCount;

            IF (@virtualCount >= 1)
                RETURN 1;
            ELSE
                RETURN 0;
        END
   RETURN 1;
END;

GO

/****** Object:  UserDefinedFunction [dbo].[fn_comparetemplate]    Script Date: 06-06-26 10:45:05 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_comparetemplate](@a nvarchar(max),@b nvarchar(max))      
returns int      
as      
begin      
  
declare @c int,@matches int=0,@p int,@m int=0,@am int=0,@aexp nvarchar(2000)      
if @a=@b  
select @matches=1  
else  
begin 
if substring(@a,1,1)='%'
begin
select @a=dbo.fn_trimprefixes(@a,'%')
declare @fs nvarchar(1000)=substring(@a,1,case when charindex('%',@a,1)>0 then charindex('%',@a,1) else len(@a) end)
--select @fs
select @b=right(@b,len(@b)-charindex(@fs,@b,1)+1)
--select @a,@b
if @a=@b
select @matches=1  
end
select @c=len(replace(@a,' ','_'))-len(replace(replace(@a,' ','_'),'%',''))      
while @c>0 --or @matches=@c      
begin      
select @aexp=substring(@a,@am+1,case when charindex('%',@a,@am+1)>0 then (charindex('%',@a,@am+1)-(@am+1)) else right(@a,len(@a)-@am) end)      
--select @aexp      
select @am=charindex('%',@a,@am+1)      
--select @am      
select @m=charindex(@aexp,@b,@m+1)-- from #a where position=@p      
select @m=case when @m>0 then @m+len(@aexp) else @m end      
--select @m      
select @matches= case when @m>0 then @matches+1 else 0 end      
--select @matches,@c      
if @matches=0 --or @matches=@c      
begin      
select @c=0    
end      
select @c=@c-1    
--select @p=@p+1      
end    
end    
return case when @matches>0 then 1 else 0 end      
--drop table #a      
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_contactexistsingroup]    Script Date: 06-06-26 10:45:05 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--sp_helptext fn_contactexistsingroup('enquiry',3857773,223033)    
--select  dbo.fn_contactexistsingroup        ('lead',1241626,211379)  
--select * from usersearchlist where id=223033    
CREATE   FUNCTION [dbo].[fn_contactexistsingroup]          
(@entity nvarchar(20),@entityid bigint,@searchid bigint)          
returns int          
as          
begin          
--declare @entity nvarchar(20)='lead',@entityid bigint=1385457,@searchid bigint=234715  
DECLARE @SearchType               nvarchar(100),                                    
         @Medium                   nvarchar(100),                                    
         @Source                   nvarchar(100),                                    
         @Campaign                 nvarchar(100),                                    
         @SpecificName             nvarchar(100),                                    
         @SpecificAddress          nvarchar(100),                                    
         @SpecificMobileNo         nvarchar(100),                                    
         @SpecificEmail            nvarchar(100),                                    
         @SpecificCity             nvarchar(100),                                    
         @SpecificState            nvarchar(100),                                    
         @SpecificCountry          nvarchar(100),                                    
         @CurrentlyAssignedTo      nvarchar(100),                                    
         @FollowUpStatus           nvarchar(100),                                    
         @CreatedBetweenFrom       nvarchar(100),                                    
         @CreatedBetweenTo         nvarchar(100),                                    
         @NextFollowUpDateFrom     nvarchar(100),                                    
         @NextFollowUpDateTo       nvarchar(100),                                    
         @ConvertedWithinFrom      nvarchar(100),                                    
         @ConvertedWithinTo        nvarchar(100)                                    
                                     
 SELECT @SearchType = usl.searchtype,                                    
        @Medium                   = usl.medium,                                    
        @Source                   = usl.source,                                    
        @Campaign                 = usl.campaign,                                    
        @SpecificName             = usl.specificname,                                    
        @SpecificAddress          = usl.specificaddress,                                    
        @SpecificMobileNo         = usl.specificmobileno,                                    
        @SpecificEmail            = usl.specificemail,                                    
        @SpecificCity             = usl.specificcity,                                    
        @SpecificState            = usl.specificstate,                                    
        @SpecificCountry          = usl.specificcountry,                                    
        @CurrentlyAssignedTo      = usl.currentlyassignedto,                                    
        @FollowUpStatus           = usl.followupstatus,                                    
        @CreatedBetweenFrom       = usl.createdbetweenfrom,                                    
        @CreatedBetweenTo         = usl.createdbetweento,                                    
        @NextFollowUpDateFrom     = usl.nextfollowupdatefrom,                                    
        @NextFollowUpDateTo       = usl.nextfollowupdateto,                                    
        @ConvertedWithinFrom      = usl.convertedwithinfrom,                                  
        @ConvertedWithinTo        = usl.convertedwithinto                                    
 FROM   usersearchlist AS usl                                    
 WHERE  usl.id = @SearchID             
 declare @status int=0          
 if (@entity='lead' and @searchtype in ('AL','LE','Co'))        
 begin          
 select  top 1 @status=1 from userleads usl(nolock) left join leadinteractionhistory(nolock) lih on usl.parentid=lih.parentid          
 and lih.leadno=usl.leadno          
 where 1=case when @Medium in ('0','') or usl.mediumname in (select value from dbo.fn_split(@medium,'#')) then 1 else 0 end                                    
 and 1=case when @Source in ('0','') or usl.sourcename  in (select value from dbo.fn_split(@source,'#')) then 1 else 0 end                                    
 and 1=case when @Campaign in ('0','') or usl.campaignname  in (select value from dbo.fn_split(@Campaign,'#')) then 1 else 0 end                                    
 and isnull(usl.personname,'') like '%'+isnull(@SpecificName,'') +'%'          
 and (isnull(usl.ResidentialAddress,'')like '%'+isnull(@specificaddress,'')+'%'              
 or isnull(usl.OfficeAddress,'')like '%'+isnull(@specificaddress,'')+'%' )                                 
 and (isnull(mobileno,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo,'')))          
 or isnull(MobileNo1,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo1,'')))          
 or isnull(mobileno2,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo2,''))) )            
 and (isnull(usl.EmailID,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID,'')))          
 or isnull(usl.EmailID1,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID1,'')))      
 or isnull(usl.EmailID2,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID2,''))))      
 and isnull(usl.City,'')=isnull(nullif(@SpecificCity,''),isnull(usl.City,''))          
 and isnull(usl.State,'')=isnull(nullif( @SpecificState,''),isnull(usl.state,''))          
 and isnull(usl.Country,'') = isnull(nullif(@SpecificCountry,''),isnull(usl.Country,''))          
 and usl.assignedto=isnull(nullif(@CurrentlyAssignedTo,0),usl.assignedto)          
 and usl.FollowUpStatus in (select value from dbo.fn_split(isnull(nullif(nullif(@followupstatus,'0'),''),usl.FollowUpStatus),'#'))          
 and datediff(dd,cast(usl.CreatedOn as date),cast(getdate() as date))           
 between case when nullif(@CreatedBetweenFrom,'') is null then datediff(dd,cast(usl.CreatedOn as date),cast(getdate() as date))            
 else nullif(@CreatedBetweenFrom,'') end          
 and case when  nullif(@CreatedBetweenTo,'') is null then datediff(dd,cast(usl.CreatedOn as date),cast(getdate() as date))            
 else nullif(@CreatedBetweenTo,'') end   
 and           
 1= case when nullif(@NextFollowUpDateto,'') is null and nullif(@NextFollowUpDateFrom,'') is null   
 and nullif(usl.FollowupDate,'') is null then 1 when nullif(@NextFollowUpDateto,'') is null and nullif(@NextFollowUpDateFrom,'') is null   
 and nullif(usl.FollowupDate,'') is not null then 1 when nullif(@NextFollowUpDateto,'') is not null and nullif(@NextFollowUpDateFrom,'') is not null   
 and nullif(usl.FollowupDate,'') is null then 0 when  
 datediff(dd,cast(usl.FollowupDate as date),cast(getdate() as date))          
 between case when nullif(@NextFollowUpDateFrom,'') is null then datediff(dd,cast(usl.FollowupDate as date),cast(getdate() as date))            
 else nullif(@NextFollowUpDateFrom,'') end          
 and case when  nullif(@NextFollowUpDateto,'') is null then datediff(dd,cast(usl.FollowupDate as date),cast(getdate() as date))            
 else nullif(@NextFollowUpDateto,'') end then 1 else 0 end            
 and          
 (lih.id is null or (lih.FollowUpStatus= case when nullif(@ConvertedWithinFrom,'') is null then lih.FollowUpStatus else  6 end          
  and datediff(dd,cast(lih.CreatedOn as date),cast(getdate() as date))           
 between case when nullif(@ConvertedWithinFrom,'') is null then datediff(dd,cast(lih.CreatedOn as date),cast(getdate() as date))            
 else nullif(@ConvertedWithinFrom,'') end          
 and case when  nullif(@ConvertedWithinto,'') is null then datediff(dd,cast(lih.CreatedOn as date),cast(getdate() as date))            
 else nullif(@ConvertedWithinto,'') end)        )  
 and usl.id=@entityid          
 end          
 if (@entity='enquiry' and @searchtype in ('AL','EN'))          
 begin          
 select  top 1 @status=1 from userenquiry usl(nolock)          
 where      
 --usl.mediumname= case when @Medium in ('0','') then usl.mediumname else @medium end                                    
 --and usl.sourcename=case when @Source in ('0','') then  usl.sourcename else @source end                                    
 --and usl.campaignname=case when @Campaign in ('0','') then  usl.campaignname else @campaign end      
 1=case when @Medium in ('0','') or usl.mediumname in (select value from dbo.fn_split(@medium,'#')) then 1 else 0 end                                    
 and 1=case when @Source in ('0','') or usl.sourcename  in (select value from dbo.fn_split(@source,'#')) then 1 else 0 end                                    
 and 1=case when @Campaign in ('0','') or usl.campaignname  in (select value from dbo.fn_split(@Campaign,'#')) then 1 else 0 end                                          
 and isnull(usl.personname,'') like '%'+isnull(@SpecificName,'') +'%'          
 and (isnull(usl.ResidentialAddress,'')like '%'+isnull(@specificaddress,'')+'%'              
 or isnull(usl.OfficeAddress,'')like '%'+isnull(@specificaddress,'')+'%' )         
  and (isnull(mobileno,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo,'')))          
 or isnull(MobileNo1,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo1,'')))          
 or isnull(mobileno2,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),',')),isnull(MobileNo2,''))))             
 and (isnull(usl.EmailID,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID,'')))          
 or isnull(usl.EmailID1,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID1,'')))      
 or isnull(usl.EmailID2,'') in (isnull((select value from dbo.fn_split(cast(nullif(@SpecificEmail,'') as nvarchar(100)),',')) ,isnull(EmailID2,''))) )                             
 --and (isnull(mobileno,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),isnull(mobileno,'')),','))          
 --or isnull(MobileNo1,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),isnull(MobileNo1,'')),','))          
 --or isnull(mobileno2,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificMobileNo,'') as nvarchar(100)),isnull(MobileNo2,'')),',')))          
 --and (isnull(usl.EmailID,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificEmail,'') as nvarchar(100)),isnull(EmailID,'')),','))           
 --or isnull(usl.EmailID1,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificEmail,'') as nvarchar(100)),isnull(EmailID1,'')),','))           
 --or isnull(usl.EmailID2,'') in (select value from dbo.fn_split(isnull(cast(nullif(@SpecificEmail,'') as nvarchar(100)),isnull(EmailID2,'')),',') ))          
 and isnull(usl.City,'')=isnull(nullif(@SpecificCity,''),isnull(usl.City,''))          
 and isnull(usl.State,'')=isnull(nullif( @SpecificState,''),isnull(usl.state,''))          
