/****** Object:  UserDefinedFunction [dbo].[fn_ConvertDateTime]    Script Date: 06-06-26 10:45:05 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_ConvertDateTime](    
 @DateTimeToConvert datetime,    
 @TimeZone nvarchar(255),    
 @IsMiliSecond bit = 0    
)    
returns nvarchar(50)    
as    
begin    
 declare @offsetminute int, @setDateTime datetime = @DateTimeToConvert    
 select @offsetminute = DATEPART(tz, (CAST('2021-01-01' AS DATETIMEOFFSET)    
  AT TIME ZONE cast(@TimeZone as nvarchar(255)))) -330     
 set @setDateTime = dateadd(minute, cast(@offsetminute as int), cast(@DateTimeToConvert as datetime))    
 return iif(@IsMiliSecond = 1, format(@setDateTime, 'dd-MMM-yyyy HH:mm:ss.ffffff'), format(@setDateTime, 'dd-MMM-yyyy HH:mm:ss'))    
 return cast(@DateTimeToConvert as nvarchar(50) )  
end 

GO

/****** Object:  UserDefinedFunction [dbo].[fn_CreateBatchID]    Script Date: 06-06-26 10:45:06 ******/
