CREATE   FUNCTION [dbo].[fn_CreateBatchID]    
(    
 @CampaignId     BIGINT,    
 @userID         BIGINT    
)    
RETURNS BIGINT    
AS    
BEGIN    
 DECLARE @BatchID BIGINT    
     
     
 SELECT @BatchID = isnull((select MAX(BatchID)    
 FROM   GetBatchRecord gbr    
 WHERE  gbr.[User_id] = @userID    
        AND gbr.RandNum = @CampaignId),(select MAX(ISNULL(BatchID,0))+1    
 FROM   GetBatchRecord gbr) )  
                
            RETURN @BatchID    
END 
GO

/****** Object:  UserDefinedFunction [dbo].[fn_ExtractDomainWithWWW]    Script Date: 06-06-26 10:45:06 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_ExtractDomainWithWWW] (@url NVARCHAR(500))
RETURNS NVARCHAR(500)
AS
BEGIN
    DECLARE @domain NVARCHAR(500);

    -- Step 1: Remove scheme (http://, https://, ftp:// etc.)
    IF CHARINDEX('://', @url) > 0
        SET @domain = SUBSTRING(@url, CHARINDEX('://', @url) + 3, LEN(@url));
    ELSE
        SET @domain = @url;

    -- Step 2: Cut off path/query after domain
    IF CHARINDEX('/', @domain) > 0
        SET @domain = LEFT(@domain, CHARINDEX('/', @domain) - 1);

    -- Step 3: Ensure domain starts with www.
    IF @domain NOT LIKE 'www.%'
        SET @domain = 'www.' + @domain;

    RETURN @domain;
END;

GO

/****** Object:  UserDefinedFunction [dbo].[fn_extractNumberFromString]    Script Date: 06-06-26 10:45:06 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_extractNumberFromString]
(
  @strAlphaNumeric nVARCHAR(max)
)
RETURNS VARCHAR(256)
AS
BEGIN
  DECLARE @intAlpha INT
  SET @intAlpha = PATINDEX('%[^0-9]%', @strAlphaNumeric)
  BEGIN
    WHILE @intAlpha > 0
    BEGIN
      SET @strAlphaNumeric = STUFF(@strAlphaNumeric, @intAlpha, 1, '' )
      SET @intAlpha = PATINDEX('%[^0-9]%', @strAlphaNumeric )
    END
  END
  RETURN ISNULL(@strAlphaNumeric,0)
END

GO

