/****** Object:  UserDefinedFunction [dbo].[fn_FormatToInternational]    Script Date: 06-06-26 10:45:07 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_FormatToInternational] (@input NVARCHAR(100))
RETURNS NVARCHAR(100)
AS
BEGIN
    DECLARE @digits NVARCHAR(100);

    -- Remove non-digits
    SET @digits = dbo.fn_OnlyDigits(@input);

    -- If null or empty after cleaning → return empty
    IF @digits IS NULL OR LTRIM(RTRIM(@digits)) = ''
        RETURN '';

    -- If already starts with 00 → keep as-is
    IF LEFT(@digits, 2) = '00'
        RETURN @digits;

    -- If starts with 91 (India code without 00) → prepend 00
    IF LEFT(@digits, 2) = '91'
        RETURN '00' + @digits;

    -- Otherwise just prepend 00
    RETURN '00' + @digits;
END

GO

