CREATE   FUNCTION [dbo].[fn_getallowedstorage](@userid bigint)

returns numeric(9,2)

as

begin

declare @parentid bigint=dbo.ufn_getuserparentid(@userid),@storage numeric(18,2),@default numeric(18,2)

select top 1 @default=AllocatedSpace from  tbl_ML_UserStorageQuota(nolock) where AllocationType='default' and parentid in (0,@parentid) and isactive=1 order by parentid desc

select @storage=sum(allocatedspace) from  tbl_ML_UserStorageQuota(nolock) where AllocationType<>'default' and parentid=@parentid and isactive=1 and getdate() between StartDate and ExpiryDate

select @storage=isnull(@storage,0)+isnull(@default,0)
 
return @storage

end
GO

