 papt.StartDate, papt.EndDate, gecu.CheckIn, gecu.CheckOut, convert(time,gecu.CheckIn, 0) CheckInTime, convert(time,gecu.CheckOut, 0) CheckOutTime, gecu.LatitudeIn, gecu.LongitudeIn,  gecu.LatitudeOut, gecu.LongitudeOut, 
 @Parentid2 ParentId, isnull(bt.BreakTransactionId, 0) BreakTransactionId, isnull(bt.StartDate, null) BreakStartDate, isnull(bt.EndDate, null) BreakEndDate, (case when ((isnull(gecu.CheckIn, '') = '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckInNormal'  
 when ((gecrIn.ActionDateTime != '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckInRejected'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckInApproved'  
 else '' end) CheckInStatus, 
 (case when ((isnull(gecu.CheckOut, '') = '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckOutNormal'  
 when ((gecrOut.ActionDateTime != '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckOutRejected'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckOutApproved'  
 else '' end) CheckOutStatus 
 from TBL_ET_PhysicalAppointment(nolock) papt  
 inner join TBL_ET_PhyAppointUserMapping(nolock) paum on papt.PhysicalAppointmentId = paum.PhysicalAppointmentId  
 left join User_Detail(nolock) ud on papt.AssignedTo = ud.User_ID  
 left join TBL_ET_GeoEntityCheckInOut (nolock) gecu on papt.PhysicalAppointmentId = gecu.PhysicalAppointmentId  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrIn on papt.PhysicalAppointmentId = gecrIn.PhysicalAppointmentId and gecrIn.ActionType = 'CheckIn'  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrOut on papt.PhysicalAppointmentId = gecrOut.PhysicalAppointmentId and gecrOut.ActionType = 'CheckOut'  
 left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca on gecrIn.GeoEntityChkInOutRequestId = gecrIn.GeoEntityChkInOutRequestId  
 left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca2 on gecrOut.GeoEntityChkInOutRequestId = geca2.GeoEntityChkInOutRequestId  
 left join tbl_tsk_UserOutcomeMaster (nolock) oc on papt.OutcomesId = oc.Id  
 left join TBL_ET_BreakTransaction (nolock) bt on paum.UserId = bt.CreatedBy and bt.StartDate between papt.StartDate and papt.EndDate  
 where papt.CreatedBy = @UserId   
 and ((cast(papt.StartDate as Date) between cast(@FromDate as Date) and cast(@ToDate as Date))  
 or (cast(papt.EndDate as Date) between cast(@FromDate as Date) and cast(@ToDate as Date)))  
 )tt  
where (tt.CheckInStatus like '%'+ @IsStatus + '%') or (tt.CheckOutStatus like '%'+ @IsStatus + '%')  
)ttt 
return @return

End

GO

/****** Object:  UserDefinedFunction [dbo].[fn_getaverageengagement]    Script Date: 06-06-26 10:45:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getaverageengagement](@user_id bigint,@type varchar(1),@fromdate date,@todate date,@mode varchar(20))
returns bigint
as
begin
declare @avgtimespent bigint--,@diff int=datediff(d,@fromdate,@todate)
if exists(select 1 from tbl_user_engagement_track_details (nolock) t where cast(t.createddate as date) between @fromdate and @todate and UserEngMasterId in (select EngagementID from tbl_user_engagement_track_master(nolock) where userid=@user_id ))
begin

select @avgtimespent=
cast(sum(SpendTime)/cast(count(distinct s.userid) as float) as int) 
from tbl_user_engagement_track_details (nolock) t join tbl_user_engagement_track_master (nolock) s on t.UserEngMasterId=s.EngagementID
 WHERE cast(t.createddate as date) between @fromdate and @todate and 
isnull(ImpersonatorID,0)=0 and mode=case when @mode='both' then mode else @mode end
and 1=case when @type='I' and s.userid=@user_id then 1 when @type='P' and dbo.ufn_getuserparentid(s.userid)=dbo.ufn_getuserparentid(@user_id) then 1 else 0 end
end
return isnull(@avgtimespent,0)
end

GO

