/****** Object:  UserDefinedFunction [dbo].[fn_GetBreakStatus]    Script Date: 06-06-26 10:45:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--select dbo.fn_GetBreakStatus(32222)
CREATE   FUNCTION [dbo].[fn_GetBreakStatus]
(
	@UserId bigint
)
RETURNS bigint
AS
BEGIN
	DECLARE @IsBreakStatus bigint  
	if Exists(Select top 1 BreakTransactionId from TBL_ET_BreakTransaction (nolock) atdn where UserId = @UserId and Cast(StartDate as Date) = Cast(GetDate() as Date) and IsActive = 1 order by BreakTransactionId desc)
	Begin
		Select top 1 @IsBreakStatus = (case when isnull(EndDate, '') = '' then BreakTransactionId else 0 end)
		from TBL_ET_BreakTransaction (nolock) atdn where UserId = @UserId and Cast(StartDate as Date) = Cast(GetDate() as Date) and IsActive = 1
		order by BreakTransactionId desc
	End
	else
	Begin
		set @IsBreakStatus = 0
	End
	RETURN @IsBreakStatus
END

