CREATE   FUNCTION [dbo].[fn_getcallstatus] (@uniqueid varchar(50))  
returns nvarchar(20)  
as  
begin  
declare @status nvarchar(20)=  
(Select case when exists (select 1 from kit19callsdialled(nolock) where puniqueid=@uniqueid and dialstatus='ANSWER') then 'Answered' 
when not exists(select 1 from Kit19CallsDialled(nolock)  where puniqueid=@uniqueid) then 'Disconnected'
else 'Missed' end as CallStatus)  
return @status  
end
