CREATE   FUNCTION [dbo].[fn_getchecktimeflow](@f nvarchar(max),@clientid bigint)    
returns nvarchar(max)    
as    
begin    
/*declare @f nvarchar(max)=    
'[{"Step":"start","Name":"start","next":"ab007c7","Client":"27741","appid":"1263","previous":""},{"Step":"end002","Name":"passthrough","next":"end001","passthroughurl":"http://10.1.1.5:8666/endcall_request.aspx?whtype=end&didno=#DNID#&callid=#CALLSID#&dur
  
ation=#DURATION#","Client":"27741","appid":"1263","previous":""},{"Step":"end001","Name":"end","next":"","Client":"27741","appid":"1263","previous":""},{"Step":"ab007c7","Name":"playfile","Client":"27741","appid":"1263","filename":"welcomealfafinal_220820
  
19","next":"a9a9c3d","previous":"start"},{"Step":"a9a9c3d","Name":"timing","Client":"27741","appid":"1263","mon":"11:00-19:00","tue":"10:00-19:00","wed":"11:00-19:00","thu":"11:00-19:00","fri":"11:00-19:00","sat":"11:00-19:00","sun":"00:00-00:00","days":"
  
|mon|tue|wed|thu|fri|sat","open":"a9cf3e7","close":"abc4c94","previous":"ab007c7"},{"Step":"a9cf3e7","Name":"call","Client":"27741","appid":"1263","number":"#Group:773#","Sticky":"off","group-dial":"off","Record":"on","ringingduration":"45","conversationd
  
uration":"14400","DefaultPlay":"default_moh","moh_tag":"global","queue":"on","playfile":"callwaiting_2208201","next":"[","previous":"a9cf3e7"},{"Step":"abc4c94","Name":"sms","Client":"27741","appid":"1263","smsurl":"http://kit19.com/ComposeSMS.aspx?userna
  
me=alfa131346&password=11804&sender=TXTSMS&to=#caller#&message=Thank you for Inquiry. Rest assured as our team connect with you soon.&priority=1&dnd=1&unicode=0","next":"aa8a1c3","previous":"abc4c94"},{"Step":"aa8a1c3","Name":"Hangup","Client":"27741","ap
  
pid":"1263","Hangup":"Hangup","next":"end002","previous":"abc4c94"}]'*/    
declare @c int=len(@f)-len(replace(@f,'timing','timin')),    
--@clientid bigint=27741,--cast((select SUBSTRING(@f,charindex('"Client":"',@f,1)+10,CHARINDEX(',',@f,charindex('"Client":"',@f,1))-(charindex('"Client":"',@f,1)+10))) as bigint),    
@n nvarchar(10),@next nvarchar(5),@i nvarchar(20) ,@st nvarchar(5),@en nvarchar(5),@nextstep nvarchar(50),@nextstepe nvarchar(50)     
,@char int,@p int=1,@chard int    
while @c>0    
begin    
declare @s nvarchar(1000),@d nvarchar(1000),@t int,@m int,@dayspipe nvarchar(30)     
select @char=charindex('timing',@f,@p)    
select @t=datepart(hour,dbo.fn_getusertimefromindiantime(@clientid,getdate())),@m=datepart(minute,dbo.fn_getusertimefromindiantime(@clientid,getdate())),@n='"'+left(datename(weekday,dbo.fn_getusertimefromindiantime(@clientid,getdate())),3)+'"'    
select @d=substring(@f,charindex('"mon',@f,@p),charindex('"days',@f,charindex('"mon',@f,@p))-charindex('"mon',@f,@p))    
select @dayspipe=SUBSTRING(@f,CHARINDEX('"days',@F,@p)+8,charindex(',',@f,CHARINDEX('"days',@F,@p))-(CHARINDEX('"days',@F,@p)+8))    
select @i=replace(replace(substring(@d,charindex(@n,@d,1),19),@n+':',''),'"','')    
select @st= left(@i,5),@EN=right(@i,5)    
select @next=case when cast(@t as nvarchar)+':'+cast(@m as nvarchar) between @st and @en then 'Open' else 'Close' end    
select @s=substring(@f,charindex('"open',@f,@p),charindex('}',@f,charindex('"open',@f,@p))-charindex('"open',@f,@p))    
select @nextstep= case when @next='Open' then replace(substring(@s,1,charindex(',',@s,1)-1),'"open"','"next"')    
else replace(substring(@s,charindex(',',@s,1)+1,charindex(',',@s,charindex(',',@s,1))),'"close"','"next"') end    
select @nextstepe=replace(substring(@s,charindex(',',@s,1)+1,charindex(',',@s,charindex(',',@s,1))),'"close"','"next"')    
set @f=replace(@f,substring(@s,charindex(',',@s,1)+1,charindex(',',@s,charindex(',',@s,1)))+',"previous"',    
substring(@s,charindex(',',@s,1)+1,charindex(',',@s,charindex(',',@s,1)))+','+@nextstep+',"previous"')    
set @f=case when @dayspipe not like '%|"' then replace(@f,@dayspipe,REPLACE(@dayspipe,'"','|"')) else @f end   
set @c=@c-1    
set @p=@p+@char    
set @f=case when @f like '%"days": |%' or  @f like '%"days":|%' then replace(replace(@f,'"days": |','"days": '),'"days":|','"days": ') else @f end
--select @clientid,@dayspipe,@next,@i,@t,@m,@n,@d,@s,@nextstep,@nextstepe,@f    
end    
return @f    
end
