/****** Object:  UserDefinedFunction [dbo].[fn_getdlttemplateid]    Script Date: 06-06-26 10:45:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getdlttemplateid]    
(@parentid bigint,@message nvarchar(2000))    
returns nvarchar(50)    
as    
begin    
declare @len int,@tid nvarchar(50)    
select @len=len(@message)    
if @len=0  
begin  
set @tid='0'  
end  
else   
begin  
select @tid=    
(select top 1 DLT_TemplateID from UserMailTemplate(nolock) where parentid=@parentid and DLT_TemplateID is not null    
and dbo.edit_distance_within(replace(MailContent,'{#var#}',''),@message,@len)<cast((@len*.4) as int)  --and ActiveStatus = 1
--and dbo.edit_distance_within(MailContent,@message,@len)<(len(mailcontent)-len(replace(mailcontent,'%','')))*30  
order by dbo.edit_distance_within(MailContent,@message,@len))    
end  
return isnull(@tid,'0')    
end
GO

