	@email1 nvarchar(200),
	@email2 nvarchar(200)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
DECLARE @String VARCHAR(MAX)

if ISNULL(@email,'')<>''
begin
set @String=@email
end
if ISNULL(@email1,'')<>''
begin
if @String  is not null
begin
set @String = @string + ' , ' + @email1
end
else
begin
set @String=@email1
end
end
if ISNULL(@email2,'')<>''
begin
if @String  is not null
begin
set @String = @string + ' , ' + @email2
end
else
begin
set @String=@email2
end
end
if @String is null
begin
set @String=''
end
RETURN @String
END 

