        --    )    
     
     
     
     
     
     
     
 IF ISNULL(@String, '') = ''    
 BEGIN    
     SET @String = REPLACE(    
             REPLACE(    
                 REPLACE(    
                     REPLACE(    
                         REPLACE(    
                             REPLACE(    
                                 REPLACE(    
                                     REPLACE(    
                                         REPLACE(    
