/****** Object:  UserDefinedFunction [dbo].[fn_getEnquiryMessage]    Script Date: 06-06-26 10:45:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION  [dbo].[fn_getEnquiryMessage] -- 335,'#personname#'  
(  
 @ParentID     BIGINT,  
 @Message      VARCHAR(2000),  
 @Mobile       VARCHAR(50)  
)  
RETURNS NVARCHAR(MAX)  
AS  
BEGIN  
 DECLARE @String VARCHAR(MAX)    
   
   
   
 SELECT TOP 1 @String = REPLACE(  
            REPLACE(  
                REPLACE(  
                    REPLACE(  
                        REPLACE(  
                            REPLACE(  
                                REPLACE(  
                                    REPLACE(  
                                        REPLACE(  
                                            REPLACE(  
                                                REPLACE(  
                                                    REPLACE(  
                                                        REPLACE(  
                                                            REPLACE(@Message, '#PersonName#', ISNULL(ue.PersonName, '')),  
                                                            '#CompanyName#',  
                                                            ISNULL(ue.CompanyName, '')  
                                                        ),  
                                                        '#MobileNo#',  
                                                        ISNULL(ue.MobileNo, '')  
                                                    ),  
                                                    '#MobileNo1#',  
                                                    ISNULL(ue.MobileNo1, '')  
                                                ),  
                                                '#MobileNo2#',  
                                                ISNULL(ue.MobileNo2, '')  
                                            ),  
                                            '#EmailID#',  
                                            ISNULL(ue.EmailID, '')  
                                        ),  
                                        '#EmailID1#',  
                                        ISNULL(ue.EmailID1, '')  
                                    ),  
                                    '#EmailID2#',  
                                    ISNULL(ue.EmailID2, '')  
                                ),  
                                '#Source#',  
                                ISNULL(uss.Name, '')  
                            ),  
                            '#Medium#',  
                            ISNULL(ums.Name, '')  
                        ),  
                        '#Campaign#',  
                        ISNULL(ucs.Name, '')  
                    ),  
                    '#InitialRemarks#',  
                    ISNULL(ue.InitialRemarks, '')  
                ),  
                '#CreateDate#',  
               
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.CreatedDate ) 
            ),  
            '#CreatedBy#',  
            ISNULL(ud.FName, '') + ' ' + ISNULL(ud.LName, '')  
        )  
 FROM   UserEnquiry ue  
        LEFT JOIN UserMediumSettings ums  
             ON  ums.MediumID = ue.MediumName  
        LEFT JOIN UserCampaignSettings ucs  
             ON  ue.CampaignName = ucs.CampaignID  
        LEFT JOIN UserSourceSettings uss  
             ON  ue.SourceName = uss.SourceID  
        LEFT JOIN User_Detail ud  
             ON  ud.[User_ID] = ue.CreatedBy  
 WHERE  ue.ParentID = @ParentID  
        AND (  
