                                            ),  
                                            '#EmailID#',  
                                            ISNULL(ue.emailid, '')  
                                        ),  
                                        '#EmailID1#',  
                                        ISNULL(ue.emailid1, '')  
                                    ),  
                                    '#EmailID2#',  
                                    ISNULL(ue.emailid2, '')  
                                ),  
                                '#Source#',  
                                ISNULL(uss.NAME, '')  
                            ),  
                            '#Medium#',  
                            ISNULL(ums.NAME, '')  
                        ),  
                   '#Campaign#',  
                        ISNULL(ucs.NAME, '')  
                    ),  
                    '#InitialRemarks#',  
                    ISNULL(ue.initialremarks, '')  
                ),  
                '#CreateDate#',
                
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.createddate)
            ),  
            '#CreatedBy#',  
            ISNULL(ud.fname, '') + ' '  
              
              
              
            + ISNULL(ud.lname, '')  
        )  
 FROM   userenquiry ue  
        LEFT JOIN usermediumsettings ums  
             ON  ums.mediumid = ue.mediumname  
        LEFT JOIN usercampaignsettings ucs  
             ON  ue.campaignname = ucs.campaignid  
        LEFT JOIN usersourcesettings uss  
             ON  ue.sourcename = uss.sourceid  
        LEFT JOIN user_detail ud  
             ON  ud.[user_id] = ue.createdby  
 WHERE  ue.parentid = @ParentID  
        AND (  
                ue.emailid = @EmailID  
                OR ue.emailid1 = @EmailID  
                OR ue.emailid2 = @EmailID  
            )  
   
   
   
   
   
   
   
 IF ISNULL(@String, '') = ''  
 BEGIN  
     SET @String = REPLACE(  
             REPLACE(  
                 REPLACE(  
                     REPLACE(  
                         REPLACE(  
                             REPLACE(  
                                 REPLACE(  
                                     REPLACE(  
                                         REPLACE(  
                                             REPLACE(  
                                                 REPLACE(  
