                             ''  
                         ),  
                         '#Campaign#',  
                         ''  
                     ),  
                     '#InitialRemarks#',  
                     ''  
                 ),  
                 '#CreateDate#',  
                 ''  
             ),  
             '#CreatedBy#',  
             ''  
         )  
 END  
   
   
   
    
   
   
   
   
 RETURN @String  
END  
