CREATE   FUNCTION  [dbo].[fn_getEnquiryMessageMail_withid]                
(                
 @ParentID        BIGINT,                
 @MailContent     NVARCHAR(MAX),                
 @EnquiryID         VARCHAR(50)                 
)                
RETURNS NVARCHAR(MAX)                
AS                
BEGIN                
DECLARE @String NVARCHAR(MAX)                
                  
                 
 SELECT TOP 1 @String =           
   REPLACE(REPLACE( REPLACE(REPLACE(REPLACE( replace(REPLACE(                
            REPLACE(                
                REPLACE(                
                    REPLACE(                
                        REPLACE(                
                            REPLACE(                
                                REPLACE                
                                                
                                                
                                                
                                (                
                                    REPLACE                
                                                    
                                                    
                                                    
                                    (                
                                        REPLACE                
                                                        
                                                        
                                                        
                                        (                
                                            REPLACE                
                                                            
                                                            
                                                            
                                            (                
                                                REPLACE                
                                                                
                                                                
                                                                
                                                (                
                                                    REPLACE                
                                                                    
                                                                    
                                                                    
                                                    (                
                                                        REPLACE                
                                                                        
                                                                        
                                                                        
                                                        (                
                                                            REPLACE                
                                                                            
                                                                            
                                                                            
                                                            (@MailContent, '#Name#', ISNULL(ue.personname, '')),                
                                                            '#Company Name#',                
                                                            ISNULL(ue.companyname, '')                
                                                        ),                
                                                        '#Mobile1#',                
                                                        ISNULL(ue.mobileno, '')                
                                                    ),                
                                                    '#Mobile2#',                
                                                    ISNULL(ue.mobileno1, '')                
                                                ),                
                                                '#Mobile3#',                
                                                ISNULL(ue.mobileno2, '')                
        ),                
                                            '#EmailID1#',                
                                            ISNULL(ue.emailid, '')                
                        ),                
                                        '#EmailID2#',                
                                        ISNULL(ue.emailid1, '')                
                                    ),                
                                    '#EmailID3#',                
      ISNULL(ue.emailid2, '')                
                                ),                
                                '#Source Name#',                
                                ISNULL(uss.NAME, '')                
                            ),                
                            '#Medium Name#',                
                            ISNULL(ums.NAME, '')                
                        ),                
                   '#Campaign Name#',                
                        ISNULL(ucs.NAME, '')                
                    ),                
                    '#InitialRemarks#',                
                    ISNULL(ue.initialremarks, '')                
                ),                
                '#Created Date#',              
                              
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.createddate)              
            ),                
            '#Created By#',                
            ISNULL(ud.fname, '') + ' '                
                            
                            
            + ISNULL(ud.lname, '')                
        )  ,'#Name#',ue.PersonName)      
      
  ,'#City#',ISNULL(ue.City,'')      
         
    ),'#State#',ISNULL(ue.State,'')      
        
  ),'#Country#',ISNULL(ue.Country,'')      
  ),      
   '#Address#', case when ISNULL(ue.ResidentialAddress,'') <> '' then ISNULL(ue.ResidentialAddress,'')      
                     else ISNULL(ue.OfficeAddress,'')      
         end       
        
  ),'#Pin Code#', cast(ISNULL(ue.PinCode,'0') as nvarchar))      
        
                
 FROM   userenquiry ue (nolock)               
        LEFT JOIN usermediumsettings ums (nolock)                
             ON  ums.mediumid = ue.mediumname                
        LEFT JOIN usercampaignsettings ucs   (nolock)             
             ON  ue.campaignname = ucs.campaignid                
        LEFT JOIN usersourcesettings uss (nolock)               
             ON  ue.sourcename = uss.sourceid                
        LEFT JOIN user_detail ud  (nolock)              
             ON  ud.[user_id] = ue.createdby                
 WHERE  ue.parentid = @ParentID                
        AND     ue.EnquiryID = @EnquiryID                
                           
                 
                 
      SELECT TOP 1 @String =           
  REPLACE(REPLACE( REPLACE( REPLACE(REPLACE( REPLACE(REPLACE(REPLACE( replace(REPLACE(                
            REPLACE(                
                REPLACE(                
                    REPLACE(                
                        REPLACE(                
                            REPLACE(                
                                REPLACE                
                                                
                                                
                                                
                                (                
                                    REPLACE                
                                                    
                                                    
                                                    
                                    (                
                                        REPLACE                
                                    
                                                        
                                                        
                                        (                
                                            REPLACE                
                                                            
                                                            
                                                            
                                            (                
                                                REPLACE                
                                                                
                                                                
                                                                
                                                (                
                                                    REPLACE                
                                                                    
                                                                    
                                                                    
                                                    (                
                                                        REPLACE                
                                                                        
                                                                        
                                                                        
                                                        (                
                                                            REPLACE                
                                                                            
                                                                            
                                                                            
                                                            (@String, '#Enquiry.PersonName#', ISNULL(ue.personname, '')),                
                                                            '#Enquiry.CompanyName#',                
                                                            ISNULL(ue.companyname, '')                
                                                        ),                
                                                        '#Enquiry.MobileNo#',                
                                                        ISNULL(ue.mobileno, '')                
                                                    ),                
                                                    '#Enquiry.MobileNo1#',                
                                                    ISNULL(ue.mobileno1, '')                
                                                ),                
                                                '#Enquiry.MobileNo2#',                
                                                ISNULL(ue.mobileno2, '')                
                                            ),                
                                            '#Enquiry.EmailID#',                
                                            ISNULL(ue.emailid, '')                
                        ),                
                                        '#Enquiry.EmailID1#',                
                                        ISNULL(ue.emailid1, '')                
                                    ),                
                                    '#Enquiry.EmailID2#',                
      ISNULL(ue.emailid2, '')                
                                ),                
                                '#Enquiry.SourceName#',                
                                ISNULL(uss.NAME, '')                
                            ),                
                            '#Enquiry.MediumName#',                
                            ISNULL(ums.NAME, '')                
                        ),                
                   '#Enquiry.CampaignName#',                
                        ISNULL(ucs.NAME, '')                
                    ),                
                    '#Enquiry.InitialRemarks#',                
                    ISNULL(ue.initialremarks, '')                
                ),                
                '#Enquiry.CreatedDate#',              
                              
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.createddate)              
            ),                
            '#Enquiry.CreatedBy#',                
            ISNULL(ud.fname, '') + ' '                
                            
                            
            + ISNULL(ud.lname, '')                
        )  ,'#Name#',ue.PersonName)      
      
  ,'#Enquiry.City#',ISNULL(ue.City,'')      
         
    ),'#Enquiry.State#',ISNULL(ue.State,'')      
        
  ),'#Enquiry.Country#',ISNULL(ue.Country,'')      
  ),      
   '#Enquiry.Address#', case when ISNULL(ue.ResidentialAddress,'') <> '' then ISNULL(ue.ResidentialAddress,'')      
                     else ISNULL(ue.OfficeAddress,'')      
         end       
        
  ),'#Enquiry.PinCode#', cast(ISNULL(ue.PinCode,'0') as nvarchar)
  )	,  
     '#Enquiry.CreatedByName#', ISNULL(ud.fname, '') + ' '                    
                             +                    
                            ISNULL(ud.lname, '')           
    )  ,          
     '#Enquiry.CreatedByPhone#', ISNULL(str(ud.mobile), '')           
    )  ,          
     '#Enquiry.CreatedByEmail#', ISNULL(ud.email, '')
 )
                
 FROM  userenquiry ue (nolock)               
        LEFT JOIN usermediumsettings ums (nolock)                
             ON  ums.mediumid = ue.mediumname                
        LEFT JOIN usercampaignsettings ucs (nolock)               
             ON  ue.campaignname = ucs.campaignid                
        LEFT JOIN usersourcesettings uss  (nolock)              
             ON  ue.sourcename = uss.sourceid                
        LEFT JOIN user_detail ud (nolock)               
             ON  ud.[user_id] = ue.createdby                
 WHERE  ue.parentid = @ParentID                
        AND     ue.EnquiryID = @EnquiryID                 
                 
                 
                 
                 
 IF ISNULL(@String, '') = ''                
 BEGIN                
     SET @String = REPLACE(REPLACE(REPLACE( REPLACE(REPLACE(REPLACE(                
             REPLACE(                
                 REPLACE(                
                     REPLACE(                
                         REPLACE(                
                             REPLACE(                
                                 REPLACE(                
                                     REPLACE(                
                                         REPLACE(                
                                             REPLACE(                
                                                 REPLACE(                
                                                     REPLACE(                
                                                         REPLACE(                
                                                             REPLACE(@MailContent, '#Name#', ''),                
                                                             '#Company Name#',                
                                                             ''                
    ),                
                                                         '#Mobile1#',                
                                                         ''                
                                                     ),                
                   '#Mobile2#',                
                                                     ''                
                                                 ),                
                                                 '#Mobile3#',                
                                                 ''                
                                             ),                
                                             '#EmailID1#',                
                                             ''                
                                         ),                
                                         '#EmailID2#',                
                 ''                
                                     ),                
                                     '#EmailID3#',                
                                     ''                
                                 ),                
                                 '#Source Name#',                
                                 ''                
                             ),                
                             '#Medium Name#',                
                             ''                
                         ),                
                         '#Campaign Name#',                
                         ''                
                     ),                
                     '#InitialRemarks#',                
                     ''                
                 ),                
                 '#Created Date#',                
                 ''                
             ),                
             '#Created By#',                
             ''                
          ),      
   '#City#',''      
   ),      
    '#State#',''      
   ),      
      '#Country#',''       
  ),      
   '#Address# ',''      
   )      
   ,'#Pin Code#','0')      
              
 END                
                 
                 
 RETURN @String                
END 
GO

