        LEFT JOIN usersourcesettings uss    
             ON  ue.sourcename = uss.sourceid    
        LEFT JOIN user_detail ud    
             ON  ud.[user_id] = ue.createdby    
 WHERE  --ue.parentid = @ParentID    
        --AND (    
        --        ue.emailid = @EmailID    
        --        OR ue.emailid1 = @EmailID    
        --        OR ue.emailid2 = @EmailID    
        --    )
		ue.EnquiryID=@enquiryid

      select @String = replace(@String, '#enquiry.'+cast(fieldname as varchar)+'#', ISnull( cast (fieldvalue as varchar),'')) 
	  from customfields cf left join customfieldEnquiryvalue cfv 
	  on cf.field_id=cfv.fieldID and cfv.enquiryid=@enquiryid
	where parentid= @ParentID 

 IF ISNULL(@String, '') = ''    
 BEGIN    
     SET @String = REPLACE(    
             REPLACE(    
                 REPLACE(    
                     REPLACE(    
                         REPLACE(    
                             REPLACE(    
                                 REPLACE(    
                                     REPLACE(    
                                         REPLACE(    
                                             REPLACE(    
                                                 REPLACE(    
                                                     REPLACE(    
                                                         REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(
														 REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(  
                                                             REPLACE(@MailContent, '#enquiry.personname#', ''),    
                                                             '#enquiry.CompanyName#',    
                                                             ''    
                                                         ),    
                                                         '#enquiry.MobileNo#',    
                                                         ''    
                                                     ),    
                                                     '#enquiry.MobileNo1#',    
                                                     ''    
                                                 ),    
                                                 '#enquiry.MobileNo2#',    
                                                 ''    
                                             ),    
                                             '#enquiry.EmailID#',    
                                             ''    
                                         ),    
                                         '#enquiry.EmailID1#',    
                                         ''    
                                     ),    
                                     '#enquiry.EmailID2#',    
                                     ''    
                                 ),    
                                 '#enquiry.Source#',    
                                 ''    
                             ),    
                             '#enquiry.Medium#',    
                             ''    
                         ),    
                         '#enquiry.Campaign#',    
                         ''    
                     ),    
                     '#enquiry.InitialRemarks#',    
                     ''    
                 ),    
                 '#enquiry.CreateDate#',    
                 ''    
             ),    
             '#enquiry.CreatedBy#',    
             ''    
         ),
		 '#enquiry.City#',''),
			'#enquiry.Country#',''),
			'#enquiry.CountryCode#',''),
			'#enquiry.CountryCode1#',''),
			'#enquiry.CountryCode2#',''),
			'#enquiry.CreatedDate#',''),
			'#enquiry.latitude#',''),
			'#enquiry.LeadNo#',''),
			'#enquiry.longitude#',''),
			'#enquiry.OfficeAddress#',''),
			'#enquiry.PinCode#',''),
			'#enquiry.ResidentialAddress#',''),
			'#enquiry.State#',''),
			'#enquiry.whereAddress#','')

		 select @String = replace(@String, '#enquiry.'+cast(fieldname as varchar)+'#', '') from customfields cf
 join customfieldEnquiryvalue cfv on cf.field_id=cfv.fieldID and enquiryid=@enquiryid
 where parentid= @ParentID 
 END    
 
 RETURN @String            
END     
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getenquiryrelativescore]    Script Date: 06-06-26 10:45:22 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getenquiryrelativescore](@enquiryid bigint)          
returns int-- numeric(18,2)          
as          
begin          
declare @parentid bigint=(select parentid from userenquiry(nolock) where EnquiryID=@enquiryid)          
declare @max int=(select (max(currentscore)*100)/99 from enquiry_score_history(nolock) e where parentid=@parentid),@relativescore numeric(18,2)          
select top 1 @relativescore= round((currentscore/cast(@max as float)*99),2) from enquiry_score_history(nolock) e           
where enquiryid=@enquiryid and parentid=@parentid order by id desc          
return isnull(@relativescore,0)          
end     
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getenquirysourcecount]    Script Date: 06-06-26 10:45:23 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getenquirysourcecount]            
(@user_id bigint,@fromdate date,@todate date,@sourcename nvarchar(100),@fieldvalue sql_variant)            
returns int            
as            
begin            
declare @count int=            
(select count(1) from  UserEnquiry(nolock) u join usersourcesettings(nolock) s on s.SourceID=u.sourcename           
join customfields(nolock) a on a.ParentID=u.CreatedBy        
join customfieldEnquiryvalue(nolock) c on    c.fieldID=a.field_ID    and c.EnquiryID=u.EnquiryID    
where  s.name=@sourcename   and   a.fieldname like '%brand%' and   fieldvalue=@fieldvalue --and a.isActive=1        
and cast(u.CreatedDate as date) between @fromdate and @todate)          
        
return isnull(@count,0)            
end


GO

