CREATE   FUNCTION [dbo].[fn_getenquirysourceid](@entity varchar(20),@entityid bigint)
returns int
as
begin
declare @es_id int=0
if @entity='enquiry'
select @es_id=enquirysource from userenquiry(nolock) where enquiryid=@entityid
else if @entity='lead'
select @es_id=enquirysource from userleads(nolock) where id=@entityid
return isnull(@es_id,0)
end
