CREATE   FUNCTION [dbo].[fn_getenquiryUserwisesourcecount]            
(@user_id bigint,@fromdate date,@todate date,@sourcename nvarchar(100),@fieldvalue sql_variant)            
returns int            
as            
begin            
declare @count int=            
(select count(1) from  UserEnquiry(nolock) u join usersourcesettings(nolock) s on s.SourceID=u.sourcename           
join customfields a on a.ParentID=u.CreatedBy        
join customfieldEnquiryvalue c on    c.fieldID=a.field_ID    and c.EnquiryID=u.EnquiryID    
