/****** Object:  UserDefinedFunction [dbo].[fn_getentityfullname]    Script Date: 06-06-26 10:45:24 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getentityfullname]  
(@entity nvarchar(50),@entityid bigint)  
returns nvarchar(100)  
as  
begin  
declare @fullname nvarchar(100)  
select @fullname =   
coalesce(  
(select isnull(personname,'') from userleads(nolock) where id=@entityid and @entity='lead'),
(select isnull(personname,'') from userenquiry(nolock) where enquiryid=@entityid and @entity='enquiry'),
(select isnull(personname,'') from conversationcontacts(nolock) where id=@entityid and @entity='conversationcontact'),
(select isnull(fname,'')+' '+isnull(lname,'') from user_detail(nolock) where user_id=@entityid and @entity='user'),
(select isnull(agentname,'') from calling_agents(nolock) where id=@entityid and @entity='agent'),
'')  
return @fullname  
end
GO

