CREATE   FUNCTION [dbo].[fn_getentityprofileimage](
	@entity nvarchar(50),
	@entityid bigint
)
returns nvarchar(100)
as
begin
	declare @fullname nvarchar(100)
	
	select @fullname = 
	coalesce(
		(select isnull(ProfileImgFileName,'') from userleads(nolock) where id=@entityid 
	and @entity='lead'),(select isnull(ProfileImgFileName,'') from userenquiry(nolock) where enquiryid=@entityid 
	and @entity='enquiry'),(select '' from conversationcontacts(nolock) where id=@entityid 
	and @entity='conversationcontact'), (select '' from user_detail(nolock) where user_id=@entityid 
	and @entity='user'),'')
	return @fullname
end
