CREATE   FUNCTION [dbo].[fn_geteventid_fromactivityid]
(@entity nvarchar(20),@activityid bigint)
returns int
as
begin
declare @eventid bigint
if @entity='lead'
begin
select @eventid=eventid from tbl_LeadEventHistory(nolock) where historyid=@activityid
end
if @entity='enquiry'
begin
select @eventid=eventid from tbl_enquiryEventHistory(nolock) where historyid=@activityid
end
if @entity='user'
