CREATE   FUNCTION [dbo].[fn_GetFilterMailsIdwithName]--(0,28513,119901)
(@Filterid bigint,@userid bigint,@mailid bigint)  
returns nvarchar(max)  
as  
begin  
  
declare @Filternamewithid nvarchar(max),@frommail nvarchar(250),@toemail nvarchar(250),@subject nvarchar(500),@body nvarchar(max)  
select @frommail=fromemail,@toemail=toemail,@subject=SubjectContains,@body=MailContentContains from UserMailsFilters where ID=@Filterid and parentid=@userid  
SET @filternamewithid=( SELECT STUFF(      
                       (      
                           SELECT DISTINCT N', ' + umf.Name + '#'      
                                  + CAST(umf.ID AS VARCHAR(50)) + '#'      
                                  +      
                                  CASE       
                                       WHEN umf.IsMapped =      
                                            1 THEN 'Mapped'      
                                       ELSE 'Not Mapped'      
                                  END      
                           FROM   UserMailsFilters AS umf  
                           join  UserMails    AS um      
 on  um.UserID = @userid and um.id=@mailid    
                           WHERE  um.UserID IN (SELECT ud.[User_ID]      
                                                FROM   User_Detail AS ud      
                                                WHERE  ud.ParentID = umf.ParentID)      
                                  AND um.FromMail LIKE '%' + umf.FromEmail +       
                                      '%'      
                                  AND um.ToEmail LIKE '%' + umf.ToEmail + '%'      
                                  AND um.MailContent LIKE      
                                      '%' + umf.MailContentContains +      
                                      '%'      
                                  AND um.MailSubject LIKE      
                                      '%' + umf.SubjectContains +      
                                      '%'      
                                      FOR XML PATH(''), TYPE      
                       ) .value('text()[1]', 'nvarchar(max)'),      
                       1,      
                       2,      
                       N''      
                   )      
 --                   AS FilterName  
 --        FROM   UserMails    AS um      
 --WHERE  um.UserID = @userid     and id=@mailid 
 --       AND um.FromMail LIKE '%' + ISNULL(@FromMail, um.FromMail) + '%'      
 --       AND um.ToEmail LIKE '%' + ISNULL(@ToEmail, um.ToEmail) + '%'      
 --       AND um.MailSubject LIKE '%' + ISNULL(@Subject, um.MailSubject) +      
 --           '%'      
 --       AND um.MailContent LIKE '%' + ISNULL(@Body, um.MailContent) + '%' 
        ) 
        
          
return @filternamewithid  
  
end
GO

