CREATE   FUNCTION [dbo].[fn_getfirstenrollment]
(@leadid bigint)
returns date
as
begin
declare @fe date
select top 1 @fe=FollowupDate from LeadInteractionHistory l (nolock) join FollowUp_Status f (nolock) on l.followupstatus=f.id where id_lead=@leadid and f.IsConvert=1  order by l.id desc
return @fe

end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getgraceexpiry]    Script Date: 06-06-26 10:45:28 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getgraceexpiry]
(@userid bigint)
returns date
as
begin
declare @parentid bigint=dbo.ufn_getuserparentid(@userid),@gracedate date,@planenddate date
select top 1  @planenddate=planenddate from Price_UserSubscriptionDetails(nolock) where userid=@parentid and IsNewPlan=1 order by id desc
select top 1 @gracedate=dateadd(d,no_of_days,@planenddate) from [tbl_pt_GracePeriodDays](nolock) where isnull(parentid,0) in (0,@parentid) order by parentid desc
return @gracedate

end
GO

