CREATE   FUNCTION [dbo].[fn_GetIntSMSUnitPrice](@parentid bigint,@countrycode nvarchar(10))  
returns numeric(18,4)  
as  
begin  
declare @cost numeric(18,4)  
select @cost=isnull(  
(select top 1 cast(Ptrns as numeric(18,4)) from Price_Base_SMS_Rate_Exception(nolock) where ParentID=@parentid and replace(DestinationCountryCode,'+','')= replace(@countrycode,'+','')), (select top 1 cast(Ptrns as numeric(18,4)) from Price_Base_SMS_Rate(nolock) where replace(DestinationCountryCode,'+','')= replace(@countrycode,'+','')))  
return @cost  
end
GO

