CREATE   FUNCTION [dbo].[fn_getISTtimefromusertime](@user_id bigint,@dbdatetime datetime)      
 returns datetime       
 as      
 begin      
 declare @userlocaldatetime datetime      
 select @userlocaldatetime = cast(convert(datetime,@dbdatetime)       
    AT TIME ZONE cast(timezone as nvarchar(200))    
