/****** Object:  UserDefinedFunction [dbo].[fn_GetJobLastRuntime]    Script Date: 06-06-26 10:45:29 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_GetJobLastRuntime]
(
	@JobName VARCHAR(500)
)
RETURNS DATETIME
AS
BEGIN 
	DECLARE @JobTime DATETIME
	
	DECLARE @job_id BINARY(16)
	
	SELECT @job_id = job_id
	FROM   msdb.dbo.sysjobs
	WHERE  (NAME = @JobName)
	
	
	 
	        SELECT TOP 1 @JobTime=A.run_datetime
	        FROM   (
	                   SELECT CONVERT(DATETIME, RTRIM(run_date))
	                          
	                          + (
	                              (run_time / 10000 * 3600) 
	                              
	                              + ((run_time % 10000) / 100 * 60) 
	                              
	                              + (run_time % 10000) % 100
	                          ) / (86399.9964) AS run_datetime
	                   FROM   msdb..sysjobhistory sjh
	                   WHERE  sjh.step_id = 0
	                          AND sjh.run_status = 1
	                          AND sjh.job_id = @job_id
	               ) A
	        ORDER BY
	               A.run_datetime DESC
	      
	
	RETURN @JobTime
END
GO

