CREATE   FUNCTION [dbo].[fn_getkycstatus](@user_id bigint)  
	returns varchar(100)  
as  
begin  

	declare @status varchar(100)  	
	select top 1 @status =status from [tbl_KycMaster](nolock) where parentid=dbo.ufn_getuserparentid(@user_id) 
  
	and ModifiedOn > dateadd(m,-6,getdate())  

	return case when isnull(@status,'')<>'Approved' then 'Incomplete' else @status end  
  
	--select case when isnull(@status,'')<>'Approved' then 'Incomplete' else @status end  
end

GO

