/****** Object:  UserDefinedFunction [dbo].[fn_getleadexpiry]    Script Date: 06-06-26 10:45:30 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getleadexpiry]
(@leadid bigint,@pipelineid int)
returns datetime
as
begin
declare @expiry datetime
select @expiry=dateadd(d,m.DealExpiry,min(l.CreatedDate)) from LeadPipelineMapping(nolock) l join Pipeline_Master m (nolock)
on m.id=l.PipelineID left join PipelineStages s(nolock) on s.id=l.PipeLineStage
where l.leadid=@leadid and l.PipelineID=@pipelineid and l.IsDeleted=0
and s.Name not in ('Won','Lost')
group by l.PipelineID,leadid,m.DealExpiry

return @expiry
end




GO

