CREATE   FUNCTION [dbo].[fn_getleadpipelineexpirydate]
(@leadid bigint,@pipelineid bigint)
returns datetime
as
begin
declare @expiry datetime=(select dateadd(dd,dealexpiry,fcreated) from
Pipeline_Master(nolock) p 
join (select leadid,min(CreatedDate) fcreated,PipelineID from LeadPipelineMapping(nolock) where isdeleted=0 and leadid=@leadid
group by leadid,PipelineID
) m
on m.PipelineID=p.ID and p.isdeleted=0 and p.id=@pipelineid
where p.Name not in ('Won','Lost')
)
return @expiry
end
