/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsConversionDate]    Script Date: 06-06-26 10:45:31 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

  
      
  
CREATE   FUNCTION  [dbo].[fn_getLeadsConversionDate]  
(  
 @LeadNo       BIGINT,  
 @ParentID     BIGINT  
)  
RETURNS NVARCHAR(200)  
AS  
BEGIN  
 DECLARE @String VARCHAR(200)    
   
 SELECT TOP 1 @String = A.CreatedOn  
 FROM   (  
            SELECT TOP 1  dbo.[fn_getusertimefromindiantime](@ParentID,lih.CreatedOn) as CreatedOn
              
            FROM   UserLeads AS ul  
                   INNER JOIN LeadInteractionHistory AS lih  
                        ON  lih.LeadNo = ul.LeadNo  
                        AND lih.ParentID = @ParentID  
            WHERE  ul.LeadNo = @LeadNo  
                   AND ul.ParentID = @ParentID  
                   --AND lih.AmountPaid <> 0  
                   and lih.FollowUpStatus=5  
            ORDER BY  
                   lih.CreatedOn ASC  
        ) A  
 ORDER BY  
        A.CreatedOn   
   
 RETURN @String  
END  
  

GO

