/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsConvertedBy]    Script Date: 06-06-26 10:45:32 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


       



CREATE   FUNCTION [dbo].[fn_getLeadsConvertedBy]
(
	@LeadNo       BIGINT,
	@ParentID     BIGINT
)
RETURNS NVARCHAR(200)
AS
BEGIN
	DECLARE @String VARCHAR(200)  
	
	
	
	SELECT TOP 1 @String = A.AssignedTo
	FROM   (
	           SELECT TOP 1 lih.AssignedTo AS AssignedTo
	           FROM   UserLeads AS ul
	                  INNER JOIN LeadInteractionHistory AS lih
	                       ON  lih.LeadNo = ul.LeadNo
	                       AND lih.ParentID = @ParentID
	           WHERE  ul.LeadNo = @LeadNo
	                  AND ul.ParentID = @ParentID
	                  AND lih.AmountPaid <> 0
	           ORDER BY
	                  lih.CreatedOn DESC
	       ) A 
	
	
	
	RETURN @String
END

GO

