/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsLastProducts]    Script Date: 06-06-26 10:45:33 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


  
CREATE   FUNCTION [dbo].[fn_getLeadsLastProducts]
(
	@LeadNo       BIGINT,
	@ParentID     BIGINT
)
RETURNS NVARCHAR(200)
AS
BEGIN
	DECLARE @String VARCHAR(200)  
	SELECT TOP 1 @String = A.ProductName
	FROM   (
	           SELECT TOP 2(
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + pm.Name  
	                                     FROM   ProductMaster pm
	                                            INNER JOIN dbo.fn_Split(lih.Products, '#') AS 
	                                                 fs
	                                                 ON  pm.ProductID = fs.[value] 
	                                                     FOR XML 
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	           ) AS ProductName,
	                  lih.CreatedOn
	           FROM   LeadInteractionHistory lih
	           WHERE  lih.LeadNo = @LeadNo
	                  AND lih.ParentID = @ParentID
	           ORDER BY
	                  lih.CreatedOn DESC
	       ) A
	ORDER BY
	       A.CreatedOn 
	       RETURN @String
END 

GO

/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsLastProducts_Testing]    Script Date: 06-06-26 10:45:33 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

  
    
CREATE   FUNCTION [dbo].[fn_getLeadsLastProducts_Testing]  
(  
 @LeadNo       BIGINT,  
 @ParentID     BIGINT  
)  
RETURNS NVARCHAR(200)  
AS  
BEGIN  
            
    exec Usp_createProductMasterTable @ParentID 

 DECLARE @String NVARCHAR(200) = ''
 Declare @FinalString nvarchar(max) = ''    
 
 Declare @Query nvarchar(max) = N' 

 SELECT TOP 1 @String = A.ProductName  
 FROM   (  
            SELECT TOP 2(  
                       SELECT STUFF(  
                                  (  
                                      SELECT N'', '' + pm.Name    
                                      FROM   ProductMaster pm  
                                             INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS   
                                                  fs  
                                                  ON  pm.ProductID = fs.[value]   
                                                      FOR XML   
                                                      PATH(''''),  
                                             TYPE  
                                  )   
                                  .value(''text()[1]'', ''nvarchar(max)''),  
                                  1,  
                                  2,  
                                  N''''  
                              )  
            ) AS ProductName,  
                   lih.CreatedOn  
            FROM   LeadInteractionHistory lih  
            WHERE  lih.LeadNo = '+ cast(@LeadNo as nvarchar(max)) + '  
                   AND lih.ParentID = '+ Cast(@ParentID as nvarchar(max)) + '  
            ORDER BY  
                   lih.CreatedOn DESC  
        ) A  
 ORDER BY  
        A.CreatedOn  '
		
	exec sp_executesql @Query, N''
		 
        RETURN @String  
END   
GO

