CREATE   FUNCTION [dbo].[fn_getLeadsLastStatus]
(
	@LeadNo       BIGINT,
	@ParentID     BIGINT
)
RETURNS NVARCHAR(200)
AS
  
   
BEGIN
	DECLARE @String VARCHAR(200)  
	SELECT TOP 1 @String = A.FollowupStatus
	FROM   (
	           SELECT TOP 2 fus.FollowupStatus,
	                  lih.CreatedOn,
	                  lih.LeadNo
	           FROM   LeadInteractionHistory lih
	                  LEFT JOIN FollowUp_Status fus
	                       ON  fus.ID = lih.FollowUpStatus
	           WHERE  lih.LeadNo = @LeadNo
	                  AND lih.ParentID = @ParentID
	           ORDER BY
	                  lih.CreatedOn DESC
	       ) A
	ORDER BY
	       A.CreatedOn 
	       RETURN @String
END 

