/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsMailMessage]    Script Date: 06-06-26 10:45:34 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION  [dbo].[fn_getLeadsMailMessage] -- 335,'#personname#'      
(      
 @ParentID       BIGINT,      
 @Message        VARCHAR(MAX),      
 @EmailID        VARCHAR(100)       
)      
RETURNS NVARCHAR(MAX)      
AS      
BEGIN      
 DECLARE @String VARCHAR(MAX)      
       
       
       
       
       
       
       
 SELECT TOP 1 @String = 
          REPLACE(      
            REPLACE(      
                REPLACE( REPLACE(      
            REPLACE(      
                REPLACE(      
                    REPLACE(      
                        REPLACE(      
                            REPLACE(      
                                REPLACE(      
                                    REPLACE      
                                          
                                          
                                          
                                    (      
                                        REPLACE(      
                                            REPLACE(      
                                                REPLACE(      
                                                    REPLACE      
                                                          
                                                          
                                                          
                                                    (      
                                                        REPLACE      
                                                              
                                                              
                                                              
                                                        (      
                                                            REPLACE      
                                                                  
                                                                  
                                                                  
                                                            (      
                                                                REPLACE      
                                                                      
                                                                      
                                                                      
                                                                (      
                                                                    REPLACE      
                                                                          
                                                                          
                                                                          
                                                                    (@Message, '#personname#', ISNULL(ue.personname, '')),      
                                                                    '#CompanyName#',      
                                                                    ISNULL(ue.companyname, '')      
                                                                ),      
                                                                '#MobileNo#',      
                                                                ISNULL(ue.mobileno, '')      
                                                            ),      
                                                            '#MobileNo1#',      
                                                            ISNULL(ue.mobileno1, '')      
                                                        ),      
                                                        '#MobileNo2#',      
                                                        ISNULL(ue.mobileno2, '')      
                                                    ),      
                                                    '#EmailID#',      
                                                    ISNULL(ue.emailid, '')      
                                                ),      
                                                '#EmailID1#',      
                                                ISNULL(ue.emailid1, '')      
                                            ),      
                                            '#EmailID2#',      
                                   ISNULL(ue.emailid2, '')      
                                        ),      
                                        '#LastFollowupDate#',      
                                        ISNULL(      
                                            (dbo.fn_getLeadsLastFollowUpDate(ue.leadno, ue.parentid)),      
                                            ''      
                                        )      
                                    ),      
                                    '#NextFollowupDate#',      
                                  
                               case when ue.followupdate is not null then cast(dbo.[fn_getusertimefromindiantime](ue.parentid,ue.followupdate)  as nvarchar) else '' end      
                                  
                                ),      
                                '#AssignedTo#',      
                                ISNULL(ud2.fname, '') + ' '      
                                      
                                      
                                      
                                +      
                                      
                                      
                                ISNULL(ud2.lname, '')      
                            ),      
                            '#LastRemarks#',      
                            ISNULL((dbo.Fn_getleadslastremarks(ue.leadno, ue.parentid)), '')      
                        ),      
                        '#LastProducts#',      
                        ISNULL((dbo.Fn_getleadslastproducts(ue.leadno, ue.parentid)), '')      
                    ),      
                    '#LastFollowupStatus#',      
                    ISNULL((dbo.Fn_getleadslaststatus(ue.leadno, ue.parentid)), '')      
                ),      
                '#CreatedOn#',      
                  
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.createdon)    
                     
            ),      
            '#CreatedBy#',      
            ISNULL(ud.fname, '') + ' '      
                  
                  
                  
            + ISNULL(ud.lname, '')      
        ), '#SourceName#', ISNULL(uss.Name, '')
		), '#MediumName#', ISNULL(ums.Name, '')
		), '#CampaignName#', ISNULL(ucs.Name, '')
		)  
		


 FROM   userleads (nolock) ue       
        LEFT JOIN user_detail (nolock) ud      
             ON  ud.[user_id] = ue.createdby      
        LEFT JOIN user_detail ud2 (nolock)     
             ON  ud2.[user_id] = ue.assignedto      
        Left join UserSourceSettings (nolock) uss
		     on ue.SourceName = uss.SourceID
	    Left join UserMediumSettings (nolock) ums
		     on ue.MediumName = ums.MediumID  		 
        Left join UserCampaignSettings (nolock) ucs
		     on ue.CampaignName = ucs.CampaignID     
 
 WHERE  ue.parentid = @ParentID      
        AND (      
                ue.emailid = @EmailID      
                OR ue.emailid1 = @EmailID      
                OR ue.emailid2 = @EmailID      
            )      
       
       


    SELECT TOP 1 @String = replace( replace( Replace( REPLACE(      
            REPLACE(      
                REPLACE(      
                    REPLACE(      
                        REPLACE(      
                            REPLACE(      
                                REPLACE(      
                                    REPLACE      
                                          
                                          
                                          
                                    (      
                                        REPLACE(      
                                            REPLACE(      
                                                REPLACE(      
                                                    REPLACE      
                                                          
                                                          
                                                          
                                                    (      
                                                        REPLACE      
                                                              
                                                              
                                                              
                                                        (      
                                                            REPLACE      
                                                                  
                                                                  
                                                                  
                                                            (      
                                                                REPLACE      
                                                                      
                                                                      
                                                                      
                                                                (      
                                                                    REPLACE      
                                                                          
                                                                          
                                                                          
                                                                    (@String, '#lead.personname#', ISNULL(ue.personname, '')),      
                                                                    '#lead.CompanyName#',      
                                                                    ISNULL(ue.companyname, '')      
                                                                ),      
                                                                '#lead.MobileNo#',      
                                                                ISNULL(ue.mobileno, '')      
                                                            ),      
                                                            '#lead.MobileNo1#',      
                                                            ISNULL(ue.mobileno1, '')      
                                                        ),      
                                                        '#lead.MobileNo2#',      
                                                        ISNULL(ue.mobileno2, '')      
                                                    ),      
                                                    '#lead.EmailID#',      
                                                    ISNULL(ue.emailid, '')      
                                                ),      
                                                '#lead.EmailID1#',      
                                                ISNULL(ue.emailid1, '')      
                                            ),      
                                            '#lead.EmailID2#',      
                                   ISNULL(ue.emailid2, '')      
                                        ),      
                                        '#lead.LastFollowupDate#',      
                                        ISNULL(      
                                            (dbo.fn_getLeadsLastFollowUpDate(ue.leadno, ue.parentid)),      
                                            ''      
                                        )      
                                    ),      
                                    '#lead.NextFollowupDate#',      
                                  
                               case when ue.followupdate is not null then cast(dbo.[fn_getusertimefromindiantime](ue.parentid,ue.followupdate)  as nvarchar) else '' end      
                                  
                                ),      
                                '#lead.AssignedTo#',      
                                ISNULL(ud2.fname, '') + ' '      
                                      
                                      
                                      
                                +      
                                      
                                      
                                ISNULL(ud2.lname, '')      
                            ),      
                            '#lead.LastRemarks#',      
                            ISNULL((dbo.Fn_getleadslastremarks(ue.leadno, ue.parentid)), '')      
                        ),      
                        '#lead.LastProducts#',      
                        ISNULL((dbo.Fn_getleadslastproducts(ue.leadno, ue.parentid)), '')      
                    ),      
                    '#lead.LastFollowupStatus#',      
                    ISNULL((dbo.Fn_getleadslaststatus(ue.leadno, ue.parentid)), '')      
                ),      
                '#lead.CreatedOn#',      
                  
                dbo.[fn_getusertimefromindiantime](@ParentID,ue.createdon)    
                     
            ),      
            '#lead.CreatedBy#',      
            ISNULL(ud.fname, '') + ' '      
                  
                  
                  
            + ISNULL(ud.lname, '')      
        ), '#lead.SourceName#', ISNULL(uss.Name, '')
		), '#lead.MediumName#', ISNULL(ums.Name, '')
		), '#lead.CampaignName#', ISNULL(ucs.Name, '')
		)



 FROM   userleads (nolock) ue      
        LEFT JOIN user_detail (nolock) ud      
             ON  ud.[user_id] = ue.createdby      
        LEFT JOIN user_detail (nolock) ud2      
             ON  ud2.[user_id] = ue.assignedto
	    Left join UserSourceSettings (nolock) uss
		     on ue.SourceName = uss.SourceID
	    Left join UserMediumSettings (nolock) ums
		     on ue.MediumName = ums.MediumID  		 
        Left join UserCampaignSettings (nolock) ucs
		     on ue.CampaignName = ucs.CampaignID     

