                                                                                                                        '#CompanyName#',      
                                                                                                                        ISNULL(ue.CompanyName, '')      
                                                                                                                    ),      
                                                                                                                    '#MobileNo#',      
                                                                                                                    ISNULL(ue.MobileNo, '')      
                                                                                                                ),      
