                                                                                                    ISNULL(ue.EmailID1, '')      
                                                                                                ),      
                                                                                                '#EmailID2#',      
                                                                                                ISNULL(ue.EmailID2, '')      
                                                                                            ),      
                                                                                            '#LastFollowupDate#',      
                                                                                            ISNULL(      
                                                                                                (dbo.fn_getLeadsLastFollowUpDate(ue.LeadNo, ue.ParentID)),      
                                                                                                ''      
                                                                                            )      
                                                                                        ),      
                                                                                        '#NextFollowupDate#',      
                                                                                        ISNULL(ue.NextStatusDate, '')      
                                                                                    ),      
                                                                                    '#CurrentlyAssignedTo#',      
                                                                                    ISNULL(ud2.FName, '')       
                                                                                          
                                                                                    +      
                                                                                          
                                                                                    ' '       
                                                                                          
                                                                                    +      
                                                                                          
                                                                                          
                                                                                          
                                                                                    ISNULL(ud2.LName, '')      
