                                                    ISNULL(ud.Country, '')      
                                                ),      
                                                '#Address#',      
                                                ISNULL(ue.ResidentialAddress, '')      
                                            ),      
                                            '#PinCode#',      
                                            ISNULL(ue.PinCode, '')      
                                        ),      
                                        '#SourceName#',      
                                        ISNULL(uss.Name, '')      
                                        ),      
                                        '#Source#',      
                                        ISNULL(uss.Name, '')      
                                    ),      
                                    '#MediumName#',      
                                    ISNULL(ums.Name, '')      
                                    ),      
                                    '#Medium#',      
                                    ISNULL(ums.Name, '')      
                                ),      
                                '#CampaignName#',      
