                                ),      
                                '#Campaign#',      
                                ISNULL(ucs.Name, '')      
                            ),      
                            '#ConversionDate#',      
                            ISNULL(dbo.fn_getLeadsConversionDate(ue.LeadNo, @ParentID), '')      
                        ),      
                        '#TotalAmountPaid#',      
                        ISNULL(dbo.fn_getLeadsTotalAmountPaid(ue.LeadNo, @ParentID), '')      
                    ),      
                    '#Products#',      
                    ISNULL(dbo.fn_getLeadsProducts(ue.LeadNo, @ParentID), '')      
