            ),      
            '#ActivityObjectCreatedOn#',      
            ISNULL(ue.LastFollowupCreatedOn, '')      
        )      
 FROM   UserLeads(nolock) ue      
        LEFT JOIN User_Detail(nolock) ud      
             ON  ud.[User_ID] = ue.CreatedBy      
        LEFT JOIN User_Detail(nolock) ud2      
             ON  ud2.[User_ID] = ue.AssignedTo      
        LEFT JOIN UserSourceSettings(nolock)  AS uss      
