/****** Object:  UserDefinedFunction [dbo].[fn_getleadsourcecount]    Script Date: 06-06-26 10:45:39 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

  
CREATE   FUNCTION [dbo].[fn_getleadsourcecount]                        
(@user_id bigint,@fromdate date,@todate date,@sourcename nvarchar(100),@fieldvalue sql_variant)                        
returns int                        
as                        
begin            
        
declare @count int=                        
(select count(1) from  UserLeads(nolock) u join usersourcesettings(nolock) s on s.SourceID=u.sourcename                       
join customfields(nolock) a on a.ParentID=u.ParentID                    
join customfieldLeadvalue(nolock) c on    c.fieldID=a.field_ID    and u.id=c.LeadID                  
where  s.name=@sourcename   and   a.fieldname = 'Brand_name' and   c.fieldvalue=@fieldvalue --and a.isActive=1                    
and cast(u.CreatedOn as date) between @fromdate and @todate            
)                      
                    
return isnull(@count,0)                        
end  
  
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsProducts]    Script Date: 06-06-26 10:45:39 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


   

CREATE   FUNCTION [dbo].[fn_getLeadsProducts]
(
	@LeadNo       BIGINT,
	@ParentID     BIGINT
)
RETURNS NVARCHAR(200)
AS
BEGIN
	DECLARE @String VARCHAR(200)  
	
	SELECT TOP 1 @String = A.ProductName
	FROM   (
	           SELECT TOP 1(
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + pm.Name
	                                     FROM   ProductMaster pm
	                                            INNER JOIN dbo.fn_Split(lih.Products, '#') AS 
	                                                 fs
	                                                 ON  pm.ProductID = fs.[value] 
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  ) AS ProductName,
	                  lih.CreatedOn
	           FROM   LeadInteractionHistory lih
	           WHERE  lih.LeadNo = @LeadNo
	                  AND lih.ParentID = @ParentID
	           ORDER BY
	                  lih.CreatedOn DESC
	       ) A 
	
	RETURN @String
END

GO

/****** Object:  UserDefinedFunction [dbo].[fn_getLeadsRemarks]    Script Date: 06-06-26 10:45:40 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


        



CREATE   FUNCTION [dbo].[fn_getLeadsRemarks]
(
	@LeadNo       BIGINT,
	@ParentID     BIGINT
)
RETURNS NVARCHAR(200)
AS
BEGIN
	DECLARE @String VARCHAR(200)  
	
	
	
	SELECT TOP 1 @String = A.Remarks
	FROM   (
	           SELECT TOP 1 lih.Remarks  AS Remarks
	           FROM   UserLeads          AS ul
	                  INNER JOIN LeadInteractionHistory AS lih
	                       ON  lih.LeadNo = ul.LeadNo
	                       AND lih.ParentID = @ParentID
	           WHERE  ul.LeadNo = @LeadNo
	                  AND ul.ParentID = @ParentID
	           ORDER BY
	                  lih.CreatedOn DESC
	       ) A 
	
	
	
	RETURN @String
END

GO

