CREATE   FUNCTION  [dbo].[fn_getLeadsUserMailMessage] -- 335,'#personname#'      
(      
 @LeadID       BIGINT,
 @ParentID     BIGINT,
 @Message      VARCHAR(MAX)       
)      
RETURNS NVARCHAR(MAX)      
AS      
BEGIN      
 DECLARE @String VARCHAR(MAX)      

 SELECT TOP 1 @String = REPLACE(      
            REPLACE(      
                REPLACE(      
                    REPLACE(      
                        REPLACE(      
                            REPLACE(      
                                REPLACE(      
                                    REPLACE(      
                                        REPLACE(      
                                            REPLACE(      
                                                REPLACE(      
                                                    REPLACE(      
                                                        REPLACE(      
                                                            REPLACE(      
                                                                REPLACE(      
                                                                    REPLACE(@Message, '#personname#', ISNULL(ue.personname, '')),      
                                                                    '#CompanyName#',      
                                                                    ISNULL(ue.companyname, '')      
                                                                ),      
                                                                '#MobileNo#',      
                                                                ISNULL(ue.mobileno, '')      
                                                            ),      
                                                            '#MobileNo1#',      
                                                            ISNULL(ue.mobileno1, '')      
                                                        ),      
                                                        '#MobileNo2#',      
                                                        ISNULL(ue.mobileno2, '')      
                                                    ),      
                                                    '#EmailID#',      
                                                    ISNULL(ue.emailid, '')      
                                                ),      
                                                '#EmailID1#',      
                                                ISNULL(ue.emailid1, '')      
                                            ),      
                                            '#EmailID2#',      
                                   ISNULL(ue.emailid2, '')      
                                        ),      
                                        '#LastFollowupDate#',      
                                        ISNULL(      
                                            (dbo.fn_getLeadsLastFollowUpDate(ue.leadno, ue.parentid)),      
                                            ''      
                                        )      
                                    ),      
                                    '#NextFollowupDate#',      
                                  
                               case when ue.followupdate is not null then cast(dbo.[fn_getusertimefromindiantime](ue.parentid,ue.followupdate)  as nvarchar) else '' end      
                                  
                                ),      
                                '#CurrentlyAssignedTo#',      
                                ISNULL(ud2.fname, '') + ' ' + ISNULL(ud2.lname, '')      
                            ),      
                            '#LastRemarks#',      
                            ISNULL((dbo.Fn_getleadslastremarks(ue.leadno, ue.parentid)), '')      
                        ),      
                        '#LastProducts#',      
                        ISNULL((dbo.Fn_getleadslastproducts(ue.leadno, ue.parentid)), '')      
                    ),      
                    '#LastFollowupStatus#',      
                    ISNULL((dbo.Fn_getleadslaststatus(ue.leadno, ue.parentid)), '')      
                ),      
                '#CreatedOn#', dbo.[fn_getusertimefromindiantime](@ParentID,ue.createdon)    
            ),      
            '#CreatedBy#',      
            ISNULL(ud.fname, '') + ' ' + ISNULL(ud.lname, '')      
        )      
 FROM   userleads(nolock) ue      
        LEFT JOIN user_detail(nolock) ud      
             ON  ud.[user_id] = ue.createdby      
        LEFT JOIN user_detail(nolock) ud2      
             ON  ud2.[user_id] = ue.assignedto      
 WHERE  ue.parentid = @ParentID AND ue.ID = @LeadID
       
 IF @String = ''      
 BEGIN      
     SET @String = REPLACE(      
             REPLACE(      
                 REPLACE(      
                     REPLACE(      
                         REPLACE(      
                             REPLACE(      
                                 REPLACE(      
                                     REPLACE(      
                                         REPLACE(      
                                             REPLACE(      
                                                 REPLACE(      
                                                     REPLACE(      
                                                         REPLACE(      
                                                             REPLACE(     
                                                                 REPLACE(      
                                                    REPLACE(@Message, '#personname#', ''),      
                                                                     '#CompanyName#', ''      
                                                                 ),      
                                                                 '#MobileNo#',      
                                                                 ''      
                                                             ),      
                                                             '#MobileNo1#',      
                                                             ''      
                                                         ),      
                                                         '#MobileNo2#',      
                                                         ''      
                                                     ),      
                                                     '#EmailID#',      
                                                     ''      
                                                 ),      
                                                 '#EmailID1#',      
                                                 ''      
                                             ),      
                                             '#EmailID2#',      
                                             ''      
                                         ),      
                                         '#LastFollowupDate#',      
                                         ''      
                                     ),      
                                     '#NextFollowupDate#',      
                                     ''      
                                 ),      
                                 '#CurrentlyAssignedTo#',      
                                 ''      
                             ),      
                             '#LastRemarks#',      
                             ''      
                         ),      
                         '#LastProducts#',      
                         ''      
                     ),      
                     '#LastFollowupStatus#',      
                     ''      
                 ),      
                 '#CreatedOn#',      
                 ''      
             ),      
             '#CreatedBy#',      
             ''      
         )      
 END      
          
       
       
       
 RETURN @String      
END    

GO

