/****** Object:  UserDefinedFunction [dbo].[fn_getleaduserwisesourcecount]    Script Date: 06-06-26 10:45:41 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getleaduserwisesourcecount]                          
(@user_id bigint,@fromdate date,@todate date,@sourcename nvarchar(100),@fieldvalue sql_variant)         
returns int                          
as                          
begin              
          
declare @count int=                          
(select count(1) from  UserLeads(nolock) u join usersourcesettings(nolock) s on s.SourceID=u.sourcename                         
join customfields a on a.ParentID=u.ParentID                      
join customfieldLeadvalue c on    c.fieldID=a.field_ID and u.id=c.LeadID                       
where AssignedTo=@user_id and s.name=@sourcename   and   a.fieldname = 'brand_name' and fieldvalue=@fieldvalue and a.isActive=1                      
and u.CreatedOn between @fromdate and @todate
)                        
                      
return isnull(@count,0)                          
end  

GO

