CREATE   FUNCTION [dbo].[fn_GetListMessage] -- 335,'#personname#'
(
	@Message          VARCHAR(2000),
	@ImportListID     BIGINT,
	@ParentID         BIGINT,
	@MobileNo         VARCHAR(50)
)
RETURNS NVARCHAR(MAX)
AS


BEGIN
	DECLARE @String VARCHAR(MAX)
	
	SELECT TOP 1 @String = REPLACE(
	           REPLACE(
	               REPLACE(
	                   REPLACE(
	                       REPLACE(
	                           REPLACE(
	                               REPLACE(
	                                   REPLACE(
	                                       REPLACE(
	                                           REPLACE(
	                                               @Message,
	                                               '#' + uilc.Column1 + '#',
	                                               ISNULL(usd.MobileNumber, '')
	                                           ),
	                                           '#' + uilc.Column2 + '#',
	                                           ISNULL(usd.EmailID, '')
	                                       ),
	                                       '#' + uilc.Column3 + '#',
	                                       ISNULL(usd.Column1, '')
	                                   ),
	                                   '#' + uilc.Column4 + '#',
	                                   ISNULL(usd.Column2, '')
	                               ),
	                               '#' + uilc.Column5 + '#',
	                               ISNULL(usd.Column3, '')
	                           ),
	                           '#' + uilc.Column6 + '#',
	                           ISNULL(usd.Column4, '')
	                       ),
	                       '#' + uilc.Column7 + '#',
	                       ISNULL(usd.Column5, '')
	                   ),
	                   '#' + uilc.Column8 + '#',
	                   ISNULL(usd.Column6, '')
	               ),
	               '#' + uilc.Column9 + '#',
	               ISNULL(usd.Column7, '')
	           ),
	           '#' + uilc.Column10 + '#',
	           ISNULL(usd.Column8, '')
	       )
	FROM   UserImportedListColumn uilc
	       INNER JOIN UserSearchData usd
	            ON  usd.ParentID = uilc.ParentID
	            AND uilc.ID = usd.ImportedListID
	WHERE  uilc.ID = @ImportListID
	       AND uilc.ParentID = @ParentID
	       AND usd.MobileNumber = @MobileNo
	           
	           RETURN @String
END


GO

