CREATE   FUNCTION [dbo].[fn_GetListMessageMails] -- 335,'#personname#'
(
	@MailContent      VARCHAR(2000),
	@ImportListID     BIGINT,
	@ParentID         BIGINT,
	@EmailID          VARCHAR(50)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
	DECLARE @String VARCHAR(MAX) 
	
	
	SELECT TOP 1 @String = REPLACE(
	           REPLACE(
	               REPLACE(
	                   REPLACE(
	                       REPLACE(
	                           REPLACE(
	                               REPLACE(
	                                   REPLACE(
	                                       REPLACE(
	                                           REPLACE(
	                                               @MailContent,
	                                               '#' + uilc.column1 +
	                                               '#',
	                                               ISNULL(usd.mobilenumber, '')
	                                           ),
	                                           '#' + uilc.column2 + '#',
	                                           ISNULL(usd.emailid, '')
	                                       ),
	                                       '#' + uilc.column3 + '#',
	                                       ISNULL(usd.column1, '')
	                                   ),
	                                   '#' + uilc.column4 +
	                                   '#',
	                                   ISNULL(usd.column2, '')
	                               ),
	                               '#' + uilc.column5 + '#',
	                               ISNULL(usd.column3, '')
	                           ),
	                           '#' + uilc.column6 + '#',
	                           ISNULL(usd.column4, '')
	                       ),
	                       '#' + uilc.column7 + '#',
	                       ISNULL(usd.column5, '')
	                   ),
	                   '#' + uilc.column8 + '#',
	                   ISNULL(usd.column6, '')
	               ),
	               '#' + uilc.column9 + '#',
	               ISNULL(usd.column7, '')
	           ),
	           '#' + uilc.column10 + '#',
	           ISNULL(usd.column8, '')
	       )
	FROM   userimportedlistcolumn uilc
	       INNER JOIN usersearchdata usd
	            ON  usd.parentid = uilc.parentid
	            AND uilc.id = usd.importedlistid
	WHERE  uilc.id = @ImportListID
	       AND uilc.parentid = @ParentID
	       AND usd.emailid = @EmailID
	
	IF ISNULL(@String, '') = ''
	BEGIN
	    SET @String = @MailContent
	END
	
	RETURN @String
END 

GO

