CREATE   FUNCTION [dbo].[fn_getlocation]
(@lid int,@locationtype nvarchar(20))
returns nvarchar(100)
as
begin
declare @location nvarchar(100)
select @location=case when @locationtype='Country' then (select Country_Name from m_country1(nolock) where Country_ID=@lid)
when @locationtype='State' then (select State_Name from m_state1(nolock) where State_ID=@lid)
when @locationtype='City' then (select City_Name from m_city1(nolock) where City_ID=@lid)
end
return @location
end
