/****** Object:  UserDefinedFunction [dbo].[fn_GetMessageCount]    Script Date: 06-06-26 10:45:43 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_GetMessageCount](@messagelength int,@unicode int)  
returns int  
as  
begin  
Declare @msgcount int  
 if(@unicode=0)  
 begin 
 if(@messagelength<160)
 begin 
 set @msgcount=CAST(CEILING((cast(@messagelength as float)/160)) AS INT)  
 End   
 else if(@messagelength>160)
 begin
  set @msgcount=CAST(CEILING((cast(@messagelength as float)/153)) AS INT)  
 end
 end
 Else  
 begin 
  if(@messagelength<70)
 begin 
 set @msgcount=CAST(CEILING((cast(@messagelength as float)/70)) AS INT)  
 end  
 else  if(@messagelength>70)
 begin 
 set @msgcount=CAST(CEILING((cast(@messagelength as float)/67)) AS INT)  
 end  
 end
  if(@msgcount=0)  
  begin  
    set @msgcount=1  
  end   
return @msgcount  
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getmessagewithshorturl]    Script Date: 06-06-26 10:45:43 ******/
