GO

CREATE   FUNCTION  [dbo].[fn_getmessagewithshorturl]  
(@message nvarchar(2500),@BATCHID bigint,@mobile nvarchar(20))  
returns nvarchar(2500)  
as  
begin  
if exists(select 1 from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid)  
begin
if (select UserID from BatchInfo(nolock) where batchid=@batchid)=335
begin
declare @ce int=(select count(1) from Link_smsMobilefromclone (nolock) lm where Mobile=@mobile and batchid=@batchid)  
declare @ide int=0  
while @ce>0  
begin  
select @ide=min(lm.mobile_url_id) from Link_smsMobilefromclone (nolock) lm where Mobile=@mobile and batchid=@batchid and mobile_url_id>@ide  
select @message=rtrim(ltrim(REPLACE(@message,longurl, shorturl+'/'+Final_url))) from Link_smsMobilefromclone (nolock) lm where mobile_url_id=@ide  
select @ce=@ce-1  
end  
end
declare @c int=(select count(1) from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid)  
declare @id int=0  
while @c>0  
begin  
select @id=min(lm.mobile_url_id) from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid and mobile_url_id>@id  
select @message=rtrim(ltrim(REPLACE(@message,longurl, shorturl+'/'+Final_url))) from Link_smsMobile (nolock) lm where mobile_url_id=@id  
select @c=@c-1  
end  
end  
return @message  
end  
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getmessagewithshorturl_m]    Script Date: 06-06-26 10:45:44 ******/
