CREATE   FUNCTION  [dbo].[fn_getmessagewithshorturl_m]      
(@message nvarchar(2500),@BATCHID bigint,@mobile nvarchar(20),@messageid bigint)      
returns nvarchar(2500)      
as      
begin      
if exists(select 1 from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid)      
begin    
if (select UserID from BatchInfo(nolock) where batchid=@batchid)=335    
begin    
declare @ce int=(select count(1) from Link_smsMobilefromclone (nolock) lm where Mobile=@mobile and batchid=@batchid  and (MessageID=@messageid or cast(batchid as nvarchar)+cast(messageid as nvarchar)=@messageid  ))      
declare @ide int=0      
while @ce>0      
begin      
select @ide=min(lm.mobile_url_id) from Link_smsMobilefromclone (nolock) lm where Mobile=@mobile and batchid=@batchid and (MessageID=@messageid or cast(batchid as nvarchar)+cast(messageid as nvarchar)=@messageid) and mobile_url_id>@ide      
select @message=rtrim(ltrim(REPLACE(@message,longurl, shorturl+'/'+Final_url))) from Link_smsMobilefromclone (nolock) lm where mobile_url_id=@ide      
select @ce=@ce-1      
end      
end    
declare @c int=(select count(1) from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid  and (MessageID=@messageid or cast(batchid as nvarchar)+cast(messageid as nvarchar)=@messageid  ))      
declare @id int=0      
while @c>0      
begin      
select @id=min(lm.mobile_url_id) from Link_smsMobile (nolock) lm where Mobile=@mobile and batchid=@batchid and mobile_url_id>@id  and (MessageID=@messageid or cast(batchid as nvarchar)+cast(messageid as nvarchar)=@messageid  )     
select @message=rtrim(ltrim(REPLACE(@message,longurl, shorturl+'/'+Final_url))) from Link_smsMobile (nolock) lm where mobile_url_id=@id      
select @c=@c-1      
end      
end      
return @message      
end 
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getmobile_linktracking_stats]    Script Date: 06-06-26 10:45:44 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getmobile_linktracking_stats](@mobile nvarchar(20),@fromdate date,@todate date,@status nvarchar(20),@parentid bigint)
returns int
as
begin
declare @count int
select @count=case when @status='Total' then
(select count(1) from Link_smsMobile(nolock) where Mobile=@mobile and parentid=@parentid and cast(CreatedDate as date) between @fromdate and @todate)
when @status='Uniqueclicks' then
(select count(distinct link_id) from Link_smsTrack(nolock) where mobile=@mobile and parentid=@parentid and cast(VisitDate as date) between @fromdate and @todate)
when @status='Totalclicks' then
(select count(link_id) from Link_smsTrack(nolock) where mobile=@mobile and parentid=@parentid and cast(VisitDate as date) between @fromdate and @todate)
end
return isnull(@count,0)
end


GO

