GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[fn_getmobilestring] -- 335,'#personname#'
(
	@countrycode nvarchar(10),
	@countrycode1 nvarchar(10),
	@countrycode2 nvarchar(10),
	@mobile nvarchar(20),
	@mobile1 nvarchar(20),
	@mobile2 nvarchar(20)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
DECLARE @String VARCHAR(MAX)

if ISNULL(@mobile,'')<>'' and isnull(@countrycode,'')<>''
begin
set @String=@countrycode+@mobile
end
if ISNULL(@mobile1,'')<>'' and isnull(@countrycode1,'')<>''
begin
if @String  is not null
begin
set @String = @string + ' , ' + @countrycode1+@mobile1
end
else
begin
set @String=@countrycode1+@mobile1
end
end
if ISNULL(@mobile2,'')<>'' and isnull(@countrycode2,'')<>''
begin
if @String  is not null
begin
set @String = @string + ' , ' + @countrycode2+@mobile2
end
else
begin
set @String=@countrycode2+@mobile2
end
end
if @String is null
begin
set @String=''
end
RETURN @String
END 

GO

