as
begin
declare @newcolumnvalue nvarchar(max)
if @columnname='sourcename'
  select @newcolumnvalue=name from usersourcesettings(nolock) where SourceID=@columnvalue
else if @columnname='mediumname'
  select @newcolumnvalue=name from usermediumsettings(nolock) where mediumID=@columnvalue
else if @columnname='campaignname'
  select @newcolumnvalue=name from usercampaignsettings(nolock) where campaignID=@columnvalue
else if @columnname='followupstatus'
