/****** Object:  UserDefinedFunction [dbo].[fn_getnextschedule]    Script Date: 06-06-26 10:45:46 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--select dbo.fn_getnextschedule      
      
--select dbo.fn_getnextschedule(SequenceActionId),      
--* from tbl_WA_SequenceActionMaster      
      
--update tbl_WA_SequenceActionMaster set fromtime='00:00:00.0000000',ToTime='00:00:00.0000000' where totime is null      
CREATE   FUNCTION [dbo].[fn_getnextschedule](@sequenceactionid bigint)        
returns datetime        
as        
begin       
--declare @sequenceactionid bigint=0,@c int      
--drop table if exists #s      
--select * into #s from tbl_WA_SequenceActionMaster      
--select @c=count(1) from #s      
--while @c>0      
--begin      
--select @sequenceactionid=min(sequenceactionid) from #s where SequenceActionId>@sequenceactionid      
declare @dt datetime,@fromtime time,@totime time,@day nvarchar(50),@date date,@weekday int,@nearestday int        
select @dt=case when timeunit = 'day' then dateadd(dd,cast(TimeInterval as int),getdate()) when timeunit = 'Hour' then dateadd(hh,cast(TimeInterval as int),getdate())        
when timeunit = 'Minutes' then dateadd(mi,cast(TimeInterval as int),getdate()) when timeunit = 'Seconds' then dateadd(SS,cast(TimeInterval as int),getdate()) end,@fromtime=FromTime,@totime=totime,@day=days from [10.0.0.135].MysmsConversations.dbo.tbl_WA_SequenceActionMaster with (nolock)         
where SequenceActionId=@sequenceactionid        
select @day=replace(replace(replace(replace(replace(replace(replace(@day,'Sun',1),'Mon',2),'Tue',3),'Wed',4),'Thu',5),'Fri',6),'Sat',7)        
select @weekday=datepart(dw,@dt)        
select @nearestday=        
case when @day like '%'+cast(@weekday as nvarchar)+'%' or @day like 'Anyday%' then 0         
else isnull((select min(value) from dbo.fn_split(@day,',') where value>=@weekday),(select min(value) from dbo.fn_split(@day,',')))         
end        
      
--select @dt,@nearestday,@weekday,@fromtime,@totime,@day,@nearestday-@weekday,7-@weekday+@nearestday      
select @dt=        
case when @nearestday=0 and @fromtime='00:00:00.0000000' and @totime='00:00:00.0000000' then @dt        
when @nearestday=0 and (@fromtime<>'00:00:00.0000000' or @totime<>'00:00:00.0000000') then         
case   
when cast(@dt as time) between cast(@fromtime as time) and cast(@totime as time) then @dt  
when cast(cast(cast(@dt as date) as nvarchar) +' '+left(@fromtime,12) as datetime) >getdate() then       
cast(cast(cast(@dt as date) as nvarchar) +' '+left(@fromtime,12) as datetime)       
else      
dateadd(d,1,cast(cast(cast(@dt as date) as nvarchar) +' '+left(@fromtime,12) as datetime)) end      
when @nearestday>@weekday and @fromtime='00:00:00.0000000' and @totime='00:00:00.0000000' then dateadd(dd,@nearestday-@weekday,@dt)        
when @nearestday<@weekday and @fromtime='00:00:00.0000000' and @totime='00:00:00.0000000' then dateadd(dd,7-@weekday+@nearestday,@dt)        
when @nearestday>@weekday and (@fromtime<>'00:00:00.0000000' or @totime<>'00:00:00.0000000')         
then dateadd(dd,@nearestday-@weekday,cast(cast(cast(@dt as date) as nvarchar) +' '+left(@fromtime,12) as datetime))        
when @nearestday<@weekday and (@fromtime<>'00:00:00.0000000' or @totime<>'00:00:00.0000000')         
then dateadd(dd,7-@weekday+@nearestday,cast(cast(cast(@dt as date) as nvarchar) +' '+left(@fromtime,12) as datetime))        
end        
return @dt--,  * from tbl_WA_SequenceActionMaster where SequenceActionId=@sequenceactionid      
--set @c=@c-1      
--end      
      
end 
GO

/****** Object:  UserDefinedFunction [dbo].[fn_getnexttemplateidingroup]    Script Date: 06-06-26 10:45:46 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getnexttemplateidingroup]
(@campaignid bigint)
returns int
as
begin
declare @nexttemplateid int,@lasttemplateorder int,@templategroup int,@lasttemplateid int,@id bigint,@nextorderno int,@isrecurring int
,@lastcampaignexecution datetime,@templatesequence int

select @templategroup=TemplateGroupID,@isrecurring=isrecurring,@lastcampaignexecution=ExecutedDateTime,
@templatesequence=TemplateGroupSequence 
from usercampaignmaster(nolock) where id=@campaignid
if @lastcampaignexecution is null
begin
select @nexttemplateid=templateid from usergrouptemplatemix(nolock)
where groupid=@templategroup and isactivated=1  and orderno=@templatesequence
end
else
begin
--select top 1 @lasttemplateorder=templatesequence,@lasttemplateid=templateid from usercampaignexecutionhistory(nolock)
--where campaignid=@id and IsExecuted=1 order by id desc
select top 1 @nextorderno=orderno,@nexttemplateid=templateid from usergrouptemplatemix(nolock)
where groupid=@templategroup and isactivated=1 and orderno=@templatesequence+1
if @nexttemplateid is null
select @nexttemplateid=templateid from usergrouptemplatemix(nolock) where
orderno=case when @isrecurring=1 then 1 end
end
return isnull(@nexttemplateid,0)
end

--select top 10 * from usercampaignmaster where templategroupid<>0 order by id desc
--select * from usergrouptemplatemix(nolock) where groupid=1931

