CREATE   FUNCTION [dbo].[fn_getNotificationURL]  
(  
  @NotificationID bigint  
)  
Returns nvarchar(max)     
Begin  
       
 declare @entity nvarchar(20),@entityid bigint,@view nvarchar(200),@reftable nvarchar(50),@refid nvarchar(100)    
 select @reftable=reftable,@refid=refid from notificationhistory(nolock) where id = @NotificationID      
 select @entity=    
 case when @reftable='tbl_LeadEventHistory' then 'Lead' when @reftable='tbl_enquiryEventHistory' then 'Enquiry' when     
 @reftable='tbl_userEventHistory' then 'User' end    
 select @entityid=     
 case when @entity='Lead' then (select leadid from tbl_leadeventhistory(nolock) where historyid=@refid)    
 when @entity='Enquiry' then (select enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@refid)    
 when @entity='User' then (select userid from tbl_usereventhistory(nolock) where historyid=@refid) end    
         
  declare @URL nvarchar(max) =  case     
     when @entity='Lead' then 'https://kit19.com/UserCRMCampaign/LeadDetails.aspx?LeadID='+cast(@entityid as nvarchar)    
     when @entity='Enquiry' then 'https://kit19.com/UserCRMCampaign/Enquiry.aspx?EnquiryID='+cast(@entityid as nvarchar)    
     else 'https://Kit19.com' end  
   
     return @URL  
end
