/****** Object:  UserDefinedFunction [dbo].[fn_getparent_allowedstorage]    Script Date: 06-06-26 10:45:47 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getparent_allowedstorage](@user_id bigint)
  returns numeric(9,2)
  as
  begin
  declare @parentid bigint=dbo.ufn_getuserparentid(@user_id),@def numeric (9,2),@pur numeric(9,2),@tot numeric(9,2)
  
  select top 1 @def= allocatedspace from [tbl_ML_UserStorageQuota](nolock) where parentid in (@parentid,0) and allocationtype='Default' and isactive=1 order by parentid desc
  select @pur=sum(allocatedspace) from [tbl_ML_UserStorageQuota](nolock) where parentid=@parentid and allocationtype<>'Default' and getdate() between startdate and ExpiryDate and IsActive=1
  select @tot=isnull(@def,0)+isnull(@pur,0)
  return isnull(@tot,0)
  end

GO

