       Declare @TempEXP nvarchar(max) = + ' ( PipelineID in '  + '(''' + CAST( @PipelineName  as nvarchar) + ''') ) '     
        set @ModifiedPipelineExpByName =  @TempEXP      
        
   End        
    else if(@DummyCount = 2 )         
      Begin        
       declare @Temp1 nvarchar(max) = left(@PipelineOLDExp,charindex('$',@PipelineOLDExp,1)-1)        
              
    set @Temp1 = REPLACE(@Temp1,'PipelineID in','')      
    set @Temp1 = RTRIM(LTRIM(@Temp1))      
    set @Temp1 = left(@Temp1,len(@Temp1)-1)        
