    set @Temp2 = REPLACE(@Temp2,'(','')      
    set @Temp2 = REPLACE(@Temp2,')','')      
    set @Temp2 = RTRIM(ltrim(@Temp2))      
    set @Temp2 = replace(@Temp2,' ','')    
    
     declare @StagesByName nvarchar(max) = ''       
  SELECT @StagesByName = isnull(STRING_AGG( ''''+ [Name] + '''' , ','), '')    
       FROM    
     (    
    select    
     (    
      select top 1 cast([Name] as nvarchar(500)) as [Name] from PipelineStages with(nolock) where ID = REPLACE([Value],'''','')  and IsDeleted = 0     
     ) as [Name]    
      from fn_Split(@Temp2,',') where [value] is not null    
      ) as tbl    
       
    
     if(trim(@StagesByName) <> '')    
      Begin    
     declare @stagesStr nvarchar(max) = ( Concat(' and PipelineStageID in (', cast( @StagesByName as nvarchar) , ') ') )    
      set @TempEXP1 += @stagesStr + ' )'    
   End    
           else    
      Begin    
             set @TempEXP1 += ')'                   
   End       
         
   if( trim(@ModifiedPipelineExpByName) <> '' )    
