CREATE   FUNCTION [dbo].[fn_getPipelineExpForSQL]             
(            
  @PipelineExp nvarchar(max),            
  @ParentID bigint               
 )            
RETURNs nvarchar(max)            
 AS            
BEGIN            
        
  --Declare @PipelineExp nvarchar(max) = N' (  ( PipelineID in (''Product Name: Uk to Canada'') and PipelineStageID in ( ''Zoom Called Conducted and Interested'')  )  ) ',            
  -- @ParentID bigint =   49995            

  Declare @ModifiedPipelineExp nvarchar(max) = ''            
  --  Declare @PipelineExp nvarchar(max) = ''        
  --  Declare @ParentID bigint = 40834                  
  --set @PipelineExp =   ' ( ( PipelineID in (''frstppln'') and PipelineStageID in ( ''stg2'',''stg4'',''Won'',''Lost'') ) or ( PipelineID in (''thrdppln'') ) or ( PipelineID in (''tstpplin3'') and PipelineStageID in ( ''rty6'') ) ) '            
      
   -- set @PipelineExp = '( ( PipelineID in (''PGT (1st Grade) Chemistry'') and PipelineStageID in ( ''Trial'',''Course Discussion'',''Positive Feedback'',''Waiting for Discount & Other'',''New Lead'',''App Download'',''want to join Trial Course'') ) )'  
  
      
   --set @PipelineExp = ' (  ( PipelineID in (''Diwali offer'') and PipelineStageID in ( ''New Leads'',''Interested in RPSC PGT (New Students)'',''Interested in RPSC PGT (Old Students)'',''Interested in CSIR NET & GATE'',''RPSC PGT Trial Joined'',''NET & GATE Trial Joined'',''PGT Course Upgrade'')  )  ) '    
      
                      
     set @PipelineExp = rtrim(ltrim(@PipelineExp))               
     set @PipelineExp =  left(@PipelineExp,len(@PipelineExp)-1)            
     set @PipelineExp =  right(@PipelineExp,len(@PipelineExp)-1)             
             
     set @PipelineExp =  REPLACE(@PipelineExp,' or ', ' ^ ')        
     set @PipelineExp =  REPLACE(@PipelineExp,' and ', ' $ ')          
                    
      declare @devidedExpTBL as table            
            (             
                RowNum  int,              
                DevidedOred nvarchar(max)              
            )                 
    insert into @devidedExpTBL(RowNum,DevidedOred)                     
   select ROW_NUMBER() over(order by [Value]  asc) as RowNum , [value] as DevidedOred  from fn_Split(@PipelineExp,'^');                 
   declare @Count int = ( select count(1) from @devidedExpTBL )            
     
   --print (@Count)  
     
   declare @RowIndex int = 1            
   while(@Count > 0)            
     Begin            
      declare @ExpSingle nvarchar(max) = (select DevidedOred from @devidedExpTBL where RowNum = @RowIndex)               
      declare @DummyCount int = ( select count(1) from fn_Split(@ExpSingle,'$'))            
      declare @innerTempTBL as table          
     (          
      innerRowIndex int,          
      innerEXP nvarchar(max)          
     )          
            
     --print 'dummy count ' + cast(@DummyCount as nvarchar(200))  
       
   if(@DummyCount = 1 and 1=1)            
      Begin            
       declare @Temp nvarchar(max) = @ExpSingle  --left(@ExpSingle,charindex(' and ',@ExpSingle,1)-1)            
       set @Temp = REPLACE(@Temp,' PipelineID in ','')          
      set @Temp = RTRIM(LTRIM(@Temp))          
      set @Temp = left(@Temp,len(@Temp)-1)            
          set @Temp = RTRIM(LTRIM(@Temp))          
      set @Temp =  right(@Temp,len(@Temp)-1)            
      set @Temp = RTRIM(LTRIM(@Temp))            
         
   --set @Temp = REPLACE(@Temp,'(','')          
      --set @Temp = REPLACE(@Temp,')','')           
         
   set @Temp = substring(@Temp,2,len(@Temp))    
   set @Temp = reverse(@Temp);    
   set @Temp = substring(@Temp,2,len(@Temp))    
   set @Temp = reverse(@Temp);    
              
      
   set @Temp = REPLACE(@Temp,'''','')           
   set @Temp = trim('( ' from @Temp)  
   set @Temp =  trim(') ' from @Temp)  
      
        
       declare @PipelineID nvarchar(50) = ''          
       select top 1 @PipelineID = cast(ID as nvarchar(50)) from Pipeline_Master with(nolock) where IsDeleted =0 and ParentID = @ParentID and [Name] = @Temp             
          --set @ModifiedPipelineExp =  @ModifiedPipelineExp             
       Declare @TempEXP nvarchar(max) = + ' ( PipelineID in '  + '(' + CAST( isnull(nullif(@PipelineID,''),'0')  as nvarchar(max)) + ') ) '         
        
     if( trim(@ModifiedPipelineExp) <> '' )        
    Begin                         
           set @ModifiedPipelineExp = @ModifiedPipelineExp + ' or ' + @TempEXP          
          end        
   else        
     Begin        
         set @ModifiedPipelineExp =  @TempEXP          
     End        
        
        
      End            
    else if(@DummyCount = 2 )             
      Begin            
          declare @Temp1 nvarchar(max) = left(@ExpSingle,charindex('$',@ExpSingle,1)-1)            
                  
            
    set @Temp1 = REPLACE(@Temp1,' PipelineID in ','')          
    set @Temp1 = RTRIM(LTRIM(@Temp1))          
    set @Temp1 = left(@Temp1,len(@Temp1)-1)            
          set @Temp1 = RTRIM(LTRIM(@Temp1))          
    set @Temp1 =  right(@Temp1,len(@Temp1)-1)            
    set @Temp1 = RTRIM(LTRIM(@Temp1))            
        
 --set @Temp1 = REPLACE(@Temp1,'(','')          
 --   set @Temp1 = REPLACE(@Temp1,')','')           
        
   set @Temp1 = substring(@Temp1,2,len(@Temp1))    
   set @Temp1 = reverse(@Temp1);    
   set @Temp1 = substring(@Temp1,2,len(@Temp1))    
   set @Temp1 = reverse(@Temp1);    
     
   set @Temp1 = REPLACE(@Temp1,'''','')           
   set @Temp1 = trim('( ' from @Temp1)  
   set @Temp1 =  trim(') ' from @Temp1)  
   
  
  
    declare @PipelineID1 nvarchar(50) = ''          
    select top 1 @PipelineID1 = cast(ID as nvarchar(50)) from Pipeline_Master with(nolock) where IsDeleted =0 and ParentID = @ParentID and [Name] = @Temp1             
 Declare @TempEXP1 nvarchar(max) =  ' ( PipelineID in '  + '(' + CAST( isnull(nullif(@PipelineID1,''),'0')  as nvarchar(max)) + ') '          
    declare @Temp2 nvarchar(max) = '';           
    set @Temp2 = (substring(@ExpSingle,charindex('PipelineStageID',@ExpSingle,1),len(@ExpSingle)))          
               
         
 set @Temp2 = REPLACE(@Temp2,'PipelineStageID in','')          
        
 --set @Temp2 = REPLACE(@Temp2,'(','')          
    --set @Temp2 = REPLACE(@Temp2,')','')          
    --set @Temp2 = RTRIM(ltrim(@Temp2))     
     
   set @Temp2 = substring(@Temp2,2,len(@Temp2))    
   set @Temp2 = reverse(@Temp2);    
   set @Temp2 = substring(@Temp2,2,len(@Temp2))    
   set @Temp2 = reverse(@Temp2);    
   set @Temp2 = RTRIM(ltrim(@Temp2))     
      
   set @Temp2 = trim('( ' from @Temp2)  
   set @Temp2 =  trim(') ' from @Temp2)  
        
  -- print 'temnp2 ' + cast(@temp2 as nvarchar(200))     
       
    --set @Temp2 = replace(@Temp2,' ','')        
              
   -- select value from fn_Split(@Temp2,',')            
     
  
     declare @StagesByID nvarchar(max) = ''           
  SELECT @StagesByID = isnull(STRING_AGG(  ID , ','), '')        
       FROM        
     (        
    select        
     (        
       select cast( isnull( (select top 1 cast(ID as nvarchar(max)) as ID  from PipelineStages with(nolock) where Name = REPLACE([Value],'''','') and PipelineID = @PipelineID1 and IsDeleted = 0), 0 ) as nvarchar(max) ) as ID 
	          
     ) as ID        
      from fn_Split(@Temp2,',') where isnull([value],'') != ''        
      ) as tbl        
           
        
     if(trim(@StagesByID) <> '')        
      Begin        
     declare @stagesStr nvarchar(max) = ( Concat(' and PipelineStageID in (', cast( @StagesByID as nvarchar(max)) , ') ') )        
      set @TempEXP1 += @stagesStr + ' )'        
   End        
           else        
      Begin        
             set @TempEXP1 += ')'                       
   End           
             
           
   if( trim(@ModifiedPipelineExp) <> '' )        
    Begin                         
           set @ModifiedPipelineExp = @ModifiedPipelineExp + ' or ' + @TempEXP1          
          end        
   else        
     Begin        
         set @ModifiedPipelineExp =  @TempEXP1          
     End          
    End              
   set @RowIndex += 1            
   set @Count -= 1            
              
  End -- end of while loop            
            
  set  @ModifiedPipelineExp  = '('+ case when isnull(@ModifiedPipelineExp,'') = ''
                                               then ' ( 1 = 1 ) '
                                      else @ModifiedPipelineExp end + ')'
                                              
  return @ModifiedPipelineExp    
  --select @ModifiedPipelineExp              
END 
