 Declare @TempEXP1 nvarchar(max) =  ' ( PipelineID in '  + '(' + CAST( @PipelineID1  as nvarchar) + ') '      
    declare @Temp2 nvarchar(max) = '';       
    set @Temp2 = (substring(@ExpSingle,charindex('PipelineStageID',@ExpSingle,1),len(@ExpSingle)))      
           
     
 set @Temp2 = REPLACE(@Temp2,'PipelineStageID in','')      
    set @Temp2 = REPLACE(@Temp2,'(','')      
    set @Temp2 = REPLACE(@Temp2,')','')      
    set @Temp2 = RTRIM(ltrim(@Temp2))      
    --set @Temp2 = replace(@Temp2,' ','')    
    
     declare @StagesByID nvarchar(max) = ''       
  SELECT @StagesByID = isnull(STRING_AGG(  ID , ','), '')    
       FROM    
     (    
    select    
     (    
      select top 1 cast(ID as nvarchar(50)) as ID from PipelineStages with(nolock) where Name = REPLACE([Value],'''','') and PipelineID = @PipelineID1 and IsDeleted = 0     
     ) as ID    
      from fn_Split(@Temp2,',') where [value] is not null    
      ) as tbl    
       
    
     if(trim(@StagesByID) <> '')    
      Begin    
     declare @stagesStr nvarchar(max) = ( Concat(' and PipelineStageID in (', cast( @StagesByID as nvarchar) , ') ') )    
      set @TempEXP1 += @stagesStr + ' )'    
   End    
           else    
      Begin    
             set @TempEXP1 += ')'                   
   End       
         
       
   if( trim(@ModifiedPipelineExp) <> '' )    
    Begin                     
           set @ModifiedPipelineExp = @ModifiedPipelineExp + ' or ' + @TempEXP1      
          end    
   else    
     Begin    
         set @ModifiedPipelineExp =  @TempEXP1      
     End      
    End          
   set @RowIndex += 1        
   set @Count -= 1        
          
  End -- end of while loop        
        
  set  @ModifiedPipelineExp  = '('+ @ModifiedPipelineExp + ')'                
     return @ModifiedPipelineExp          
END 
