CREATE   FUNCTION [dbo].[fn_getrelativescore](@leadid bigint)      
returns int-- numeric(18,2)      
as      
begin      
declare @parentid bigint=(select parentid from userleads(nolock) where id=@leadid)      
declare @max int=(select (max(currentscore)*100)/99 from lead_score_history(nolock) e where parentid=@parentid),@relativescore numeric(18,2)      
select top 1 @relativescore= round((currentscore/cast(@max as float)*99),2) from lead_score_history(nolock) e       
where leadid=@leadid and parentid=@parentid order by id desc      
return isnull(@relativescore,0)      
end 
GO

