GO

CREATE   FUNCTION [dbo].[fn_getroles](@eventid int,@parentid bigint,@entity nvarchar(20))
returns nvarchar(200)
as
begin
declare @values nvarchar(200)
if @entity='mode' 
select @values= coalesce(@values+',','')+m.mode from 
(select distinct n.modeid,m.mode from
adminnotificationsettings(nolock) a join notificationsmaster n on a.notificationid=n.id
join notificationmodes m on m.id=n.modeid where a.parentid=@parentid and ans_eventid=@eventid
) m
if @entity='role'
select @values= coalesce(@values+',','')+m.rolename from 
(select distinct a.roleid,m.rolename from
adminnotificationsettings(nolock) a join notificationsmaster n on a.notificationid=n.id
join systemroles m on m.id=n.roleid where a.parentid=@parentid and ans_eventid=@eventid
) m
return @values
end
GO

