/****** Object:  UserDefinedFunction [dbo].[fn_GetSignOutStatus]    Script Date: 06-06-26 10:45:52 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[fn_GetSignOutStatus]
(
	@UserId bigint
)
RETURNS bit
AS
BEGIN
	DECLARE @IsSignOutStatus bit  
	if Exists(Select top 1 AttendanceId from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(GetDate() as Date) and IsActive = 1 order by AttendanceId desc)
	Begin
		Select top 1 @IsSignOutStatus = (case when isnull(AttendanceOut, '') = '' then 0 else 1 end)
		from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(GetDate() as Date) and IsActive = 1
		order by AttendanceId desc
	End
	else
	Begin
		set @IsSignOutStatus = 0
	End
	RETURN @IsSignOutStatus
END

GO

