/****** Object:  UserDefinedFunction [dbo].[fn_getTicketentityfullname]    Script Date: 06-06-26 10:45:54 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_getTicketentityfullname]  
(@tpuserid bigint)  
returns nvarchar(100)  
as  
begin  
declare @fullname nvarchar(100) ,@entity nvarchar(20) , @entityid bigint
select @entityid= case when User_Id is not null then User_Id else EntityId End ,@entity= case when User_Id is not null then 'User' else EntityName End  from tbl_tp_UserLogin(nolock) where TpUser_Id=@tpuserid
select @fullname =   
coalesce(  
(select isnull(personname,'') from userleads(nolock) where id=@entityid and @entity='lead'),
(select isnull(personname,'') from userenquiry(nolock) where enquiryid=@entityid and @entity='enquiry'),
(select isnull(personname,'') from conversationcontacts(nolock) where id=@entityid and @entity='conversationcontact'),
(select isnull(fname,'')+' '+isnull(lname,'') from user_detail(nolock) where user_id=@entityid and @entity='user'),
(select isnull(agentname,'') from calling_agents(nolock) where id=@entityid and @entity='agent'),
'')  
return @fullname  
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_gettotalengagement]    Script Date: 06-06-26 10:45:54 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_gettotalengagement](@user_id bigint,@type varchar(1),@fromdate date,@todate date,@mode varchar(20)) 
returns bigint 
as 
begin 
declare @timespent bigint 
if exists(select 1 from tbl_user_engagement_track_details (nolock) t where cast(t.createddate as date) between @fromdate and @todate and UserEngMasterId in (select EngagementID from tbl_user_engagement_track_master(nolock) where userid=@user_id ))
begin
select @timespent=sum(spendtime) from tbl_user_engagement_track_details (nolock) t 
join tbl_user_engagement_track_master (nolock) s on t.UserEngMasterId=s.EngagementID  WHERE cast(t.createddate as date) between @fromdate and @todate and  isnull(ImpersonatorID,0)=0 and mode=case when @mode='both' then mode else @mode end and 1=case when 
@type='I' and s.userid=@user_id then 1 when @type='P' and dbo.ufn_getuserparentid(s.userid)=dbo.ufn_getuserparentid(@user_id) then 1 else 0 end 
end
return isnull(@timespent,0) 
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_GetUniqueAgentName]    Script Date: 06-06-26 10:45:54 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_GetUniqueAgentName]
(
    @ParentId  BIGINT,
    @Name      NVARCHAR(200),
    @ExcludeId BIGINT = NULL
)
RETURNS NVARCHAR(200)
AS
BEGIN
  
  --DECLARE @ParentId    BIGINT = 34594,
  --  @Name              NVARCHAR(200) = 'Kit19Bot',
  --  @ExcludeId         BIGINT = NULL
  
  
  DECLARE @NextSuffix  INT
  DECLARE @SuffixStart INT = Len(@Name) + 3 -- start position of N inside "Name (N)"
  ;
  WITH takensuffixes AS
  (
         SELECT
                CASE
                       WHEN NAME = @Name THEN 1
                              -- NULLIF prevents negative length from reaching SUBSTRING
                       ELSE try_cast( Substring( NAME, @SuffixStart,
                              -- NULLIF(x, 0) → NULL when length ≤ 0, TRY_CAST then returns NULL safely
                              NULLIF(Len(NAME) - @SuffixStart, 0) ) as int)
                END as n
         FROM   tbl_ai_agents
         WHERE  isdeleted = 0
         AND    (
                       @ExcludeId IS NULL
                OR     agentid <> @ExcludeId)
         AND    ( (
                              @ParentId IS NULL
                       AND    parentid IS NULL)
                OR     parentid = @ParentId )
         AND    (
                       NAME = @Name
                OR     (
                              NAME LIKE @Name + ' ([0-9]%)'
                              -- Ensures suffix length is at least 1 char between "(" and ")"
                       AND    len(NAME) > @SuffixStart
                       AND    RIGHT(NAME, 1) = ')' ) ) )
  SELECT @NextSuffix = min(gap.n)
  FROM   (
                SELECT n + 1 AS n
                FROM   takensuffixes
                WHERE  n IS NOT NULL
                UNION ALL
                SELECT 1 ) gap
  WHERE  gap.n NOT IN
         (
                SELECT n
                FROM   takensuffixes
                WHERE  n IS NOT NULL)
  --SELECT CASE
  --              WHEN @NextSuffix IS NULL
  --              OR     @NextSuffix = 1 THEN @Name
  --              ELSE @Name + ' (' + cast(@NextSuffix AS nvarchar(10)) + ')'
  --       END AS uniqueagentname
  RETURN CASE
                WHEN @NextSuffix IS NULL
                OR     @NextSuffix = 1 THEN @Name
                ELSE @Name + ' (' + cast(@NextSuffix AS nvarchar(10)) + ')'
         END 
 
END

GO

