/****** Object:  UserDefinedFunction [dbo].[fn_GetUseridFromRole]    Script Date: 06-06-26 10:45:55 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--select * from systemroles     
--select * from ActivityMaster where context='enquiry'     
   --select dbo.[fn_GetUseridFromRole]('lead',30678709,'Collaborator')  
CREATE   FUNCTION [dbo].[fn_GetUseridFromRole](@entity nvarchar(100),@activityid bigint,@role nvarchar(100))     
returns nvarchar(max)     
as     
begin     
declare @userids nvarchar(max),@user bigint,@parentid bigint,@eventid int,@eventgroup nvarchar(100),@entityid bigint,     
@reftables nvarchar(max),@refids nvarchar(max),@seektable nvarchar(100),@context nvarchar(100)     
if @entity='lead'     
begin     
select @user=userid,@parentid=ParentID,@eventid=eventid,@entityid=LeadID,@reftables=reftables,@refids=refids,@seektable='tbl_LeadEventHistory'     
from tbl_LeadEventHistory(nolock) where historyid=@activityid     
end     
if @entity='enquiry'     
begin     
select @user=userid,@parentid=ParentID,@eventid=eventid,@entityid=EnquiryID,@reftables=reftables,@refids=refids,@seektable='tbl_enquiryEventHistory' from tbl_enquiryEventHistory(nolock) where historyid=@activityid     
end     
if @entity='user'     
begin     
select @user=userid,@parentid=ParentID,@eventid=eventid,@entityid=userid,@reftables=reftables,@refids=refids,@seektable='tbl_userEventHistory' from tbl_userEventHistory(nolock) where historyid=@activityid     
end     
     
select @eventgroup = eventtype,@context=context from activitymaster(nolock) where id=@eventid     
     
if @eventgroup is null     
begin     
select @role=''     
end     
     
if @role='Siteowner'     
begin     
select @userids=335     
end     
else if @role='Partner'     
begin     
select @userids=0     
end     
else if @role='SuperAdmin'     
begin     
select @userids=@parentid     
end     
else if @role='Admin'     
begin     
select @userids=coalesce(@userids+',','')+cast(user_id as nvarchar) from user_detail(nolock) where parentid=@parentid and IsAdmin=1     
end     
else if @role='Manager'     
begin     
if @eventgroup='TimeTracking'     
begin     
--select distinct manageruser_id into #mgr from mysmstimetrack.[dbo].[timetracking_roleusermapping](nolock) m     
select @userids=coalesce(@userids+',','')+cast(manageruser_id as nvarchar) from     
mysmstimetrack.[dbo].[timetracking_roleusermapping] m with (nolock)     
join user_detail(nolock) u on u.user_id=manageruser_id and u.status=1 and m.user_id=@user     
end     
else     
begin     
select @userids=0     
end     
end     
else if @role='Owner'     
begin     
if @context<>'lead'     
begin     
select @userids=@user     
end     
else if @eventgroup in ('Task','appointment') and @context='lead'     
begin     
if @reftables='tbl_tsk_TaskComments'
begin
select @userids=AssignedTo from tbl_tsk_TaskHistory(nolock) where id=  
(select task_history_id from tbl_tsk_TaskComments(nolock) where id=@refids  )   
end
else
begin
select @userids=AssignedTo from tbl_tsk_TaskHistory(nolock) where id=@refids  
end
end     
else if @eventgroup in ('lifecycle','chat') and @context='lead'     
begin     
if @reftables='leadinteractionhistory'     
begin     
select @userids=assignedto from leadinteractionhistory(nolock) where id=@refids     
end     
else     
begin     
select @userids=assignedto from userleads(nolock) where id=@entityid     
end     
end     
else if @eventgroup='deal' and @context='lead'     
begin     
select @userids=DealOwner from LeadPipelineMapping(nolock) where id=@refids     
end     
else if @eventgroup='support' and @context='lead'     
begin     
select @userids=     
(select user_id_old from serv_user_detail (nolock) where ser_user_id =     
(select t.assignto from serv_ticketmaster t(nolock)     
left join Serv_TicketHistory h (nolock) on t.ticketid=h.TicketID     
left join Serv_ticket_feedback_tbl(nolock) f on f.TICKETID=t.ticketid     
where     
(h.tickethistoryid is null or     
cast(h.tickethistoryid as nvarchar)=     
case when @reftables='serv_ticketmaster'     
then (select max(tickethistoryid) from serv_tickethistory where ticketid=h.ticketid)     
when @reftables='Serv_ticket_feedback_tbl' then cast(f.TicketHistoryID as nvarchar)     
when @reftables='Serv_TicketHistory' then @refids end)     
and     
cast(f.id as nvarchar)=case when @reftables='Serv_ticket_feedback_tbl' then @refids else null end     
and cast(t.TicketID as nvarchar)=case when @reftables='serv_ticketmaster'     
then @refids else cast(t.TicketID as nvarchar) end     
))     
     
end     
else if @context='lead'     
begin     
select @userids=assignedto from userleads(nolock) where id=@entityid     
end     
else if @context='enquiry'     
begin     
select @userids=createdby from userenquiry(nolock) where enquiryid=@entityid     
end     
end     
else if @role='Creator'     
begin     
if @eventgroup in ('Task','appointment') and @context='lead'     
begin 
if @reftables='tbl_tsk_TaskComments'
begin
select @userids=Created_By from tbl_tsk_TaskComments(nolock) where id=@refids     
end
else
begin
select @userids=CreatedBy from tbl_tsk_TaskHistory(nolock) where id=@refids
end
end     
else if @eventgroup='lifecycle' and @context='lead'     
begin     
if @reftables='leadinteractionhistory'     
begin     
select @userids=CreatedBy from leadinteractionhistory(nolock) where id=@refids     
end     
else     
begin     
select @userids=CreatedBy from userleads(nolock) where id=@entityid     
end     
end     
else if @eventgroup='deal' and @context='lead'     
begin     
select @userids=CreatedBy from LeadPipelineMapping(nolock) where id=@refids     
end     
else if @eventgroup='support' and @context='lead'     
begin     
select @userids=     
(select user_id_old from serv_user_detail (nolock) where ser_user_id =     
(select h.raisedby from serv_ticketmaster t(nolock)     
left join Serv_TicketHistory h (nolock) on t.ticketid=h.TicketID     
left join Serv_ticket_feedback_tbl(nolock) f on f.TICKETID=t.ticketid     
where     
(h.tickethistoryid is null or     
cast(h.tickethistoryid as nvarchar)=     
case when @reftables='serv_ticketmaster'     
then (select max(tickethistoryid) from serv_tickethistory where ticketid=h.ticketid)     
when @reftables='Serv_ticket_feedback_tbl' then cast(f.TicketHistoryID as nvarchar)     
when @reftables='Serv_TicketHistory' then @refids end)     
and     
cast(f.id as nvarchar)=case when @reftables='Serv_ticket_feedback_tbl' then @refids else null end     
and cast(t.TicketID as nvarchar)=case when @reftables='serv_ticketmaster'     
then @refids else cast(t.TicketID as nvarchar) end     
))     
end     
else     
begin     
select @userids=@user     
end     
end     
else if @role='Collaborator'     
begin     
if @eventgroup in ('Task','appointment') and @context='lead'     
begin 
if @reftables='tbl_tsk_TaskComments'
begin
select @userids=coalesce(@userids +',','')+ cast(user_id as nvarchar) from tbl_tsk_CollaborationUserMapping (nolock)     
c join tbl_tsk_TaskHistory(nolock) t on t.id=c.TaskHistoryId     
where t.id=(select task_history_id from tbl_tsk_TaskComments(nolock) where id=@refids  )   
end
else
begin
select @userids=coalesce(@userids +',','')+ cast(user_id as nvarchar) from tbl_tsk_CollaborationUserMapping (nolock)     
c join tbl_tsk_TaskHistory(nolock) t on t.id=c.TaskHistoryId     
where t.id=@refids     
end
end     
else if @eventgroup in ('lifecycle','chat') and @context='lead'     
begin     
if @reftables='leadinteractionhistory'     
begin     
select @userids=assignedto from leadinteractionhistory(nolock) where id=@refids     
end     
else     
begin     
select @userids=assignedto from userleads(nolock) where id=@entityid     
end     
end     
else if @eventgroup='deal' and @context='lead'     
begin     
select @userids=DealOwner from LeadPipelineMapping(nolock) where id=@refids     
end     
else if @eventgroup='support' and @context='lead'     
begin     
select @userids=coalesce(@userids+',','')+cast(user_id_old as nvarchar)     
FROM [MySMS].[dbo].[Serv_Agent_Mast] where group_id=     
(select top 1 t.Assign_Group from serv_ticketmaster t(nolock)     
left join Serv_TicketHistory h (nolock) on t.ticketid=h.TicketID     
where     
1= case when @reftables='serv_ticketmaster'     
and h.tickethistoryid=(select max(tickethistoryid) from serv_tickethistory(nolock) where cast(t.TicketID as nvarchar)=@refids) then 1     
when @reftables='serv_ticketmaster' and cast(t.TicketID as nvarchar)=@refids and h.tickethistoryid is null then 1     
when @reftables='Serv_TicketHistory' and cast(h.tickethistoryid as nvarchar)= @refids then 1     
when @reftables='serv_ticketmaster'and cast(t.TicketID as nvarchar)= @refids then 1 else 0 end     
--(h.tickethistoryid is null or     
--cast(h.tickethistoryid as nvarchar)=     
--case when @reftables='serv_ticketmaster'     
--then (select max(tickethistoryid) from serv_tickethistory where ticketid=h.ticketid)     
--when @reftables='Serv_TicketHistory' then @refids end)     
--and cast(t.TicketID as nvarchar)=case when @reftables='serv_ticketmaster'     
--then @refids else cast(t.TicketID as nvarchar) end     
)     
end     
else     
begin     
select @userids=@user     
end     
end     
else     
begin     
select @userids=0     
end     
     
return isnull(@userids,0)     
end     
     
     
     
--select top 10 * from tbl_tsk_CollaborationUserMapping     
--select * from tbl_LeadEventHistory(nolock) where eventid=53 reftables='LeadPipelineMapping'     
     
--569428 
GO

