/****** Object:  UserDefinedFunction [dbo].[fn_GetUserTimeFromIST]    Script Date: 06-06-26 10:45:57 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_GetUserTimeFromIST]
(
    @indiandatetime DATETIME,
    @timezone NVARCHAR(200)  -- target timezone
)
RETURNS DATETIME
AS
BEGIN
    DECLARE @userlocaldatetime DATETIME;

    -- Convert IST datetime to target timezone
    SET @userlocaldatetime = CAST(
        (@indiandatetime AT TIME ZONE 'India Standard Time')
        AT TIME ZONE @timezone
        AS DATETIME
    );

    RETURN @userlocaldatetime;
END

GO

