/****** Object:  UserDefinedFunction [dbo].[fn_GetVoiceCreditCalculationScalar]    Script Date: 06-06-26 10:45:58 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_GetVoiceCreditCalculationScalar](
	@AccTypeValue nvarchar(20),
	@userID bigint,
	@duration int,
	@mcount int
)
RETURNS numeric(18,4)     
as     
begin     
                             
declare 
	@intdur as bigint,
	@fracdur as bigint,
	@Pulse_Rate as bigint,
	@price numeric(18,4),
	@cr_amt numeric(18,4),
	@Actualbalance numeric(18,4),
	@credits numeric(18,4)     
    
	   declare @PID bigint = (select top 1 isnull(ParentID,USER_ID) from User_Detail with(nolock) where User_ID = @userID  )   

select top 1 @Actualbalance = Balance from dbo.IntCredit_Details with(nolock) where USER_ID = @PID order by Credit_ID desc                                                   
 
if exists(                          
select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns                          
            when @AccTypeValue = 'MTIX_PRO'  or @AccTypeValue ='promo'  then LocalRPromo                          
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                          
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                         
      from Price_Base_Voice_Rate_Exception with(nolock) where OriginCountryId=101 and USERID=@PID and destinationCountryid=101)  
begin                          
set @price=                          
(                          
select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns                          
            when @AccTypeValue = 'MTIX_PRO'  or @AccTypeValue ='promo'  then LocalRPromo                          
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                          
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                         
      from Price_Base_Voice_Rate_Exception where OriginCountryId=101 and USERID=@userID and destinationCountryid=101  )
end                   
else 
begin
set @price=                          
(select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns              
            when @AccTypeValue = 'MTIX_PRO' or @AccTypeValue ='promo'   then LocalRPromo                          
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                          
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                           
         from Price_Base_Voice_Rate with(nolock)  where OriginCountryId=101 and destinationCountryid=101                            
)
end                          
 set @Pulse_Rate=30                          
                          
select @intdur =Convert(int,@duration/@Pulse_Rate),                          
 @fracdur= @duration%@Pulse_Rate                           
                          
if @fracdur >0                          
 set @intdur = @intdur+1                            
                          
set @Cr_amt=@price * @mCount * @intdur      
    
    
--select @credits=case when @Actualbalance >= @Cr_amt then @Cr_amt else 0 end    
select @credits=@cr_amt
    
return @credits                     
    
end    
                           
    
    
--select dbo.fn_GetVoiceCreditCalculationscalar('MTIX_TR',38406,180,5548)

GO

/****** Object:  UserDefinedFunction [dbo].[fn_GetVoiceCreditCalculationScalar_global]    Script Date: 06-06-26 10:45:58 ******/
