CREATE   FUNCTION [dbo].[fn_GetVoiceCreditCalculationScalar_global]        
(@AccTypeValue nvarchar(20),@userID bigint,@duration int,@mcount int,@countrycode nvarchar(5))        
RETURNS numeric(18,4)         
as         
begin         
                            
declare @intdur as bigint                              
, @fracdur as bigint                              
,@Pulse_Rate as bigint        
,@price numeric(18,4)         
,@cr_amt numeric(18,4)           
,@Actualbalance numeric(18,4)        
,@credits numeric(18,4),@destcountryid int         
        
    declare @PID bigint = (select top 1 isnull(ParentID,USER_ID) from User_Detail with(nolock) where User_ID = @userID  )     
  select top 1 @destcountryid=case when @countrycode is null or  @countrycode in ('+91','91') then 101 
  else country_id end from m_country1(nolock) where ltrim(rtrim(replace(@countrycode,'+','')))=ltrim(rtrim(replace(countrycode,'+','')))
select top 1 @Actualbalance = Balance from dbo.IntCredit_Details with(nolock) where USER_ID = @PID order by Credit_ID desc                                                     
     
if exists(                              
select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns                              
            when @AccTypeValue = 'MTIX_PRO'  or @AccTypeValue ='promo'  then LocalRPromo                              
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                              
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                             
      from Price_Base_Voice_Rate_Exception with(nolock) where OriginCountryId=101 and USERID=@PID and destinationCountryid=@destcountryid)    
begin                              
set @price=                              
(                              
select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns                              
            when @AccTypeValue = 'MTIX_PRO'  or @AccTypeValue ='promo'  then LocalRPromo                              
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                              
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                             
      from Price_Base_Voice_Rate_Exception with(nolock) where OriginCountryId=101 and USERID=@PID and destinationCountryid=@destcountryid  )    
end                       
else     
begin    
set @price=                              
(select case when @AccTypeValue = 'MTIX_TR' or @AccTypeValue = 'trans' then LocalRTrns                  
            when @AccTypeValue = 'MTIX_PRO' or @AccTypeValue ='promo'   then LocalRPromo                              
   when @AccTypeValue = 'MTIX_TRC' or @AccTypeValue ='promo'  then LocalRTrnsScurb                              
   when @AccTypeValue = 'CRITICAL' then LocalRCritical end as pprice                               
         from Price_Base_Voice_Rate with(nolock)  where OriginCountryId=101 and destinationCountryid=101                              
)    
end                              
 set @Pulse_Rate=30                              
                              
select @intdur =Convert(int,@duration/@Pulse_Rate),                              
 @fracdur= @duration%@Pulse_Rate                               
                              
if @fracdur >0                              
 set @intdur = @intdur+1                                
                              
set @Cr_amt=@price * @mCount * @intdur          
        
        
--select @credits=case when @Actualbalance >= @Cr_amt then @Cr_amt else 0 end        
select @credits=@cr_amt    
        
return @credits                         
        
end        
                               
        
        
