/****** Object:  UserDefinedFunction [dbo].[fn_GiveVirtualCredits]    Script Date: 06-06-26 10:45:58 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

      
CREATE   FUNCTION [dbo].[fn_GiveVirtualCredits](@userid bigint)      
returns int      
as      
begin      
declare @return int      
    
  Declare @ParentID bigint = 0    
  Select top 1 @ParentID = isnull(ParentID,0) from User_Detail with(nolock) Where User_ID = @userid    
    
if exists(select cd.balance from user_detail c (nolock)      
cross apply (select top 1 user_id,debits,credits,balance,datecreated from credit_details cd1 (nolock) where cd1.User_ID=c.user_id and fromuser_id=cd1.user_id order by Credit_ID desc) as cd      
where ParentSuperResellerId=@ParentID and cd.Balance>0)      
select @return= 0      
else       
select @return=1      
return isnull(@return,0)      
end      
      
