/****** Object:  UserDefinedFunction [dbo].[fn_IsUnicode]    Script Date: 06-06-26 10:46:02 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_IsUnicode](
         @Msg nvarchar(max)
	 )         
    RETURNS bit  
    BEGIN 
    DECLARE @IsUnicode bit =  0
	    
		IF PATINDEX('%[' + NCHAR(0x80) + '-' + NCHAR(0xFFFF) + ']%', @Msg COLLATE Latin1_General_BIN) > 0
		    begin
			   set  @IsUnicode = 1
			end
          else
		    begin
			  set  @IsUnicode = 0 
			end

    RETURN @IsUnicode; 
  END 
GO

/****** Object:  UserDefinedFunction [dbo].[fn_IsUnicode_1]    Script Date: 06-06-26 10:46:02 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_IsUnicode_1](@Msg NVARCHAR(MAX))
RETURNS BIT
AS
BEGIN
    DECLARE @IsUnicode BIT = 0;

    -- Use a temp table to hold characters with their Unicode values
    IF EXISTS (
        SELECT 1
        FROM (
            SELECT UNICODE(SUBSTRING(@Msg, number, 1)) AS codepoint
            FROM master..spt_values
            WHERE type = 'P'
              AND number BETWEEN 1 AND LEN(@Msg)
        ) AS CharCodes
        WHERE codepoint > 127
    )
    BEGIN
        SET @IsUnicode = 1;
    END

    RETURN @IsUnicode;
END

GO

