/****** Object:  UserDefinedFunction [dbo].[fn_MonthsRemaining]    Script Date: 06-06-26 10:46:05 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_MonthsRemaining]
(
    @ActualEndDate DATE
)
RETURNS INT
AS
BEGIN
 
   DECLARE @CurrentDate DATE = GETDATE();
    DECLARE @RemainingMonths FLOAT = 0;
    DECLARE @TempDate DATE = @ActualEndDate;
    DECLARE @YearDiff INT;
    DECLARE @MonthDiff INT;

    -- While the TempDate is greater than or equal to the current date
    WHILE @TempDate >= @CurrentDate
    BEGIN
        -- Decrease the date by one month
        SET @TempDate = DATEADD(MONTH, -1, @TempDate);

        -- Increase the month counter by 1 for every full month
        SET @RemainingMonths = @RemainingMonths + 1;
    END;

    -- Check if there are remaining days in the current month
    -- Calculate the remaining days in the current month
    DECLARE @RemainingDaysInMonth INT = DAY(EOMONTH(@CurrentDate)) - DAY(@CurrentDate);
    DECLARE @DaysInTargetMonth INT = DAY(EOMONTH(@ActualEndDate));

    -- If we're within the current month, calculate fractional months
    IF @RemainingDaysInMonth > 0
    BEGIN
        SET @RemainingMonths = @RemainingMonths + CAST(@RemainingDaysInMonth AS FLOAT) / CAST(@DaysInTargetMonth AS FLOAT);
    END;

    RETURN @RemainingMonths;
END;
GO

