/****** Object:  UserDefinedFunction [dbo].[fn_OnlyDigits]    Script Date: 06-06-26 10:46:06 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_OnlyDigits](@s NVARCHAR(100))
RETURNS NVARCHAR(100)
AS
BEGIN
    DECLARE @i INT = 1, @len INT = LEN(@s), @out NVARCHAR(100) = '', @c NCHAR(1)
    WHILE @i <= @len
    BEGIN
        SET @c = SUBSTRING(@s, @i, 1)
        IF @c >= '0' AND @c <= '9'
            SET @out += @c
        SET @i += 1
    END
    RETURN @out
END

GO

