/****** Object:  UserDefinedFunction [dbo].[fn_probableoption]    Script Date: 06-06-26 10:46:08 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_probableoption](@a int=null,@b int=null)
returns int
as
begin
declare @probableoption int
select @probableoption =  case 
							  when @a is null and @b is null then null 
                              when @a is null then @b 
							  when @b is null then @a 
							  when @a=0 then @a 
							  when @b=0 then @b 
							  when @a<@b and @a<0 and @b<0 then @b 
							  when @a<@b and @a<0 and @b>0 then @a 
							  when @a>@b and @a<0 and @b<0 then @a 
							  else @b end
return @probableoption
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_recursivereplace]    Script Date: 06-06-26 10:46:08 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_recursivereplace]
(@tbl recursivereplace readonly, @string nvarchar(max))
returns nvarchar(max)
as
begin
	
	;WITH TranslationTable    
	AS (    
		SELECT 
			FindValue = '#' + displaykey + '#',
			ReplaceValue = [value],
			ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn    
		FROM @tbl where displaykey is not null    
	)    
	--Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue    
	,RecursiveCte as ( 
		SELECT cast(@string as nvarchar(max)) AS StrValue, 
		(    
			SELECT count(*)    
			FROM TranslationTable    
		) AS cnt    
	UNION ALL    
	SELECT cast(replace(isnull(StrValue, ''), tt.FindValue, isnull(tt.Replacevalue, '')) as nvarchar(max))    
		,cnt - 1 
	FROM RecursiveCte JOIN TranslationTable tt ON tt.rn = cnt )
	
	SELECT top 1 @string=StrValue  FROM RecursiveCte where cnt = 0 option (maxrecursion 0)

	return @string

end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_recursivereplace_withoutpound]    Script Date: 06-06-26 10:46:08 ******/
