CREATE   FUNCTION [dbo].[fn_recursivereplace_withoutpound]
(@tbl recursivereplace readonly, @string nvarchar(max))
returns nvarchar(max)
as
begin
	
	;WITH TranslationTable    
	AS (    
		SELECT 
			FindValue = displaykey,
			ReplaceValue = [value],
			ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn    
		FROM @tbl where displaykey is not null    
	)    
	--Recursive CTE to loop through the TranslationTable and replace FindValue with ReplaceValue    
	,RecursiveCte as ( 
		SELECT cast(@string as nvarchar(max)) AS StrValue, 
		(    
			SELECT count(*)    
			FROM TranslationTable    
		) AS cnt    
	UNION ALL    
	SELECT cast(replace(isnull(StrValue, ''), tt.FindValue, isnull(tt.Replacevalue, '')) as nvarchar(max))    
		,cnt - 1 
	FROM RecursiveCte JOIN TranslationTable tt ON tt.rn = cnt )
	
	SELECT top 1 @string=StrValue  FROM RecursiveCte where cnt = 0 option (maxrecursion 0)

	return @string

end
GO

