/****** Object:  UserDefinedFunction [dbo].[fn_RemoveHashPlaceholders]    Script Date: 06-06-26 10:46:09 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_RemoveHashPlaceholders]
(
    @Input NVARCHAR(MAX)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @Result NVARCHAR(MAX) = @Input;
    DECLARE @Start INT;
    DECLARE @End INT;

    -- Loop until no #...# pattern exists
    WHILE CHARINDEX('#', @Result) > 0
    BEGIN
        SET @Start = CHARINDEX('#', @Result);
        SET @End   = CHARINDEX('#', @Result, @Start + 1);

        -- Break if unmatched #
        IF @End = 0
            BREAK;

        -- Replace #value# with null (JSON safe)
        SET @Result = STUFF(
                          @Result,
                          @Start,
                          @End - @Start + 1,
                          'null'
                      );
    END

    RETURN @Result;
END;

GO

