SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_removewww]  
(@domain nvarchar(255))  
returns nvarchar(255)  
as  
begin  
if left(@domain,7)='http://' or left(@domain,8)='https://'
select @domain=replace(replace(@domain,'https://',''),'http://','')

if left(@domain,4)='www.'  
select @domain=right(@domain,len(@domain)-4)  
  
return @domain  
end
