CREATE   FUNCTION [dbo].[fn_replaceattributes](@content nvarchar(max),@user_id bigint)
returns nvarchar(max)
as
begin
--select * into #ReplaceTable from replaceableAttributes where tablename='#AlertsData'
declare @replacements int=(select COUNT(1) from replaceableAttributes where tablename='#AlertsData')
declare @ovalue nvarchar(100),@fvalue nvarchar(100),@fcvalue nvarchar(100)
declare @id int=0,@q1 nvarchar(max)
while @replacements >0
begin
set @id=(select min(ID) from replaceableAttributes where tablename='#AlertsData' and id>@id)
select @ovalue=ValueToBeReplaced,@fvalue=ColumnName from replaceableAttributes where ID=@id
set @q1='select @fcvalue=isnull(' +@fvalue + ','''') from Alertsdata where user_id=@user_id'
execute sp_executesql @q1,N'@fcvalue nvarchar(max) OUTPUT', 
    @fcvalue = @fcvalue output;
set @content = replace(@content,@ovalue,@fcvalue)
set @replacements=@replacements-1
end
--select @content
return @content
end
GO

