--select * from systemroles 
--select * from ActivityMaster where context='enquiry' 
 
CREATE   FUNCTION [dbo].[fn_requiredworkingtime] 
(@user_id bigint,@workdate date) 
returns bigint 
as 
begin 
declare @worktime bigint 
--select @workdate=coalesce(@workdate,getdate()) 
declare @day nvarchar(10)=datename(weekday,@workdate),@starttime nvarchar(10),@endtime nvarchar(10) 
--declare @j nvarchar(max)='[{"Day":"Monday","From":"09:00","To":"18:00","Status":"Opened"},{"Day":"Tuesday","From":"09:00","To":"18:00","Status":"Opened"},{"Day":"Wednesday","From":"09:00","To":"18:00","Status":"Opened"}, 
--{"Day":"Thursday","From":"09:00","To":"18:00","Status":"Opened"},{"Day":"Friday","From":"09:00","To":"18:00","Status":"Opened"},{"Day":"Saturday","From":"02:00","To":"18:00","Status--":"Opened"},{"Day":"Sunday","From":"09:00","To":"18:00","Status":"Closed
--"}]' 
select @starttime=substring(value,charindex('from":"',value,1)+7,5) from openjson((select workinghours from mysmstimetrack.dbo.timetracking_settings 
t with (nolock) 
 where user_id=@user_id)) 
where value like '%'+@day+'%' and value like '%opened%' 
select @endtime=substring(value,charindex('to":"',value,1)+5,5) from openjson((select workinghours from mysmstimetrack.dbo.timetracking_settings 
t with (nolock) 
where user_id=@user_id)) 
where value like '%'+@day+'%' and value like '%opened%' 
--select isnull(@starttime,'0'),isnull(@endtime,'0') 
select @worktime=case when datediff(ss,cast(@starttime as time),cast(@endtime as time))>0 then datediff(ss,cast(@starttime as time),cast(@endtime as time)) else 0 end 
return @worktime 
end 

