GO

CREATE   FUNCTION [dbo].[fn_serviceusedlast]  
(@parentid bigint,@servicename nvarchar(50))  
returns nvarchar(100)  
as  
begin  
declare @lastused nvarchar(100)  
if @servicename='SMS'  
begin  
select top 1 @lastused=fromdate from credit_details(nolock) where fromuser_id=user_id and debits>0 order by credit_id desc  
if @lastused is null  
set @lastused ='More than 1 year ago'  
end  
else if @servicename='Mail'  
begin  
select top 1 @lastused=fromdate from mailcreditdetails(nolock) where fromuser_id=user_id and debits>0 order by credit_id desc  
if @lastused is null  
set @lastused ='Never'  
end  
else
begin
declare @cid int=(select credittypeid from price_master_typecredit(nolock) where creditname=@servicename)
select top 1 @lastused=cast(fromdate as nvarchar) from intcredit_details(nolock) where fromuser_id=user_id and debits>0 and typecredit=@cid order by credit_id desc  
if @lastused is null  
set @lastused ='More than 1 year ago'  
end
if @lastused is null
set @lastused='Never'
return @lastused  
   
end
