/****** Object:  UserDefinedFunction [dbo].[fn_Strip_entityPlaceholders]    Script Date: 06-06-26 10:46:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[fn_Strip_entityPlaceholders](@input NVARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    /*
      Removes all occurrences of "#lead.<anything>#" except those where
      <anything> begins with '{' and ends with '}' (e.g. "#lead.{keep}#").
    */

    DECLARE @s NVARCHAR(MAX) = @input;
    DECLARE @start INT = 1;
    DECLARE @pos INT;
    DECLARE @endPos INT;
    DECLARE @inner NVARCHAR(MAX);

    -- search loop
    WHILE 1 = 1
    BEGIN
        -- find next occurrence of '#lead.' starting from @start
        SET @pos = CHARINDEX('#lead.', @s, @start);

        IF @pos = 0 BREAK; -- none found

        -- find the next '#' after the found position
        SET @endPos = CHARINDEX('#', @s, @pos + LEN('#lead.'));

        -- if no closing '#' found, stop processing (leave the rest unchanged)
        IF @endPos = 0 BREAK;

        -- extract the inner part between "#lead." and the closing "#"
        SET @inner = SUBSTRING(@s, @pos + LEN('#lead.'), @endPos - (@pos + LEN('#lead.')));

        -- if inner is wrapped in braces '{...}' then skip (leave as-is)
        
        BEGIN
            -- remove the whole "#lead.<inner>#" segment
            SET @s = STUFF(@s, @pos, (@endPos - @pos + 1), '');

            -- after removal, continue searching from same position (in case adjacent patterns)
            SET @start = @pos;
        END
    END

    RETURN @s;
END

GO

/****** Object:  UserDefinedFunction [dbo].[fn_StripHTML]    Script Date: 06-06-26 10:46:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_StripHTML] (@HTML NVARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @Result NVARCHAR(MAX);

    -- Replace invalid XML characters (&, <, >) to make it XML-compatible
    SET @HTML = REPLACE(REPLACE(REPLACE(@HTML, '&', '&amp;'), '<', '&lt;'), '>', '&gt;');

    -- Convert to XML and extract the inner text

        SET @Result = CAST(
            (SELECT CAST('<x>' + @HTML + '</x>' AS XML).value('.', 'NVARCHAR(MAX)')) 
            AS NVARCHAR(MAX)
        );


        -- If there is an issue with invalid characters, return the original input
        SET @Result = @HTML;


    RETURN @Result;
END;

GO

