/****** Object:  UserDefinedFunction [dbo].[fn_TaskAppointmentStatus]    Script Date: 06-06-26 10:46:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--drop function fn_TaskAppointmentStatus
CREATE   FUNCTION [dbo].[fn_TaskAppointmentStatus] (
@SDate Date = null,
@EDate Date = null,
@IsTask bit = 0,
@User_ID bigint = 0,
@User_IDS bigint = 0,
@OutcomeName varchar(20) = '',
@Mode varchar(1) ='T'
)    
RETURNS VARCHAR(100)    
as begin
Declare @out varchar(100)
if(@Mode = 'A')
Begin
Select @out = Case 
When ((CAST (iif(@IsTask = 1, @EDate, @SDate) as date) > CAST(GETDATE() as date)) and (cast(@User_ID as nvarchar) = @User_IDS)) 
then 'My Appointments Today'
when ((CAST(iif(@IsTask = 1, @EDate, @SDate) as date) > CAST(GETDATE() as date)) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Appointments Today'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) = @User_IDS))
then 'My Overdue Appointments'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Overdue Appointments'
when (CAST(@SDate as date) > CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) = @User_IDS))
then 'My upcoming Appointments'
when (CAST(@SDate as date) > CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Upcoming Appointments'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (@OutcomeName != '')) then 'Appointments with '+ @OutcomeName +' outcome'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (@OutcomeName != '')) then 'Appointments with '+ @OutcomeName +' outcome today'
else 'Other Appointments' end
End
if(@Mode = 'T')
Begin
Select @out = Case 
When ((CAST (iif(@IsTask = 1, @EDate, @SDate) as date) > CAST(GETDATE() as date)) and (cast(@User_ID as nvarchar) = @User_IDS)) 
then 'My Tasks Today'
when ((CAST(iif(@IsTask = 1, @EDate, @SDate) as date) > CAST(GETDATE() as date)) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Tasks Today'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) = @User_IDS))
then 'My Overdue Tasks'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Overdue Tasks'
when (CAST(@SDate as date) > CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) = @User_IDS))
then 'My upcoming Tasks'
when (CAST(@SDate as date) > CAST(GETDATE() as date) and (cast(@User_ID as nvarchar) != @User_IDS))
then 'Upcoming Tasks'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (@OutcomeName != '')) then 'Tasks with '+ @OutcomeName +' outcome'
when (CAST(iif(@IsTask = 1, @EDate, @SDate) as date) < CAST(GETDATE() as date) and (@OutcomeName != '')) then 'Tasks with '+ @OutcomeName +' outcome today'
else 'Other Task' end
End
return @out;    

END

GO

