/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_AttendanceTotalSummary]    Script Date: 06-06-26 10:46:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_TBL_ET_AttendanceTotalSummary]
(@UserId bigint, @Date varchar(20), @CheckType varchar(30))
returns decimal(10,2)
as
begin
declare @totalCount decimal(10,2)
--set @Date = CONVERT(CHAR(10),CONVERT(DATETIME,LEFT(@Date,10),105),101);

if(@CheckType = 'TotalCount')
Begin
set @totalCount = isnull((select sum(DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)))/60 from TBL_ET_Attendance(nolock) atra where UserId = @UserId and (cast(AttendanceIn as Date) = cast(@Date as Date) or cast(AttendanceOut as Date) = cast(@Date as Date))), 0)
End
if(@CheckType = 'TotalHoursMonth')
Begin
set @totalCount = isnull((select sum(DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)))/60 from TBL_ET_Attendance(nolock) atra where UserId = @UserId and 
	(( DATEPART(MONTH, cast(AttendanceIn as Date)) = DATEPART(MONTH, cast(@Date as Date))
		AND DATEPART(YEAR, cast(AttendanceIn as Date)) = DATEPART(YEAR, cast(@Date as Date)))
	OR ( DATEPART(MONTH, cast(AttendanceOut as Date)) = DATEPART(MONTH, cast(@Date as Date))
		AND DATEPART(YEAR, cast(AttendanceOut as Date)) = DATEPART(YEAR, cast(@Date as Date)))
	)), 0)
End
else if(@CheckType = 'Totalminutes')
Begin
set @totalCount = isnull((select sum(DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))) 
from TBL_ET_Attendance(nolock) atra where atra.UserId = @UserId and ((Month(cast(AttendanceIn as Date)) = Month(cast(@Date as Date))
and Year(cast(AttendanceIn as Date)) = Year(cast(@Date as Date))) or (Month(cast(AttendanceOut as Date)) = Month(cast(@Date as Date))
and Year(cast(AttendanceOut as Date)) = Year(cast(@Date as Date))))),0)
End
else if(@CheckType = 'TotalWorkingDay')
Begin
set @totalCount = isnull((select Count(sDate) from (
select distinct case when cast(aa.AttendanceIn as Date) != '' then cast(aa.AttendanceIn as Date) else cast(aa.AttendanceOut as Date) end sDate
from TBL_ET_Attendance(nolock) aa 
where aa.UserId = @UserId and ((Month(cast(aa.AttendanceIn as Date)) = Month(cast(@Date as Date))
and Year(cast(aa.AttendanceIn as Date)) = Year(cast(@Date as Date))) or (Month(cast(aa.AttendanceOut as Date)) = Month(cast(@Date as Date))
and Year(cast(aa.AttendanceOut as Date)) = Year(cast(@Date as Date))))
)t), 0)
End
else if(@CheckType = 'TotalLeave')
Begin
set @totalCount = isnull((select sum(tt.dayLeave) from (
Select (case when cast(t.FromDate as date) = cast(t.ToDate as date) then (Leavecount * (QuarterRenge* .25)) 
when cast(t.FromDate as date) = cast(t.ToDate as date) and StartQuarterDate = 1 and EndQuarterDate = 4 then Leavecount 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount = 2 and StartQuarterDate = 1 and EndQuarterDate = 4 then Leavecount 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount = 2 and StartQuarterDate != 1 or EndQuarterDate != 4 then 
((4 - StartQuarterDate + 1) + (EndQuarterDate)) 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount > 2 and StartQuarterDate != 1 or EndQuarterDate != 4 then 
(Leavecount - 2) +((4 - StartQuarterDate + 1) + (EndQuarterDate)) 
else 0 End) dayLeave 
from ( 
Select tblr.FromDate, tblr.ToDate, StartQuarterDate, EndQuarterDate, FromTime, ToTime, 
(isnull(DATEDIFF(day, tblr.FromDate, tblr.ToDate),0) + 1) Leavecount, 
((EndQuarterDate - StartQuarterDate) +1) QuarterRenge 
from TBL_ET_LeaveApproval(nolock) tlap 
inner join TBL_ET_LeaveRequest(nolock) tblr on tlap.LeaveRequestId = tblr.LeaveRequestId 
where tblr.UserId = @UserId and ApproverStatus = 'Approved' and (Month(cast(tblr.FromDate as Date)) = Month(cast(@Date as Date)) 
and Year(cast(tblr.ToDate as Date)) = Year(cast(@Date as Date))) 
) t 
) tt), 0)
End
else if(@CheckType = 'WeekOff')
Begin
set @totalCount = isnull((select count(*) from (
select distinct sumpwo.WeekOffId from TBL_ET_ShiftUserMapping(nolock) sump 
inner join TBL_ET_ShiftUserMappWeekOff (nolock) sumpwo on sump.ShiftUserMappingId = sumpwo.ShiftUserMappingId and sumpwo.IsActive = 1
where sump.UserId = @UserId
and ((Month(cast(@Date as date)) = Month(cast(sump.FromDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(sump.FromDate as date)))) or 
(Month(cast(@Date as date)) = Month(cast(sump.ToDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(sump.ToDate as date))))))t),0)
End
else if(@CheckType = 'LateSignin')
Begin
set @totalCount = isnull((select count(AttendanceI) from (
Select distinct AttendanceI from(
Select cast(AttendanceIn as date) AttendanceI, IATime, StartTime, (case when IATime > StartTime then 1
else 0 end) LateLogin
from (Select atra.AttendanceId, atra.AttendanceIn, atra.AttendanceGroupId,
CAST(atra.AttendanceIn AS time) IATime,
 smat.StartTime
 from TBL_ET_TEMPMonthDate(nolock) tmde 
 left join TBL_ET_Attendance(nolock) atra on cast(tmde.MDate as date) = cast(atra.AttendanceIn as date) 
 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where (Month(cast(tmde.MDate as date)) = Month(cast(@Date as date)) and Year(cast(tmde.MDate as date)) = Year(cast(@Date as date))) and
 agum.UserId = @UserId 
)t
)t2
where LateLogin > 0
)t3 
),0)
End
else if(@CheckType = 'OutEarlyDays')
Begin
set @totalCount = isnull((select count(AttendanceO) from (
Select distinct AttendanceO from (
Select cast(AttendanceOut as date) AttendanceO, IATime, StartTime, (case when OATime < EndTime then 1
else 0 end) EarlyLogin
from (Select atra.AttendanceId, atra.AttendanceOut, atra.AttendanceGroupId,
CAST(atra.AttendanceIn AS time) IATime,
CAST(atra.AttendanceOut AS time) OATime,
 smat.StartTime,
 smat.EndTime
 from TBL_ET_TEMPMonthDate (nolock) tmde 
 left join TBL_ET_Attendance (nolock) atra on cast(tmde.MDate as date) = cast(atra.AttendanceOut as date) 
 inner join TBL_ET_AttendanceGroup (nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where (Month(cast(tmde.MDate as date)) = Month(cast(@Date as date)) and Year(cast(tmde.MDate as date)) = Year(cast(@Date as date))) and
 agum.UserId = @UserId
)t) t5 where EarlyLogin > 0 
) t4),0)
End
else if(@CheckType = 'TotalDays')
Begin
set @totalCount = DAY(EOMONTH(cast(@Date as date)))
End
else if(@CheckType = 'HalfDays')
Begin
set @totalCount = (select count(*) from ( 
select distinct ADate, ROW_NUMBER() OVER ( PARTITION BY ADate ORDER BY ADate, Attttime desc) row_num, Attttime, --(((case when max(Attttime) != '' then max(Attttime) else 0 End) * 100)/AtttSettingTime) akm, 
AttendanceMinPercentage, AttendanceMaxPercentage 
from( 
select (case when cast(AttendanceIn as date) != '' Then cast(AttendanceIn as date) 
else cast(AttendanceOut as date) End) ADate, Attttime, AtttSettingTime, 
AttendanceMinPercentage, AttendanceMaxPercentage, TypeOfStatus 
from( 
Select distinct atra.AttendanceIn, atra.AttendanceOut, 
CAST(atra.AttendanceIn AS time) IATime, CAST(atra.AttendanceOut AS time) OATime, 
DATEDIFF(MINUTE, atra.AttendanceIn, atra.AttendanceOut) Attttime, 
DATEDIFF(MINUTE, smat.StartTime, smat.EndTime) AtttSettingTime, 
atgas.AttendanceMinPercentage, atgas.AttendanceMaxPercentage, TypeOfStatus 
from TBL_ET_Attendance (nolock) atra 
 inner join TBL_ET_AttendanceGroup (nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 --left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_AttendanceGroupAttendanceSettings(nolock) atgas on atra.AttendanceGroupId = atgas.AttendanceGroupId 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId 
 where (Month(cast(atra.AttendanceIn as date)) = Month(cast(@Date as date)) and 
 Year(cast(atra.AttendanceIn as date)) = Year(cast(@Date as date))) 
 or (Month(cast(atra.AttendanceOut as date)) = Month(cast(@Date as date)) and 
 Year(cast(atra.AttendanceOut as date)) = Year(cast(@Date as date))) 
and agum.UserId = @UserId 
)tt 
)tt2 
where Attttime != '' and TypeOfStatus = 'HalfDay' 
group by ADate, Attttime, AttendanceMinPercentage, AttendanceMaxPercentage, TypeOfStatus 
)tt3 where row_num = 1 and Attttime between AttendanceMinPercentage and AttendanceMaxPercentage)
End
else if(@CheckType = 'NumberOfBreaks')
Begin
set @totalCount = isnull((select count(*) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((Month(cast(@Date as date)) = Month(cast(tebt.StartDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.StartDate as date)))) or 
(Month(cast(@Date as date)) = Month(cast(tebt.EndDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.EndDate as date)))))
)Tbt),0)
End
else if(@CheckType = 'TimeInBreaks')
Begin
set @totalCount = isnull((select sum(cast(DATEDIFF(minute, cast(Tbts.StartDate as datetime), cast(Tbts.EndDate as datetime)) as int)) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((Month(cast(@Date as date)) = Month(cast(tebt.StartDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.StartDate as date)))) or 
(Month(cast(@Date as date)) = Month(cast(tebt.EndDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.EndDate as date)))))
)Tbts),0)
End
else if(@CheckType = 'MaxBreakTimes')
Begin
set @totalCount = isnull((select max(cast(DATEDIFF(minute, cast(Tbts.StartDate as datetime), cast(Tbts.EndDate as datetime)) as int)) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((Month(cast(@Date as date)) = Month(cast(tebt.StartDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.StartDate as date)))) or 
(Month(cast(@Date as date)) = Month(cast(tebt.EndDate as date)) 
and (Year(cast(@Date as date)) = Year(cast(tebt.EndDate as date)))))
)Tbts),0)
End
else if(@CheckType = 'TotalTask')
Begin
set @totalCount = isnull((select sum(Total) from (
select count(*) Total from tbl_tsk_TaskHistory(nolock) ttth where ttth.AssignedTo = @UserId 
and ((Month(cast(ttth.StartDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(ttth.StartDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(ttth.EndDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(ttth.EndDate as date)) = Year(cast(@Date as date))))
union all
select count(*) Total from TBL_ET_PhysicalAppointment(nolock) tepa where tepa.AssignedTo = @UserId 
and ((Month(cast(tepa.StartDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(tepa.StartDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(tepa.EndDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(tepa.EndDate as date)) = Year(cast(@Date as date))))
)t), 0)
End
else if(@CheckType = 'TimeSpentInTasks')
Begin
set @totalCount = isnull((Select sum(DATEDIFF(minute, CheckIn, CheckOut)) from (
Select distinct GeoEntityCheckId, PhysicalAppointmentId, UserId, CheckIn, CheckOut from TBL_ET_GeoEntityCheckInOut(nolock) tege
where tege.UserId = @UserId 
and ((Month(cast(tege.CheckIn as date)) = Month(cast(@Date as date)) and 
 Year(cast(tege.CheckIn as date)) = Year(cast(@Date as date)))
or (Month(cast(tege.CheckOut as date)) = Month(cast(@Date as date)) and 
Year(cast(tege.CheckOut as date)) = Year(cast(@Date as date))))
)tt),0)
End
else if(@CheckType = 'SignIn')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_Attendance(nolock) where UserId = @UserId and ((Month(cast(AttendanceIn as Date)) = Month(cast(@Date as Date)) and Year(cast(AttendanceIn as Date)) = Year(cast(@Date as Date))))), 0)
End
else if(@CheckType = 'SignInRequest')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_AttendanceIssueRequest(nolock) where UserId = @UserId and ActionType='SignIn' and ((Month(cast(ActionDateTime as Date)) = Month(cast(@Date as Date)) and Year(cast(ActionDateTime as Date)) = Year(cast(@Date as Date))))), 0)
End
else if(@CheckType = 'SignOut')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_Attendance(nolock) where UserId = @UserId and ((Month(cast(AttendanceOut as Date)) = Month(cast(@Date as Date)) and Year(cast(AttendanceOut as Date)) = Year(cast(@Date as Date))))), 0)
End
else if(@CheckType = 'SignOutRequest')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_AttendanceIssueRequest(nolock) where UserId = @UserId and ActionType='SignOut' and ((Month(cast(ActionDateTime as Date)) = Month(cast(@Date as Date)) and Year(cast(ActionDateTime as Date)) = Year(cast(@Date as Date))))), 0)
End
else if(@CheckType = 'HolidayDays')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_HolidayBranch(nolock) tehb
inner join TBL_ET_HolidayMaster(nolock) tehm on tehb.HolidayId = tehm.HolidayId
inner join TBL_ET_AttendanceGroupBranchMapping (nolock) atbg on tehb.BranchId = atbg.BranchId
inner join TBL_ET_AttendanceGroupUserMapping (nolock) atum on atbg.AttendanceGroupId = atum.AttendanceGroupId
where atum.UserId = @UserId and ((Month(cast(tehm.HolidayDate as Date)) = Month(cast(@Date as Date)) and Year(cast(tehm.HolidayDate as Date)) = Year(cast(@Date as Date))))), 0)
End


return @totalCount
end

GO

/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_AttendanceTotalSummaryFT]    Script Date: 06-06-26 10:46:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_TBL_ET_AttendanceTotalSummaryFT]
(@UserId bigint, @FDate varchar(25), @TDate varchar(25), @CheckType varchar(30))
returns decimal(10,2)
as
begin
declare @totalCount decimal(10,2)
--set @FDate = CONVERT(CHAR(25),CONVERT(DATETIME,LEFT(@FDate,25),105),101);
--set @TDate = CONVERT(CHAR(25),CONVERT(DATETIME,LEFT(@TDate,25),105),101);

set @FDate = CONVERT(DATETIME, @FDate);
set @TDate = CONVERT(DATETIME, @TDate);

if(@CheckType = 'TotalCount')
Begin
set @totalCount = isnull((select sum(DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)))/60 from TBL_ET_Attendance(nolock) atra where UserId = @UserId and ((cast(AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0)
End
else if(@CheckType = 'Totalminutes')
Begin
set @totalCount = isnull((select sum(DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))) 
from TBL_ET_Attendance(nolock) atra where atra.UserId = @UserId and ((cast(AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0)
End
else if(@CheckType = 'TotalWorkingDay')
Begin
set @totalCount = isnull((select Count(sDate) from (
select distinct case when cast(aa.AttendanceIn as Date) != '' then cast(aa.AttendanceIn as Date) else cast(aa.AttendanceOut as Date) end sDate
from TBL_ET_Attendance(nolock) aa 
where aa.UserId = @UserId and ((cast(AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)t), 0)
End
else if(@CheckType = 'TotalLeave')
Begin
set @totalCount = isnull((select sum(tt.dayLeave) from (
Select (case when cast(t.FromDate as date) = cast(t.ToDate as date) then (Leavecount * (QuarterRenge* .25)) 
when cast(t.FromDate as date) = cast(t.ToDate as date) and StartQuarterDate = 1 and EndQuarterDate = 4 then Leavecount 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount = 2 and StartQuarterDate = 1 and EndQuarterDate = 4 then Leavecount 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount = 2 and StartQuarterDate != 1 or EndQuarterDate != 4 then 
((4 - StartQuarterDate + 1) + (EndQuarterDate)) 
when cast(t.FromDate as date) != cast(t.ToDate as date) and Leavecount > 2 and StartQuarterDate != 1 or EndQuarterDate != 4 then 
(Leavecount - 2) +((4 - StartQuarterDate + 1) + (EndQuarterDate)) 
else 0 End) dayLeave 
from ( 
Select tblr.FromDate, tblr.ToDate, StartQuarterDate, EndQuarterDate, FromTime, ToTime, 
(isnull(DATEDIFF(day, tblr.FromDate, tblr.ToDate),0) + 1) Leavecount, 
((EndQuarterDate - StartQuarterDate) +1) QuarterRenge 
from TBL_ET_LeaveApproval(nolock) tlap 
inner join TBL_ET_LeaveRequest(nolock) tblr on tlap.LeaveRequestId = tblr.LeaveRequestId 
where tblr.UserId = @UserId and ApproverStatus = 'Approved' and 
((cast(tblr.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tblr.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))) t 
) tt), 0)
End
else if(@CheckType = 'WeekOff')
Begin
set @totalCount = isnull((select count(*) from (
select distinct sumpwo.WeekOffId from TBL_ET_ShiftUserMapping(nolock) sump 
inner join TBL_ET_ShiftUserMappWeekOff (nolock) sumpwo on sump.ShiftUserMappingId = sumpwo.ShiftUserMappingId and sumpwo.IsActive = 1
where sump.UserId = @UserId
and ((cast(sump.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(sump.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date))))t),0)
End
else if(@CheckType = 'LateSignin')
Begin
set @totalCount = isnull((select count(AttendanceI) from (
Select distinct AttendanceI from(
Select cast(AttendanceIn as date) AttendanceI, IATime, StartTime, (case when IATime > StartTime then 1
else 0 end) LateLogin
from (Select atra.AttendanceId, atra.AttendanceIn, atra.AttendanceGroupId,
CAST(atra.AttendanceIn AS time) IATime,
 smat.StartTime
 from TBL_ET_TEMPMonthDate(nolock) tmde 
 left join TBL_ET_Attendance(nolock) atra on cast(tmde.MDate as date) = cast(atra.AttendanceIn as date) 
 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where (cast(tmde.MDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) and agum.UserId = @UserId 
)t
)t2
where LateLogin > 0
)t3 
),0)
End
else if(@CheckType = 'OutEarlyDays')
Begin
set @totalCount = isnull((select count(AttendanceO) from (
Select distinct AttendanceO from (
Select cast(AttendanceOut as date) AttendanceO, IATime, StartTime, (case when OATime < EndTime then 1
else 0 end) EarlyLogin
from (Select atra.AttendanceId, atra.AttendanceOut, atra.AttendanceGroupId,
CAST(atra.AttendanceIn AS time) IATime,
CAST(atra.AttendanceOut AS time) OATime,
 smat.StartTime,
 smat.EndTime
 from TBL_ET_TEMPMonthDate (nolock) tmde 
 left join TBL_ET_Attendance (nolock) atra on cast(tmde.MDate as date) = cast(atra.AttendanceOut as date) 
 inner join TBL_ET_AttendanceGroup (nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where (cast(tmde.MDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) and
 agum.UserId = @UserId
)t) t5 where EarlyLogin > 0 
) t4),0)
End
else if(@CheckType = 'TotalDays')
Begin
set @totalCount = DATEDIFF(DAY, cast(@FDate as date), cast(@TDate as date))
End
else if(@CheckType = 'HalfDays')
Begin
set @totalCount = (select count(*) from ( 
select distinct ADate, ROW_NUMBER() OVER ( PARTITION BY ADate ORDER BY ADate, Attttime desc) row_num, Attttime, --(((case when max(Attttime) != '' then max(Attttime) else 0 End) * 100)/AtttSettingTime) akm, 
AttendanceMinPercentage, AttendanceMaxPercentage 
from( 
select (case when cast(AttendanceIn as date) != '' Then cast(AttendanceIn as date) 
else cast(AttendanceOut as date) End) ADate, Attttime, AtttSettingTime, 
AttendanceMinPercentage, AttendanceMaxPercentage, TypeOfStatus 
from( 
Select distinct atra.AttendanceIn, atra.AttendanceOut, 
CAST(atra.AttendanceIn AS time) IATime, CAST(atra.AttendanceOut AS time) OATime, 
DATEDIFF(MINUTE, atra.AttendanceIn, atra.AttendanceOut) Attttime, 
DATEDIFF(MINUTE, smat.StartTime, smat.EndTime) AtttSettingTime, 
atgas.AttendanceMinPercentage, atgas.AttendanceMaxPercentage, TypeOfStatus 
from TBL_ET_Attendance (nolock) atra 
 inner join TBL_ET_AttendanceGroup (nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 --left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join TBL_ET_AttendanceGroupAttendanceSettings(nolock) atgas on atra.AttendanceGroupId = atgas.AttendanceGroupId 
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId 
 where ((cast(atra.AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(atra.AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date))) and agum.UserId = @UserId 
)tt 
)tt2 
where Attttime != '' and TypeOfStatus = 'HalfDay' 
group by ADate, Attttime, AttendanceMinPercentage, AttendanceMaxPercentage, TypeOfStatus 
)tt3 where row_num = 1 and Attttime between AttendanceMinPercentage and AttendanceMaxPercentage)
End
else if(@CheckType = 'NumberOfBreaks')
Begin
set @totalCount = isnull((select count(*) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((cast(tebt.StartDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tebt.EndDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)Tbt),0)
End
else if(@CheckType = 'TimeInBreaks')
Begin
set @totalCount = isnull((select sum(cast(DATEDIFF(minute, cast(Tbts.StartDate as datetime), cast(Tbts.EndDate as datetime)) as int)) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((cast(tebt.StartDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tebt.EndDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)Tbts),0)
End
else if(@CheckType = 'MaxBreakTimes')
Begin
set @totalCount = isnull((select max(cast(DATEDIFF(minute, cast(Tbts.StartDate as datetime), cast(Tbts.EndDate as datetime)) as int)) from (
select distinct tebt.StartDate, tebt.EndDate from TBL_ET_BreakTransaction tebt where UserId = @UserId
and ((cast(tebt.StartDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tebt.EndDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)Tbts),0)
End
else if(@CheckType = 'TotalTask')
Begin
set @totalCount = isnull((select sum(Total) from (
select count(*) Total from tbl_tsk_TaskHistory(nolock) ttth where ttth.AssignedTo = @UserId 
and ((cast(ttth.StartDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(ttth.EndDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
union all
select count(*) Total from TBL_ET_PhysicalAppointment(nolock) tepa where tepa.AssignedTo = @UserId 
and ((cast(tepa.StartDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tepa.EndDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)t), 0)
End
else if(@CheckType = 'TimeSpentInTasks')
Begin
set @totalCount = isnull((Select sum(DATEDIFF(minute, CheckIn, CheckOut)) from (
Select distinct GeoEntityCheckId, PhysicalAppointmentId, UserId, CheckIn, CheckOut from TBL_ET_GeoEntityCheckInOut(nolock) tege
where tege.UserId = @UserId 
and ((cast(tege.CheckIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tege.CheckOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
)tt),0)
End
else if(@CheckType = 'SignIn')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_Attendance(nolock) where UserId = @UserId  
and ((cast(AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(AttendanceIn as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
), 0)
End
else if(@CheckType = 'SignInRequest')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_AttendanceIssueRequest(nolock) where UserId = @UserId and ActionType='SignIn' 
and ((cast(ActionDateTime as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(ActionDateTime as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0)
End
else if(@CheckType = 'SignOut')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_Attendance(nolock) where UserId = @UserId  
and ((cast(AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(AttendanceOut as Date) between cast(@FDate as Date) and cast(@TDate as Date)))
), 0)
End
else if(@CheckType = 'SignOutRequest')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_AttendanceIssueRequest(nolock) where UserId = @UserId and ActionType='SignOut' and ((cast(ActionDateTime as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(ActionDateTime as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0)
End
else if(@CheckType = 'HolidayDays')
Begin
set @totalCount = isnull((select count(*) from TBL_ET_HolidayBranch(nolock) tehb
inner join TBL_ET_HolidayMaster(nolock) tehm on tehb.HolidayId = tehm.HolidayId
inner join TBL_ET_AttendanceGroupBranchMapping (nolock) atbg on tehb.BranchId = atbg.BranchId
inner join TBL_ET_AttendanceGroupUserMapping (nolock) atum on atbg.AttendanceGroupId = atum.AttendanceGroupId
where atum.UserId = @UserId and ((cast(tehm.HolidayDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(tehm.HolidayDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0)
End
return @totalCount
end

GO

/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_BreakTransactionListByUserIdDate]    Script Date: 06-06-26 10:46:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_TBL_ET_BreakTransactionListByUserIdDate] 
(@UserId bigint, @Date varchar(20)) 
returns nvarchar(max) 
as 
begin 
declare @breakjson nvarchar(max)= '' 
Begin 
set @breakjson = (select isnull(brtm.BreakTypeName, '') BreakTypeName, 
FORMAT(CAST(brts.StartDate AS DATETIME),'hh:mm tt') BreakStartTime, isnull(FORMAT(CAST(brts.EndDate AS DATETIME),'hh:mm tt'), 'No Data')  BreakEndTime 
from TBL_ET_BreakTransaction(nolock) brts 
inner join TBL_ET_BreakTypeMaster (nolock) brtm on brts.BreakTypeId = brtm.BreakTypeId 
where UserId = @UserId and (cast(brts.StartDate as Date) = cast(@Date as Date) or cast(brts.EndDate as Date) = cast(@Date as Date)) 
for JSON PATH) 
End 
return @breakjson 
end 

GO

/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_ExpenseTotalSummary]    Script Date: 06-06-26 10:46:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_TBL_ET_ExpenseTotalSummary]
(@UserId bigint, @Date varchar(20), @CheckType varchar(30))  
returns decimal(10,2) 
as 
begin 
declare @totalCount decimal(10,2) 
if(@CheckType = 'TotalNoOfVisit') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.NoOfVisits), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and (Month(cast(teec.FromDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.FromDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(teec.ToDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.ToDate as date)) = Year(cast(@Date as date)))),0)
End 
else if(@CheckType = 'TotalDistance') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.TotalKMs), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and (Month(cast(teec.FromDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.FromDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(teec.ToDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.ToDate as date)) = Year(cast(@Date as date)))),0)
End 
else if(@CheckType = 'TotalTimeSpentTravelled') 
Begin 
set @totalCount = isnull((Select sum(duration) from (
Select isnull(DATEDIFF(minute, teec.FromDate, teec.ToDate), 0) duration from TBL_ET_ExpenseApproval(nolock) teea 
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId 
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved' 
and (Month(cast(teec.FromDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.FromDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(teec.ToDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.ToDate as date)) = Year(cast(@Date as date))) 
)tttt),0)
End 
else if(@CheckType = 'TotalClaim') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.TotalAmount), 0) from TBL_ET_ExpenseClaim(nolock) teec 
Where teec.UserId = @UserId and (Month(cast(teec.FromDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.FromDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(teec.ToDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.ToDate as date)) = Year(cast(@Date as date)))), 0) 
End 
else if(@CheckType = 'TotalApproved') 
Begin 
set @totalCount = isnull((Select isnull(sum(teea.ApprovedAmount), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and (Month(cast(teec.FromDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.FromDate as date)) = Year(cast(@Date as date))) 
 or (Month(cast(teec.ToDate as date)) = Month(cast(@Date as date)) and 
 Year(cast(teec.ToDate as date)) = Year(cast(@Date as date)))),0) 
End 
--else if(@CheckType = 'TotalPaidOuts') 
--Begin 
