/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_ExpenseTotalSummaryFT]    Script Date: 06-06-26 10:46:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_TBL_ET_ExpenseTotalSummaryFT]
(@UserId bigint, @FDate varchar(20), @TDate varchar(20), @CheckType varchar(30))  
returns decimal(10,2) 
as 
begin 
declare @totalCount decimal(10,2) 
--set @FDate = CONVERT(CHAR(10),CONVERT(DATETIME,LEFT(@FDate,10),105),101);
--set @TDate = CONVERT(CHAR(10),CONVERT(DATETIME,LEFT(@TDate,10),105),101);

if(@CheckType = 'TotalNoOfVisit') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.NoOfVisits), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0)
End
else if(@CheckType = 'TotalDistance') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.TotalKMs), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0)
End 
else if(@CheckType = 'TotalTimeSpentTravelled') 
Begin 
set @totalCount = isnull((Select sum(duration) from (
Select isnull(DATEDIFF(minute, teec.FromDate, teec.ToDate), 0) duration from TBL_ET_ExpenseApproval(nolock) teea 
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId 
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved' 
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date))))tttt),0)
End
else if(@CheckType = 'TotalClaim') 
Begin 
set @totalCount = isnull((Select isnull(sum(teec.TotalAmount), 0) from TBL_ET_ExpenseClaim(nolock) teec 
Where teec.UserId = @UserId and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0) 
End 
else if(@CheckType = 'TotalApproved') 
Begin
set @totalCount = isnull((Select isnull(sum(teea.ApprovedAmount), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Approved'
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0) 
End
else if(@CheckType = 'TotalRejected') 
Begin
set @totalCount = isnull((Select isnull(sum(teea.ApprovedAmount), 0) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus = 'Rejected' 
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0) 
End
else if(@CheckType = 'TotalPending') 
Begin
Declare @ClaimAmount decimal(10,2) 
set @ClaimAmount = isnull((Select isnull(sum(teec.TotalAmount), 0) from TBL_ET_ExpenseClaim(nolock) teec 
Where teec.UserId = @UserId and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))), 0)

set @totalCount = isnull((Select (@ClaimAmount - isnull(sum(teea.ApprovedAmount), 0)) from TBL_ET_ExpenseApproval(nolock) teea
inner join TBL_ET_ExpenseClaim(nolock) teec on teea.ExpenseClaimId = teec.ExpenseClaimId
Where teec.UserId = @UserId and teea.ApproverStatus in ('Approved','Rejected') 
and ((cast(teec.FromDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)) or (cast(teec.ToDate as Date) between cast(@FDate as Date) and cast(@TDate as Date)))),0) 
End
return @totalCount 
end 

GO

/****** Object:  UserDefinedFunction [dbo].[fn_TBL_ET_GeoEntityCheckInOutCount]    Script Date: 06-06-26 10:46:14 ******/
