CREATE   FUNCTION [dbo].[fn_TBL_ET_GeoEntityCheckInOutCount]
(@UserId bigint, @Date varchar(20), @CheckType varchar(10))
returns int
as
begin
declare @totalCount int= 0
if(@CheckType = 'CheckIn')
Begin
set @totalCount = isnull((select count(CheckIn) from TBL_ET_GeoEntityCheckInOut(nolock) 
where UserId = @UserId and cast(CheckIn as Date) = cast(@Date as Date)), 0)
End
if(@CheckType = 'CheckOut')
Begin
set @totalCount = isnull((select count(CheckOut) from TBL_ET_GeoEntityCheckInOut(nolock) 
where UserId = @UserId and cast(CheckOut as Date) = cast(@Date as Date)), 0)
End
if(@CheckType = 'CheckInCount')
Begin
set @totalCount = isnull((select count(CheckIn) from TBL_ET_GeoEntityCheckInOut(nolock) 
where UserId = @UserId and ((Month(cast(CheckIn as Date)) = Month(cast(@Date as Date))) and (Year(cast(CheckIn as Date)) = Year(cast(@Date as Date))))), 0)
End
if(@CheckType = 'CheckOutCount')
Begin
set @totalCount = isnull((select count(CheckOut) from TBL_ET_GeoEntityCheckInOut(nolock) 
where UserId = @UserId and ((Month(cast(CheckOut as Date)) = Month(cast(@Date as Date))) and (Year(cast(CheckOut as Date)) = Year(cast(@Date as Date))))), 0)
End
if(@CheckType = 'CheckInRequest')
Begin
set @totalCount = isnull((select count(ActionDateTime) from TBL_ET_GeoEntityCheckInOutRequest(nolock) 
where UserId = @UserId and ActionType = 'CheckIn' and  ((Month(cast(ActionDateTime as Date)) = Month(cast(@Date as Date))) and (Year(cast(ActionDateTime as Date)) = Year(cast(@Date as Date))))), 0)
End
if(@CheckType = 'CheckOutRequest')
Begin
set @totalCount = isnull((select count(ActionDateTime) from TBL_ET_GeoEntityCheckInOutRequest(nolock) 
where UserId = @UserId and ActionType = 'CheckOut' and ((Month(cast(ActionDateTime as Date)) = Month(cast(@Date as Date))) and (Year(cast(ActionDateTime as Date)) = Year(cast(@Date as Date))))), 0)
End

return @totalCount
end

GO

