CREATE   FUNCTION [dbo].[fn_TBL_ET_PhysicalCollebratorUM_PhyId]
(@PhysicalAppointmentId bigint, @CheckType varchar(30))
returns nvarchar(max)
as
begin
		declare @AllUsers nvarchar(max)
		if(@CheckType = 'Collaborator')
		Begin

			select @AllUsers=isnull(STRING_AGG(t.UserName,', '),'') from (
			select distinct Concat(ud.FName, ' ', isnull(ud.LName, '')) UserName from TBL_ET_PhyAppointCollaboratorUserMapping(nolock) phcum 
			inner join User_Detail(nolock) ud on phcum.UserId = ud.User_ID
			where phcum.PhysicalAppointmentId = @PhysicalAppointmentId
			)t
		--select * from TBL_ET_PhyAppointUserMapping
		End
		if(@CheckType = 'FieldExecutive')
		Begin
			select @AllUsers=isnull(STRING_AGG(tt.UserName,', '),'') from (
			select distinct Concat(ud.FName, ' ', isnull(ud.LName, '')) UserName from TBL_ET_PhyAppointUserMapping(nolock) phcum 
			inner join User_Detail(nolock) ud on phcum.UserId = ud.User_ID
			where phcum.PhysicalAppointmentId = @PhysicalAppointmentId)tt
		End

	return @AllUsers
end

GO

