/****** Object:  UserDefinedFunction [dbo].[fn_trimprefixes]    Script Date: 06-06-26 10:46:16 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

    
CREATE   FUNCTION [dbo].[fn_trimprefixes](@string nvarchar(max),@prefix nvarchar(10))    
 returns nvarchar(max)    
 as    
 begin  
 declare @len int=len(@prefix)    
 while substring(@string,1,@len)=@prefix and len(@string)>@len  
 begin    
 select @string=right(@string,len(@string)-@len)    
 end    
 return @string    
 end 
GO

