GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[fn_userbrandedpartner](@userid bigint)    

  returns bigint

  as    

  begin    

  declare @partneruser_id bigint,@m_id bigint,@partnertype int=0 

  if not exists(select 1 from reseller_detail(nolock) where user_id=dbo.ufn_GetUserParentId(@userid) and partner_type > 1)

  begin

  select @m_id=m_id from user_detail(nolock) where user_id=@userid 

  end

  else

  begin

    select @m_id=Reseller_ID from reseller_detail(nolock) where user_id=@userid 

  end

  select @partnertype=partner_type,@userid=user_id from reseller_detail(nolock) where reseller_id=@m_id 

  if isnull(@partnertype,0)>1

  begin

  select @partneruser_id=@userid

  end

  else

  begin

   select @m_id=case when @partneruser_id=1 then m_id else 10043 end from user_detail(nolock) where user_id=@userid     

  select @partneruser_id=user_id from reseller_detail(nolock) where reseller_id=@m_id 

  end    

  return @partneruser_id    

  end
 
GO

