 CREATE   FUNCTION [dbo].[fn_userdomain](@userid bigint)  
  returns nvarchar(500)  
  as  
  begin  
  declare @domain nvarchar(500),@m_id bigint,@partnertype int=0  
  select @m_id=m_id from user_detail(nolock) where user_id=@userid  
  select @partnertype=partner_type from reseller_detail(nolock) where user_id=@userid  
  select @domain='https://'+replace(replace(domain,'https://',''),'http://','') from reseller_detail(nolock) where   
   case when isnull(@partnertype,0) in (0,1) then reseller_id else user_id end  
  =case when isnull(@partnertype,0) in (0,1) then @m_id else @userid end  
    
  return @domain  
  
  end  
GO

