GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_UserIsSignedIn](@user_id bigint)
returns int
as
begin
declare @status int=0
if ((select top 1 movementcode from [TBL_ET_UserLocationTracking] (nolock) where userid=@user_id and cast(locationdatetime as date)
=cast(getdate() as date)  order by locationdatetime desc) not in ('breakIn','signOut','SIGN_OUT')
and exists (select 1 from [TBL_ET_UserLocationTracking] (nolock) where userid=@user_id and cast(locationdatetime as date)
=cast(getdate() as date) and MovementCode in ('SIGN_IN','SignIn')))
set @status=1

return isnull(@status,0)
end







