CREATE   FUNCTION [dbo].[fn_UserLastMovementCode](@user_id bigint)
returns nvarchar(20)
as
begin
	declare @Mc nvarchar(20) = (select top 1 movementcode 
		from [TBL_ET_UserLocationTracking] (nolock) 
		where userid=@user_id and cast(locationdatetime as date) = cast(getdate() as date) order by locationdatetime desc) 

	if(ISNULL(@Mc, '') = '')
	begin
		set @Mc = (select top 1 movementcode 
		from [TBL_ET_UserLocationTracking_Archived] (nolock) 
		where userid=@user_id and cast(locationdatetime as date) = cast(getdate() as date) order by locationdatetime desc) 
	end

	return isnull(@Mc,'')
end


