/****** Object:  UserDefinedFunction [dbo].[fn_UserMatchesSearch]    Script Date: 06-06-26 10:46:19 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

        
CREATE   FUNCTION [dbo].[fn_UserMatchesSearch]      
(      
 @User_ID           BIGINT,      
 @SavedSearchId     BIGINT      
)      
RETURNS INT      
AS      
      
BEGIN      
    
     Declare @ParentID bigint = 0    
     Select top 1 @ParentID = isnull(ParentID,0) from User_Detail with(nolock) Where User_ID = @User_ID       
    
    
 --Declare & assign uservalues        
 DECLARE @UUserName            NVARCHAR(100),      
         @UMobile              BIGINT,      
         @UEmailID             NVARCHAR(200),      
         @UUserType            NVARCHAR(1),      
         @UUserFilter          NVARCHAR(20),      
         @UIsActive            NVARCHAR(1),      
         @ULastLoginBefore     BIGINT,      
         @ULastPurchase        DECIMAL(18, 4),      
         @ULastLogin           BIGINT      
       
 SELECT @uusername = user_login,      
        @umobile         = mobile,      
        @uemailid        = email,      
        @uusertype       = usertype,      
        @uuserfilter     = userfilter,      
        @uisactive       = STATUS      
 FROM   user_detail with(nolock)     
 WHERE  USER_ID          = @user_id      
        AND M_ID         = 10043      
       
 SELECT @ulastlogin = ISNULL(      
            (      
                SELECT DATEDIFF(      
                           d,      
                           CONVERT(NVARCHAR, MAX(createddate), 112),      
                           CONVERT(NVARCHAR, GETDATE(), 112)      
                       )      
                FROM   AddCreditDetails with(nolock)      
                WHERE  USERID         = @ParentID      
                       AND Reason     = 'Purchase'      
            ),      
            0      
        )      
       
 SELECT @ulastpurchase = ISNULL(      
            (      
                SELECT TOP 1 Pricepersms      
                FROM   AddCreditDetails with(nolock)     
                WHERE  USERID         = @ParentID      
                       AND Reason     = 'Purchase'      
                ORDER BY      
                       id DESC      
            ),      
            0      
        )      
       
 SELECT @uLastLoginBefore = ISNULL(      
            (      
                SELECT DATEDIFF(      
                           d,      
                           CONVERT(NVARCHAR, MAX(datecreated), 112),      
                           CONVERT(NVARCHAR, GETDATE(), 112)      
                       )      
                FROM   Credit_Details with(nolock)     
                WHERE  USER_ID         = ISNULL(fromuser_id, USER_ID)      
                       AND USER_ID     = @ParentID      
            ),      
            0      
        )       
       
       
 --Declare & assign search values where exist and rest to assume user values        
 DECLARE @NewUser             INT,      
         @UserName            NVARCHAR(100),      
         @Mobile              BIGINT,      
         @EmailID             NVARCHAR(200),      
         @UserType            NVARCHAR(1),      
         @UserFilter          NVARCHAR(20),      
         @IsActive            NVARCHAR(1),      
         @LastLoginBefore     BIGINT,      
         @LastPurchase        DECIMAL(18, 4),      
         @LastLogin           BIGINT      
       
 SELECT @NewUser = newuser,      
        @username            = ISNULL(NULLIF(UserName, ''), @uusername),      
        @mobile              = ISNULL(NULLIF(mobile, 0), @uMobile),      
        @emailid             = ISNULL(NULLIF(EmailID, ''), @uemailid),      
        @usertype            = ISNULL(NULLIF(UserType, ''), @uusertype),      
        @userfilter          = ISNULL(NULLIF(UserFilter, ''), @uuserfilter),      
        @isactive            = ISNULL(IsActive, @uisactive),      
        @LastLoginBefore     = ISNULL(NULLIF(lastloginbefore, 0), @ulastloginbefore),      
        @lastpurchase        = ISNULL(NULLIF(LastPurchase, 0), @ulastpurchase),      
        @lastlogin           = ISNULL(NULLIF(LastLogin, 0), @ulastlogin)      
 FROM   SavedSearch with(nolock)     
 WHERE  ID                   = @SavedSearchid        
       
 DECLARE @result INT       
 --Return 1 if user is a match else 0        
 IF @NewUser = 1      
 BEGIN      
     IF NOT EXISTS(      
            SELECT 1      
            FROM   credit_details with(nolock)      
            WHERE  USER_ID = @ParentID      
            HAVING COUNT(*) > 1      
        )      
     BEGIN      
         SET @result = 1      
     END      
     ELSE      
     BEGIN      
         SET @result = 0      
     END       
     GOTO endst      
 END      
 ELSE      
 BEGIN      
     IF EXISTS(      
            SELECT 1      
            FROM   user_detail  with(nolock)    
            WHERE  USER_ID             = @user_id      
                   AND @username    = @uusername      
                   AND @mobile         = @uMobile      
                   AND @emailid        = @uEmailID      
                   AND @usertype       = @uUserType      
                   AND @userfilter     = @uUserFilter      
                   AND @isactive       = @uIsActive      
                   AND @LastLoginBefore <= @ulastloginbefore      
                   AND @lastpurchase <= @uLastPurchase      
                   AND @lastlogin <= @uLastLogin      
        )      
     BEGIN      
         SET @result = 1      
     END      
     ELSE      
     BEGIN      
         SET @result = 0      
     END       
     GOTO endst      
 END       
 endst:      
 RETURN @result      
END 
GO

/****** Object:  UserDefinedFunction [dbo].[fn_UserMatchesSearchForMail]    Script Date: 06-06-26 10:46:19 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[fn_UserMatchesSearchForMail]
(
	@User_ID           BIGINT,
	@SavedSearchId     BIGINT
)
RETURNS INT
AS
BEGIN
	--Declare & assign uservalues        
	DECLARE @UUserName            NVARCHAR(100),
	        @UMobile              BIGINT,
	        @UEmailID             NVARCHAR(200),
	        @UUserType            NVARCHAR(1),
	        @UUserFilter          NVARCHAR(20),
	        @UIsActive            NVARCHAR(1) = 0,
	        @ULastLoginBefore     BIGINT,
	        @ULastPurchase        DECIMAL(18, 4),
	        @ULastLogin           BIGINT      
	
	SELECT @uusername = user_login,
	       @umobile         = mobile,
	       @uemailid        = email,
	       @uusertype       = usertype,
	       @uuserfilter     = userfilter,
	       @uisactive       = STATUS
	FROM   user_detail
	WHERE  USER_ID          = @user_id
	       AND M_ID         = 10043      
	
	SELECT @ulastlogin = ISNULL(
	           (
	               SELECT DATEDIFF(
	                          d,
	                          CONVERT(NVARCHAR, MAX(createddate), 112),
	                          CONVERT(NVARCHAR, GETDATE(), 112)
	                      )
	               FROM   AddCreditDetails
	               WHERE  USERID         = @user_id
	                      AND Reason     = 'Purchase'
	           ),
	           0
	       )      
	
	SELECT @ulastpurchase = ISNULL(
	           (
	               SELECT TOP 1 Pricepersms
	               FROM   AddCreditDetails
	               WHERE  USERID         = @user_id
	                      AND Reason     = 'Purchase'
	               ORDER BY
	                      id DESC
	           ),
	           0
	       )      
	
	SELECT @uLastLoginBefore = ISNULL(
	           (
	               SELECT DATEDIFF(
	                          d,
	                          CONVERT(NVARCHAR, MAX(datecreated), 112),
	                          CONVERT(NVARCHAR, GETDATE(), 112)
	                      )
	               FROM   MailCreditDetails
	               WHERE  USER_ID         = ISNULL(fromuser_id, USER_ID)
	                      AND USER_ID     = @user_id
	           ),
	           0
	       ) 
	
	
	--Declare & assign search values where exist and rest to assume user values        
	DECLARE @NewUser             INT,
	        @UserName            NVARCHAR(100),
	        @Mobile              BIGINT,
	        @EmailID             NVARCHAR(200),
	        @UserType            NVARCHAR(1),
	        @UserFilter          NVARCHAR(20),
	        @IsActive            NVARCHAR(1),
	        @LastLoginBefore     BIGINT,
	        @LastPurchase        DECIMAL(18, 4),
	        @LastLogin           BIGINT      
	
	SELECT @NewUser = newuser,
	       @username            = ISNULL(NULLIF(UserName, ''), @uusername),
	       @mobile              = ISNULL(NULLIF(mobile, 0), @uMobile),
	       @emailid             = ISNULL(NULLIF(EmailID, ''), @uemailid),
	       @usertype            = ISNULL(NULLIF(UserType, ''), @uusertype),
	       @userfilter          = ISNULL(NULLIF(UserFilter, ''), @uuserfilter),
	       @isactive            = ISNULL(IsActive, @uisactive),
	       @LastLoginBefore     = ISNULL(NULLIF(lastloginbefore, 0), @ulastloginbefore),
	       @lastpurchase        = ISNULL(NULLIF(LastPurchase, 0), @ulastpurchase),
	       @lastlogin           = ISNULL(NULLIF(LastLogin, 0), @ulastlogin)
	FROM   SavedSearch
	WHERE  ID                   = @SavedSearchid        
	
	DECLARE @result INT 
	--Return 1 if user is a match else 0        
	IF @NewUser = 1
	BEGIN
	    IF NOT EXISTS(
	           SELECT 1
	           FROM   MailCreditDetails
	           WHERE  USER_ID = @user_id
	           HAVING COUNT(*) > 1
	       )
	    BEGIN
	        SET @result = 1
	    END
	    ELSE
	    BEGIN
	        SET @result = 0
	    END 
	    GOTO endst
	END
	ELSE
	BEGIN
	    IF EXISTS(
	           SELECT 1
	           FROM   user_detail
	           WHERE  USER_ID             = @user_id
	                  AND @username       = @uusername
	                  AND @mobile         = @uMobile
	                  AND @emailid        = @uEmailID
	                  AND @usertype       = @uUserType
	                  AND @userfilter     = @uUserFilter
	                  AND @isactive       = @uIsActive
	                  AND @LastLoginBefore <= @ulastloginbefore
	                  AND @lastpurchase <= @uLastPurchase
	                  AND @lastlogin <= @uLastLogin
	       )
	    BEGIN
	        SET @result = 1
	    END
	    ELSE
	    BEGIN
	        SET @result = 0
	    END 
	    GOTO endst
	END 
	endst:
	RETURN @result
END

GO

/****** Object:  UserDefinedFunction [dbo].[fn_userpendingfollowup]    Script Date: 06-06-26 10:46:19 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_userpendingfollowup]
(@user_id bigint)
returns int
as
begin
Declare @c int
select @c=count(1) from userleads(nolock) u where assignedto=@user_id and followupdate<getdate() and followupstatus in
(select id from FollowUp_Status(nolock) f where isnull(parentid,u.parentid)=u.parentid and IsCallback=1)
return @c

end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_userpendingfollowup_datewise]    Script Date: 06-06-26 10:46:20 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_userpendingfollowup_datewise]      
(@user_id bigint,@fromdate date,@todate date)      
returns int      
as      
begin      
Declare @c int ,@parentid bigint      
select @parentid = dbo.ufn_GetUserParentId(@user_id)  
select @c=count(1) from userleads(nolock) u where  parentid=@parentid and  assignedto=@user_id and followupdate<getdate() and followupstatus in       
   (select id from FollowUp_Status(nolock) f where isnull(parentid,u.parentid)=u.parentid and IsCallback=1)   
      and  createdon between @fromdate and @todate      
return @c      
      
end
GO

/****** Object:  UserDefinedFunction [dbo].[fn_usersloggedin_today]    Script Date: 06-06-26 10:46:20 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fn_usersloggedin_today](@parentid bigint)
returns int
as
begin
declare @count int
select @count=count(1) from user_detail(nolock) where cast(LastLogin1 as date)=cast(getdate() as date) and parentid=@parentid
return @count
end

