CREATE   FUNCTION [dbo].[fnAppEmailCheck](@email VARCHAR(255))   
--Returns true if the string is a valid email address.   
RETURNS bit   
as   
BEGIN  
 DECLARE @valid bit =0 
 --IF isnull(@email,'')=''
 --begin
 --set @valid=1
 --end
 IF isnull(@email,'')<>''
begin
   if @email not like '%@%@%' and @email LIKE '%_@__%.__%'
   begin
   --IF @email like '[a-z,0-9,_,-]%@[a-z,0-9,_,-]%.[a-z][a-z]%' AND  @email NOT like '%@%@%' AND CHARINDEX('.@',@email) = 0 AND CHARINDEX('..',@email) = 0 AND CHARINDEX(',',@email) = 0 AND RIGHT(@email,1) between 'a' AND 'z' 
   SET @valid=1 
   end
end
   RETURN @valid 
   END  
   
GO

