 -- '      
 -- ' Returns (smallint) :      
 -- ' -1 : Null or empty string operator      
 -- ' -2 : Invalid operator type      
 -- '  1 : The expression was Valid      
 -- '  0 : None of the above was true, and somehow got       
 -- '   past my checks, should never happen      
 -- '---------------------------------------------      
      
 --check if they sent in an operator      
 IF @Operator IS NULL OR LEN(RTRIM(LTRIM(@Operator))) = 0      
  RETURN -1      
      
 --prep the operator      
 SET @Operator = UPPER(LTRIM(RTRIM(@Operator)))      
 --remove any arbitrary single quotes      
 SET @Operator = REPLACE(@Operator, CHAR(39), '')      
      
 --check for a Valid operator      
 IF PATINDEX('%;' + @Operator + ';%', ';=;!=;<;<=;>;>=;LIKE %VAL%;NOT LIKE %VAL%;LIKE VAL%;NOT LIKE VAL%;LIKE %VAL;NOT LIKE %VAL;IS NULL;IS NOT NULL;') <= 0      
  RETURN -2      
       
 --sent in a null @string2 but not checking for nullable       
 --so it invalidates the rest of the checks      
 --allows for the possibility to NOT check      
 IF @String2 IS NULL AND (@Operator <> 'IS NULL' AND @Operator <> 'IS NOT NULL')      
  RETURN 1      
       
 IF @Operator = '=' --AND @String1 = @String2
   Begin
      return    case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                   then
				       case when cast(@String1 as numeric(18,2)) = cast(@String2 as numeric(18,2))
					      then 1
					      else  0
					   end 		         
		         when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) = cast(@String2 as date)
					      then 1
					      else  0
					   end

                 when  @String1  =  @String2
			         then 1					      
				 else
				      0
                  end 
     --RETURN 1      
   end
	   
 IF(@Operator = '!=' OR @Operator = '<>') --AND @String1 <> @String2      
     Begin
      return   case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                   then
				       case when cast(@String1 as numeric(18,2)) <> cast(@String2 as numeric(18,2))
					      then 1
					      else  0
					   end 		         
		         when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) <> cast(@String2 as date)
					      then 1
					      else  0
					   end

                 when  @String1  <>  @String2
			         then 1					      
				 else
				      0
                  end 
        --RETURN 1      
     end      
       
 IF @Operator = '<' -- AND @String1 < @String2
    Begin
	  return 
	          case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                   then
				       case when cast(@String1 as numeric(18,2)) < cast(@String2 as numeric(18,2))
					      then 1
					      else  0
					   end 		         
		          when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) < cast(@String2 as date)
					      then 1
					      else  0
					   end
				  else
				      0
                  end
				    
	    -- RETURN 1      
    end    
 IF @Operator = '<=' --AND @String1 <= @String2      
  Begin
	  return 
	          case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                   then
				       case when cast(@String1 as numeric(18,2)) <= cast(@String2 as numeric(18,2))
					      then 1
					      else  0
					   end 		         
		          when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) <= cast(@String2 as date)
					      then 1
					      else  0
					   end
				  else
				      0
                  end
				    
	    -- RETURN 1      
    end      
             
 IF @Operator = '>' --AND @String1 > @String2      
    Begin
    	 return 
	         case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                  then
			       case when cast(@String1 as numeric(18,2)) > cast(@String2 as numeric(18,2))
				      then 1
			  	       else  0
				   end 		         
		          when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) > cast(@String2 as date)
					      then 1
					      else  0
					   end
				  else
				      0
                  end
				    
	    -- RETURN 1 
    end       
       
 IF @Operator = '>=' -- AND @String1 >= @String2      
  Begin
    	 return 
	         case when isnumeric(@String1) = 1 and isnumeric(@String2) = 1
                  then
			       case when cast(@String1 as numeric(18,2)) >= cast(@String2 as numeric(18,2))
				      then 1
			  	       else  0
				   end 		         
		          when isdate(@String1) = 1 and isdate(@String2) = 1
                   then
				       case when cast(@String1 as date) >= cast(@String2 as date)
					      then 1
					      else  0
					   end
				  else
				      0
                  end
				    
	    -- RETURN 1 
  end     
 --Contains      
 IF @Operator = 'LIKE %VAL%' AND @String1 LIKE '%' + @String2 + '%'      
  RETURN 1      
       
 --Does not contain      
 IF @Operator = 'NOT LIKE %VAL%' AND @String1 NOT LIKE '%' + @String2 + '%'      
  RETURN 1      
      
 --begins with      
 IF @Operator = 'LIKE VAL%' AND @String1 LIKE @String2 + '%'      
  RETURN 1      
       
 --does not begin with      
 IF @Operator = 'NOT LIKE VAL%' AND @String1 NOT LIKE @String2 + '%'      
  RETURN 1      
       
 --starts with      
 IF @Operator = 'LIKE %VAL' AND @String1 LIKE '%' + @String2      
  RETURN 1      
       
 --does not start with      
 IF @Operator = 'NOT LIKE %VAL' AND @String1 NOT LIKE '%' + @String2      
  RETURN 1      
      
 --is null :)      
 IF @Operator = 'IS NULL' AND @String1 IS NULL      
  RETURN 1      
       
 --is not null      
 IF @Operator = 'IS NOT NULL' AND @String1 IS NOT NULL      
  RETURN 1      
      
 --IF we got here something is not right :( or we have a PEBCAK issue       
 --of course it can't be my code..... :D LOL {{Tim C 12-06-2002 23:13:25}}      
 --OR it COULD be that the check was invalid.........      
 RETURN 0      
END 
GO

/****** Object:  UserDefinedFunction [dbo].[fncRemove_HTML]    Script Date: 06-06-26 10:46:22 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fncRemove_HTML] (@HTMLText VARCHAR(MAX))
RETURNS VARCHAR(MAX)
AS
BEGIN
 
    DECLARE    @Start INT
    DECLARE    @End INT
    DECLARE    @Length INT
 
    -- Substitui a entidade HTML "&amp;" pelo caracter '&'
    SET @Start = CHARINDEX('&amp;', @HTMLText)
    SET @End = @Start + 4
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, '&')
        SET @Start = CHARINDEX('&amp;', @HTMLText)
        SET @End = @Start + 4
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a entidade HTML "&lt;" pelo caracter '<'
    SET @Start = CHARINDEX('&lt;', @HTMLText)
    SET @End = @Start + 3
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0) 
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, '<')
        SET @Start = CHARINDEX('&lt;', @HTMLText)
        SET @End = @Start + 3
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a entidade HTML "&gt;" pelo caracter '>'
    SET @Start = CHARINDEX('&gt;', @HTMLText)
    SET @End = @Start + 3
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, '>')
        SET @Start = CHARINDEX('&gt;', @HTMLText)
        SET @End = @Start + 3
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a entidade HTML "&amp;&amp;" pelo caracter '&'
    SET @Start = CHARINDEX('&amp;amp;', @HTMLText)
    SET @End = @Start + 4
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, '&')
        SET @Start = CHARINDEX('&amp;amp;', @HTMLText)
        SET @End = @Start + 4
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a entidade HTML "&nbsp;" pelo caracter ' '
    SET @Start = CHARINDEX('&nbsp;', @HTMLText)
    SET @End = @Start + 5
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, ' ')
        SET @Start = CHARINDEX('&nbsp;', @HTMLText)
        SET @End = @Start + 5
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a tag <br> pela sequência de nova linha (CHR(13) + CHR(10))
    SET @Start = CHARINDEX('<br>', @HTMLText)
    SET @End = @Start + 3
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, CHAR(13) + CHAR(10))
        SET @Start = CHARINDEX('<br>', @HTMLText)
        SET @End = @Start + 3
        SET @Length = (@End - @Start) + 1
    END
 
 
    -- Substitui a tag <br/> pela sequência de nova linha (CHR(13) + CHR(10))
    SET @Start = CHARINDEX('<br/>', @HTMLText)
    SET @End = @Start + 4
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, 'CHAR(13) + CHAR(10)')
        SET @Start = CHARINDEX('<br/>', @HTMLText)
        SET @End = @Start + 4
        SET @Length = (@End - @Start) + 1
    END
 
    -- Substitui a tag <br /> pela sequência de nova linha (CHR(13) + CHR(10))
    SET @Start = CHARINDEX('<br />', @HTMLText)
    SET @End = @Start + 5
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, 'CHAR(13) + CHAR(10)')
        SET @Start = CHARINDEX('<br />', @HTMLText)
        SET @End = @Start + 5
        SET @Length = (@End - @Start) + 1
    END
 
 
    -- Remove os parâmetros contidos nas tags HTML
    SET @Start = CHARINDEX('<', @HTMLText)
    SET @End = CHARINDEX('>', @HTMLText, CHARINDEX('<', @HTMLText))
    SET @Length = (@End - @Start) + 1
 
    WHILE (@Start > 0 AND @End > 0 AND @Length > 0)
    BEGIN
        SET @HTMLText = STUFF(@HTMLText, @Start, @Length, '')
        SET @Start = CHARINDEX('<', @HTMLText)
        SET @End = CHARINDEX('>', @HTMLText, CHARINDEX('<', @HTMLText))
        SET @Length = (@End - @Start) + 1
    END
 
 
    RETURN LTRIM(RTRIM(@HTMLText))
    
 
END
GO

/****** Object:  UserDefinedFunction [dbo].[fnGetalphabeticValue]    Script Date: 06-06-26 10:46:22 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fnGetalphabeticValue]  
(  
  @strAlphaNumeric NVARCHAR(256)  
)  
RETURNS NVARCHAR(256)  
AS  
BEGIN  
   
 --return LEFT(SUBSTRING(@inputString, PATINDEX('%[0-9.-]%', @inputString), 100),  
 --          PATINDEX('%[^0-9.-]%', SUBSTRING(@inputString, PATINDEX('%[0-9.-]%', @inputString), 100) + 'X') -1)  
  
 DECLARE @intAlpha INT  
  SET @intAlpha = PATINDEX('%[^a-z]%', @strAlphaNumeric)  
  BEGIN  
    WHILE @intAlpha > 0  
    BEGIN  
      SET @strAlphaNumeric = STUFF(@strAlphaNumeric, @intAlpha, 1, '' )  
      SET @intAlpha = PATINDEX('%[^a-z ]%', @strAlphaNumeric )  
    END  
  END 
  
  RETURN ISNULL(trim(@strAlphaNumeric),'')  
end  
GO

/****** Object:  UserDefinedFunction [dbo].[fnGetFacebookJsonFieldValue]    Script Date: 06-06-26 10:46:23 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fnGetFacebookJsonFieldValue]
(
    @Json NVARCHAR(MAX),
    @FieldName NVARCHAR(100)
)
RETURNS NVARCHAR(255)
AS
BEGIN
    DECLARE @Result NVARCHAR(255);

    SELECT TOP 1 @Result = JSON_VALUE([value], '$.values[0]')
    FROM OPENJSON(@Json, '$.field_data')
    WHERE JSON_VALUE([value], '$.name') = @FieldName;

    RETURN @Result;
END;

GO

