/****** Object:  UserDefinedFunction [dbo].[fnGetNumericValue]    Script Date: 06-06-26 10:46:24 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fnGetNumericValue]
(
    @strAlphaNumeric NVARCHAR(256)
)
RETURNS NVARCHAR(25)
AS
BEGIN
    IF @strAlphaNumeric IS NULL OR @strAlphaNumeric = ''
        RETURN N'0';
    
    DECLARE @result NVARCHAR(256) = '';
    DECLARE @i INT = 1;
    DECLARE @len INT = LEN(@strAlphaNumeric);
    DECLARE @char NCHAR(1);
    
    -- Extract only numeric characters
    WHILE @i <= @len
    BEGIN
        SET @char = SUBSTRING(@strAlphaNumeric, @i, 1);
        IF @char BETWEEN N'0' AND N'9'
            SET @result = @result + @char;
        SET @i = @i + 1;
    END
    
    -- Convert and trim
    RETURN ISNULL(LTRIM(RTRIM(CAST(TRY_CONVERT(BIGINT, @result) AS NVARCHAR(25)))), N'0');
END

GO

