/****** Object:  UserDefinedFunction [dbo].[fnGetNumericValue_TestDBAv2]    Script Date: 06-06-26 10:46:25 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fnGetNumericValue_TestDBAv2]  
(  
  @strAlphaNumeric VARCHAR(256)  
)  
RETURNS VARCHAR(256)  
AS  
BEGIN 

	 IF TRIM(@strAlphaNumeric) = ''
		BEGIN
			RETURN 0;
		END

	SET @strAlphaNumeric = REPLACE(@strAlphaNumeric, ' ', '');

	 IF TRY_CAST(@strAlphaNumeric AS BIGINT) IS NOT NULL 
		BEGIN
			RETURN @strAlphaNumeric;
		END

	DECLARE @charsToReplace VARCHAR(256) = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ!@#$%^&*()-=_+[]{}|\;:",.<>/?`~ ';
	DECLARE @rep CHAR(1) = '~';

	SELECT @strAlphaNumeric =
    REPLACE(
           TRANSLATE(
               @strAlphaNumeric,
               @charsToReplace,
               REPLICATE(@rep, DATALENGTH(@charsToReplace))
           ),
           @rep,
           ''
       )

	RETURN @strAlphaNumeric

END

GO

/****** Object:  UserDefinedFunction [dbo].[fnOffsettimeConvert]    Script Date: 06-06-26 10:46:25 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[fnOffsettimeConvert](
	@OffsetValue nvarchar(12)
)
returns int
as
begin
	declare @hours int, @minutes int
	select @hours = [value] from fn_Split(@OffsetValue, ':') where position = 1
	select @minutes = [value] from fn_Split(@OffsetValue, ':') where position = 2
	return ((@hours *60 )+ @minutes)-330
end

GO

