CREATE   FUNCTION [dbo].[fun_getEntityDetail_entityId]
(@EntityId bigint)
returns nvarchar(300)
as
begin
declare @UserName nvarchar(300)
set @UserName = isnull((select top 1 (case when GeoEntityType = 'lead' then (select top 1 ud.PersonName + ' Lead No.' + cast(LeadNo as varchar(10)) from UserLeads(nolock) ud where Id = tgesmm.EntityId)
when GeoEntityType = 'enquiry' then (select top 1 ue.PersonName from UserEnquiry(nolock) ue where EnquiryID = tgesmm.EntityId)
when GeoEntityType = 'location' then GeoEntityName + ' ' + Mobile 
else ''
end) 
from TBL_ET_GeoEntityMaster(nolock) tgesmm where GeoEntityId = @EntityId),'')

return @UserName

end

