/****** Object:  UserDefinedFunction [dbo].[Fun_GetMeetingMailMessage]    Script Date: 06-06-26 10:46:26 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

  
-- =============================================    
-- Author:  <Author,,Name>    
-- Create date: <Create Date, ,>    
-- Description: <Description, ,>    
-- =============================================    
CREATE   FUNCTION [dbo].[Fun_GetMeetingMailMessage]    
(    
 -- Add the parameters for the function here    
 @message nvarchar(max), @userid bigint,    
 @meetingid bigint,    
 @entityId Bigint     
)    
RETURNS NVARCHAR(MAX)    
AS    
BEGIN    
 -- Declare the return variable here    
 DECLARE @string nvarchar(max)  , @host nvarchar(200)
 select @host= EntityName from tbl_meetingUser where user_role='host' and Meeting_id=@meetingid
    
 Select @String =REPLACE     
      (Replace    
       ( Replace( Replace  
	   ( Replace   ( Replace  ( Replace( Replace
        (Replace (@message,    
        '#MeetingTitle#', ISNULL(TRIM(mt.Meeting_Name),''))    
       ,'#MeetingAgenda#' , ISNULL(TRIM(mt.MeetingAgenda),''))    
      ,'#UserName#', ISNULL(TRIM(mtu.EntityName),''))    
     ,'#Email#',ISNULL(TRIM(mtu.Email),''))    
	 ,'#MeetingStartTime#',ISNULL( cast(case when mt.StartTime is not null then mt.StartTime else mt.MeetStartTime end  as varchar),''))
    ,'#MeetingEndTime#',ISNULL(cast (mt.MeetEndTime as varchar),''))
	,'#JoinLink#',ISNULL(Replace(TRIM(jex.Expression),'#username#',trim(mtu.EntityName)),''))
	,'#RegistionFormLink#',ISNULL(TRIM(mt.RegistrationFormLink),''))
	,'#HostName#',ISNULL(TRIM(@host),''))
 from tbl_meeting mt     
 JOIN tbl_meetingUser mtu ON mtu.Meeting_ID=mt.ID     
 join Tbl_MeetingUserJoinExpression jex on jex.MeetingId=mt.ID
 WHERE mt.ID= @meetingid and mtu.EntityID =@entityId    
 -- Return the result of the function    
 RETURN @String     
    
END 



GO

