/****** Object:  UserDefinedFunction [dbo].[func_Tbl_eventProfilePic]    Script Date: 06-06-26 10:46:26 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[func_Tbl_eventProfilePic]
(
  @refTable nvarchar(200),
  @refID nvarchar(200)
)  
returns  nvarchar(500)
as
Begin
      Declare @ProfilePic nvarchar(500) = '' 
      
	  if(@refTable = 'tbl_LeadEventHistory')
	     Begin
		    
			select top 1  @ProfilePic = isnull(ProfileImgFileName,'') from UserLeads(nolock)	where id 
			      in (
			           select top 1 isnull(LeadID,0) from tbl_LeadEventHistory(nolock) where HistoryID = @refID 
			         )
		 End 
       else if(@refTable = 'tbl_EnquiryEventHistory')
	    Begin
		    select top 1  @ProfilePic = isnull(ProfileImgFileName,'') from Userenquiry(nolock)	where EnquiryID 
			      in (
			           select top 1 isnull(EnquiryID,0) from tbl_EnquiryEventHistory(nolock) where HistoryID = @refID 
			         )
		end
	   else if(@refTable = 'tbl_UserEventHistory')
	    Begin

		    select top 1  @ProfilePic = isnull(Image,'') from User_Detail(nolock)	where USER_ID 
			      in (
			           select top 1 isnull(UserID,0) from tbl_UserEventHistory(nolock) where HistoryID = @refID 
			         )
		 end   
       else 
	    Begin
