CREATE   FUNCTION [dbo].[func_ToGetTotalReached]  
(  
  @SMSCampaignID bigint,  
  @MailCampaignID bigint,  
  @VoiceCampaignID bigint,  
  @WhatsappCampaignID bigint  
)  
 Returns bigint as  
Begin  
  
       Declare @TotalReached bigint = 0    
                      
       select  @TotalReached =  SUM(NoOfRecipients)  from UserCampaignExecutionHistory(nolock)  
    where campaignID in  
               (  
        isnull(@SMSCampaignID,0),  
        isnull(@MailCampaignID,0),  
        isnull(@VoiceCampaignID,0),  
        isnull(@WhatsappCampaignID,0)  
      )  
  
       return isnull(@TotalReached,0)     
  
End




