CREATE   FUNCTION [dbo].[func_ToGetTotalReached_includingsequence]    
(   
@triggeredcampaignid bigint
  
)    
 Returns bigint as    
Begin 
       Declare @TotalReached bigint = 0,@SMSCampaignID bigint, @MailCampaignID bigint,@VoiceCampaignID bigint,    
  @WhatsappCampaignID bigint,@sequenceid bigint 
  
select @smscampaignid=smscampaignid,@MailCampaignID=mailcampaignid,@VoiceCampaignID=voicecampaignid,@WhatsappCampaignID=
whatsappcampaignid,@sequenceid=sequenceid
from triggeredcampaigns(nolock) where id=@triggeredcampaignid                        

select  @TotalReached =  
isnull((select SUM(NoOfRecipients)  from UserCampaignExecutionHistory(nolock)    
    where campaignID in    
               (    
        isnull(@SMSCampaignID,0),    
        isnull(@MailCampaignID,0),    
        isnull(@VoiceCampaignID,0),    
        isnull(@WhatsappCampaignID,0)    
      )),0) +
isnull((select count(distinct activityid) from [10.0.0.135].MySMSConversations.dbo.tbl_wa_automationtasks with (nolock) where activityid
is not null and ruleid=@triggeredcampaignid),0)	

   
    return isnull(@TotalReached,0)       
    
End  
GO

