Begin

    --Declare @IndiaMartkey nvarchar(200) = 'MTU2ODcxOTIwNi42MDcxIzE3MDkwNjIw' 
    
	Declare @TotalCount bigint = 0 
    Declare @LastRecordsDT nvarchar(50) = '' 
    Declare @ReturnText nvarchar(500) = ''
	
	Select @TotalCount = isnull(COUNT(INDIAMARTKEY),0) from IndiamartLeads(nolock) where INDIAMARTKEY =  @IndiaMartkey
          group by INDIAMARTKEY    
   
    --select @TotalCount  
