GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[FuncTo_CheckDIDInComingCalls](@DID nvarchar(50))    
returns nvarchar(50)    
as    
Begin    
    declare @temp nvarchar(50) = 'Not Exists'     
    if(exists(select 1 from leadsettings where (DIDNo = RTRIM(ltrim(@DID)) or (DIDNo = '0'+ RTRIM(ltrim( @DID))) ) and  isnull(Mode,'') = 'IncomingCallsLead'  and  ISNULL(Status,0) = 1 ))    
       begin    
         set @temp = 'Exists'     
    End       
   else    
    Begin    
        set @temp = 'Not Exists'    
    End    
    
    return @temp    
End
GO

