returns nvarchar(50)
as
Begin
    declare @temp nvarchar(50) = 'Not Exists' 
    if(exists(select 1 from leadsettings where (DIDNo = @DID or APPID = @APPID)  and  isnull(Mode,'') = 'OutboundCalls'  and  ISNULL(Status,0) = 1 ))
       begin
	        set @temp = 'Exists' 
	   End   
	  else
	   Begin
	       set @temp = 'Not Exists'
	   End

	   return @temp
End
