CREATE   FUNCTION [dbo].[funcToGetEnquiryIDLeadIDUserID]
(
  @refTable nvarchar(200),
  @refID nvarchar(200)
)
returns  nvarchar(500)
as
Begin
      Declare @En_LD_UD nvarchar(500) = '' 
      
	  if(@refTable = 'tbl_LeadEventHistory')
	     Begin
	         select top 1 @En_LD_UD = CAST(isnull(LeadID,0) as nvarchar) from tbl_LeadEventHistory(nolock)
			  where HistoryID = @refID 
		 End 
       else if(@refTable = 'tbl_EnquiryEventHistory')
	    Begin
			 
		 Select top 1 @En_LD_UD = Cast(isnull(EnquiryID,0) as nvarchar) from tbl_EnquiryEventHistory(nolock) where HistoryID = @refID 
		
		end
	   else if(@refTable = 'tbl_UserEventHistory')
	    Begin
	       select top 1 @En_LD_UD = Cast(isnull(UserID,0) as nvarchar) from tbl_UserEventHistory(nolock) where HistoryID = @refID 
		 end   
       else 
	    Begin
	      select top 1  @En_LD_UD = ''
	    End  
	 return @En_LD_UD
End
GO

/****** Object:  UserDefinedFunction [dbo].[funcToGetLastRun]    Script Date: 06-06-26 10:46:31 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetLastRun]
(
  @SMSCampaignID bigint,
  @MailCampaignID bigint,
  @VoiceCampaignID bigint,
  @WhatsappCampaignID bigint

)
returns  nvarchar(100)
Begin
      declare @LastRun nvarchar(100) = ''
	   
	  select  @LastRun =
	  
	    cast( Coalesce(
	             (select max(UCH.Step3DateTime) from MySMSReport.dbo.usercampaignhistory(nolock) as UCH where UCH.CampaignID 
				    in (
					   
					   isnull(@SMSCampaignID,0),
					   isnull(@MailCampaignID,0),
					   isnull(@VoiceCampaignID,0),
					   isnull(@WhatsappCampaignID,0)  )
					   
				 ),
				 (
				  select max(Step3DateTime) from MySMSReport.dbo.UserCampaignHistory_Archive(nolock)  where CampaignID 
				    in (
					   
					   isnull(@SMSCampaignID,0),
					   isnull(@MailCampaignID,0),
					   isnull(@VoiceCampaignID,0),
					   isnull(@WhatsappCampaignID,0)  )
				 
				 )
				 ,
				 (
				  select max(Step3DateTime) from MySMSReport.dbo.UserCAmpaignHistoryold(nolock)  where CampaignID 
				    in (
					   
					   isnull(@SMSCampaignID,0),
					   isnull(@MailCampaignID,0),
					   isnull(@VoiceCampaignID,0),
					   isnull(@WhatsappCampaignID,0)  )
				 
				 )
				 ,
				 (
				  select max(Step3DateTime) from MySMS.dbo.UserCampaignHistory(nolock)  where CampaignID 
				    in (
					   
					   isnull(@SMSCampaignID,0),
					   isnull(@MailCampaignID,0),
					   isnull(@VoiceCampaignID,0),
					   isnull(@WhatsappCampaignID,0)  )
				 
				 )
				 ,
				 (
				  select max(ExecutionTime) from MySMS.dbo.UserCampaignExecutionHistory(nolock)  where CampaignID 
				    in (
					   
					   isnull(@SMSCampaignID,0),
					   isnull(@MailCampaignID,0),
					   isnull(@VoiceCampaignID,0),
					   isnull(@WhatsappCampaignID,0)  )
				 
				 )
	             , 'Never'
	  
	             )

			      as nvarchar(100)
				)
			  
	   
	  return @LastRun
End

GO

