/****** Object:  UserDefinedFunction [dbo].[funcToGetLastRun_New_includingsequence]    Script Date: 06-06-26 10:46:33 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetLastRun_New_includingsequence]       
(        
  @triggeredCampaignID bigint  
)        
returns  nvarchar(100)        
Begin        
declare @LastRun nvarchar(100),@SMSCampaignID bigint, @MailCampaignID bigint,@VoiceCampaignID bigint,      
  @WhatsappCampaignID bigint,@sequenceid bigint,@uchdate datetime,@seqdate datetime            
select @smscampaignid=smscampaignid,@MailCampaignID=mailcampaignid,@VoiceCampaignID=voicecampaignid,@WhatsappCampaignID=  
whatsappcampaignid,@sequenceid=sequenceid  
from triggeredcampaigns(nolock) where id=@triggeredcampaignid                          
  
select @uchdate=max(executiontime) from UserCampaignexecutionHistory(nolock) where campaignid in       
(isnull(@SMSCampaignID,0),      
        isnull(@MailCampaignID,0),      
        isnull(@VoiceCampaignID,0),      
        isnull(@WhatsappCampaignID,0)   )  
  
select @seqdate=max(processedat) from [10.0.0.135].MySMSConversations.dbo.tbl_wa_automationtasks with (nolock) where activityid  
is not null and ruleid=@triggeredcampaignid  
  
if @uchdate is null and @seqdate is not null  
select @LastRun=@seqdate  
  
if @uchdate is not null and @seqdate is null  
select @LastRun=@uchdate  
  
if @uchdate is null and @seqdate is null  
select @LastRun='Never'  
  
if @uchdate is not null and @seqdate is not null  
select @lastrun=[dbo].[fn_Max_date](@uchdate,@seqdate)   
  
   return @LastRun        
End

GO

