/****** Object:  UserDefinedFunction [dbo].[funcToGetScoreStatus]    Script Date: 06-06-26 10:46:34 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetScoreStatus](@LeadID bigint)
RETURNS nvarchar(200) AS
BEGIN
    declare @ScoreStatus nvarchar(200) = ''
	declare @ScoreSum numeric(18,2) = 0; 

    select  @ScoreSum = SUM(isnull(ScoreAdded,0)) from lead_score_history(nolock) where datediff(d,createdon,getdate()) <= 7 and leadid = @LeadID

	 if(@ScoreSum > 0)
	    Begin
		    set   @ScoreStatus = 'Green_Up' 
		End
      else if(@ScoreSum < 0)
	    Begin
		    set   @ScoreStatus = 'Red_Down' 
		End   

		
   if( @ScoreSum is null or @ScoreSum = 0 )
	  Begin

	     select  top 1  @ScoreSum = isnull(ScoreAdded,0) from lead_score_history(nolock) where  ISNULL(ScoreAdded,0) <> 0 and leadid = @LeadID order by id desc    
	  if(@ScoreSum > 0)
	    Begin
		    set   @ScoreStatus = 'Gray_Up' 
		End
      else if(@ScoreSum < 0)
	    Begin
		    set   @ScoreStatus = 'Gray_Down' 
			 
		End     			

     End

    RETURN @ScoreStatus
END;
GO

/****** Object:  UserDefinedFunction [dbo].[funcToGetScoreStatus_New]    Script Date: 06-06-26 10:46:34 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetScoreStatus_New](@LeadID bigint)      
RETURNS nvarchar(200) AS      
BEGIN      
          
   declare @lastscoreupdate datetime,@lastscore int    
   declare @ScoreStatus nvarchar(200) = 'Green_Up'      
    
      select top 1 @lastscoreupdate=createdon,@lastscore=scoreadded from lead_score_history(nolock) where leadid=@leadid order by id desc      
    
      select  @ScoreStatus  =           
     isnull(( case         
    when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)>0 then 'Green_Up'         
    when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)<0 then 'Red_Down'        
    when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)=0 and @lastscore>0 then 'Green_Up'        
    when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)=0 and @lastscore<0 then 'Red_Down'         
    when  datediff(dd,@lastscoreupdate,getdate()) > 7 and @lastscore>0 then 'Grey_Up'        
    when  datediff(dd,@lastscoreupdate,getdate()) > 7 and @lastscore<0 then 'Grey_Down'        
     end ),'' )  
              
   from lead_score_history (nolock) where leadid=@leadid     
    
    
 --   declare @ScoreStatus nvarchar(200) = ''      
 --declare @ScoreSum numeric(18,2) = 0;       
      
 --   select  @ScoreSum = SUM(isnull(ScoreAdded,0)) from lead_score_history(nolock) where datediff(d,createdon,getdate()) <= 7 and leadid = @LeadID      
      
 -- if(@ScoreSum > 0)      
 --    Begin      
 --     set   @ScoreStatus = 'Green_Up'       
 -- End      
 --     else if(@ScoreSum < 0)      
 --    Begin      
 --     set   @ScoreStatus = 'Red_Down'       
 -- End         
      
        
 --  if( @ScoreSum is null or @ScoreSum = 0 )      
 --  Begin      
      
 --     select  top 1  @ScoreSum = isnull(ScoreAdded,0) from lead_score_history(nolock) where  ISNULL(ScoreAdded,0) <> 0 and leadid = @LeadID order by id desc          
 --  if(@ScoreSum > 0)      
 --    Begin      
 --     set   @ScoreStatus = 'Gray_Up'       
 -- End      
 --     else if(@ScoreSum < 0)      
 --    Begin      
 --     set   @ScoreStatus = 'Gray_Down'       
          
 -- End              
      
 --    End    
       
      
    RETURN @ScoreStatus      
END;
GO

/****** Object:  UserDefinedFunction [dbo].[funcToGetSearchFilterByCriteriaID]    Script Date: 06-06-26 10:46:34 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetSearchFilterByCriteriaID]   
(  
  @CriteriaID bigint,  
  @AndorOR nvarchar(20)      
)  
RETURNS nvarchar(max)  
     AS   
  BEGIN  
         
   Declare @abc nvarchar(max) = ''   
  
      select  @abc = (  
        select  
       stuff  
        (   
      (select ' '+@AndorOR+' ' + tbl.ColumnName + ' ' + REPLACE(replace(Operator,'&lt;', '<'),'&gt;', '>') + ' ' + tbl.Value from  
           (select ColumnName,Operator,Value from ProductSearchCondition(nolock) where CriteriaID = @CriteriaID) as tbl  
           FOR XML PATH('')), 1, 4 ,'')  
         )  
  
    set @abc =  REPLACE(replace(@abc,'&lt;', '<'),'&gt;', '>')       
     
      RETURN @abc  
  END  
GO

/****** Object:  UserDefinedFunction [dbo].[funcToGetThresholdColor]    Script Date: 06-06-26 10:46:35 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[funcToGetThresholdColor](@LeadID 
bigint)
returns nvarchar(200) as
Begin
     
  declare @ThresholdColor nvarchar(200) = 'Cold'
  
  select @ThresholdColor =
  case when [dbo].[fn_getrelativescore](@LeadID)>=isnull(l.Warm,(select Warm from lead_cateogy_thresholds(nolock) where parentid=0)) then 'Hot'    
  when [dbo].[fn_getrelativescore](@LeadID) between isnull(l.Cold,(select cold from lead_cateogy_thresholds(nolock) where parentid=0))    
  and isnull(l.warm,(select warm from lead_cateogy_thresholds(nolock) where parentid=0)) then 'Warm' else 'Cold' end    
  
  from userleads(nolock) u    
  left join lead_cateogy_thresholds(nolock) l on u.parentid=l.parentid   
  where u.ID = @LeadID
	  
	  return   @ThresholdColor

End 
GO

