CREATE   FUNCTION [dbo].[GetAvailableBalanceForParent]  --- latest running
(
    @UserId BIGINT,
	@ServiceName NVARCHAR(25) = ''
)
RETURNS DECIMAL(18, 4)
AS
BEGIN
    DECLARE @ParentId BIGINT;
    DECLARE @BalanceAmount DECIMAL(18, 4);
    DECLARE @TotalReserved DECIMAL(18, 4);
	DECLARE @TotalReservedDeduct DECIMAL(18, 4);
    DECLARE @CreditTypeId BIGINT;
    DECLARE @Result DECIMAL(18, 4);

    SELECT TOP 1 
        @ParentId = ParentId FROM User_Detail (nolock) WHERE USER_ID = @UserId;

    IF @ParentId IS NULL
    BEGIN
        RETURN NULL; 
    END

    
    SELECT TOP 1 
        @BalanceAmount = Balance  FROM IntCredit_Details WHERE User_ID = @ParentId  ORDER BY Credit_ID DESC;

    IF @BalanceAmount IS NULL
    BEGIN
        RETURN NULL; 
    END
	SELECT TOP 1  @CreditTypeId = CreditTypeID FROM Price_Master_TypeCredit (NOLOCK)WHERE CreditName = @ServiceName;

    SELECT  @TotalReserved = SUM(Amount)FROM tbl_IntCreditReserveFunds (nolock) WHERE ParentId = @ParentId;

    IF @TotalReserved IS NULL
    BEGIN
        SET @TotalReserved = 0; 
    END

    IF (@BalanceAmount >= @TotalReserved)
    BEGIN
	SELECT  @TotalReservedDeduct = SUM(Amount)FROM tbl_IntCreditReserveFunds (NOLOCK) WHERE ParentId = @ParentId AND CreditTypeId <> @CreditTypeId;
		SET @Result = @BalanceAmount - @TotalReservedDeduct;

    --IF @Result < 0
    --BEGIN
    --    SET @Result = 0; 
    --END
        --SET @Result = @BalanceAmount;
    END
    --ELSE
    --BEGIN
    --    SET @Result = 0; 
    --END

    RETURN @Result;
END;

GO

