/****** Object:  UserDefinedFunction [dbo].[GetCountBasedOnCondition]    Script Date: 06-06-26 10:46:37 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[GetCountBasedOnCondition] (
	@tid BIGINT
)
RETURNS INT
AS
BEGIN
    DECLARE @eventid INT

    SELECT @eventid = eventid FROM triggeredcampaigns WITH (NOLOCK) WHERE id = @tid

    DECLARE @Count INT

    IF @eventid NOT IN (680, 681)
    BEGIN
        SELECT @Count = COUNT(1)
        FROM scheduledtodos s WITH (NOLOCK)
        INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON
            ((s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid) AND s.scheduledaction = 'campaign')
            OR (s.scheduledaction = 'AutomationRules' AND s.eventid = t.eventid)) and s.parentid = t.parentid
        WHERE t.id = @tid
    END
    ELSE
    BEGIN
        SELECT @Count = COUNT(1)
        FROM scheduledtodos s WITH (NOLOCK)
        INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON
            ((s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid)) AND s.scheduledaction = 'tcampaign')
				and s.parentid = t.parentid
        WHERE t.id = @tid
    END

    RETURN @Count
END

GO

