CREATE   FUNCTION [dbo].[GetEntityActionMappingCode] 
(
@dtEntityActionAllMappingMaster nvarchar(max)
)        
RETURNS VARCHAR(50)        
as begin 
declare @EntityActionMappingCode varchar(50)        
select @EntityActionMappingCode = EntityActionMappingCode from openjson(@dtEntityActionAllMappingMaster)
with
(
	ModuleCode varchar(50) '$.ModuleCode',
	[Add] bit '$.Add',
	Edit bit '$.Edit',
	[View] bit '$.View',
	[Delete] bit '$.Delete',
	Search bit '$.Search',
	Import bit '$.Import',
	Export bit '$.Export',
	MassUpdate bit '$.MassUpdate',
	MassDelete bit '$.MassDelete') t , TBL_UA_EntityActionMappingMaster team
where team.[Add] = t.[Add] and team.Edit = t.Edit 
	   and team.[View] = t.[View] and team.[Delete] = t.[Delete] and team.Search = t.Search and team.Import = t.Import 
	   and team.Export = t.Export and team.MassUpdate = t.MassUpdate and team.MassDelete = t.MassDelete 
return @EntityActionMappingCode;        
END
