CREATE   FUNCTION [dbo].[GetNameIdList](@Id bigint, @Type VARCHAR(20))
RETURNS NVARCHAR(MAX)
as
Begin
DECLARE @Branch NVARCHAR(MAX)
SELECT @Branch = ''
--Declare @AttendanceGroupId bigint = 1
--Declare @Type varchar(10) = ''
--set @Type = 'Name'
if(@Type = 'Name')
Begin
select @Branch = COALESCE(@Branch + ',' ,'') + isnull(IUBranch.name, '') from TBL_ET_AttendanceGroupBranchMapping(nolock) agbm 
inner join tbl_inv_UserTaxNumber(nolock) IUBranch on agbm.BranchId = IUBranch.id
where agbm.AttendanceGroupId = @Id

--select @Branch
End
if(@Type = 'Id')
Begin
--set @Type = 'Id'

select @Branch = COALESCE(@Branch + ',' ,'') + cast(IUBranch.id as varchar(10)) from TBL_ET_AttendanceGroupBranchMapping(nolock) agbm 
inner join tbl_inv_UserTaxNumber(nolock) IUBranch on agbm.BranchId = IUBranch.id
where agbm.AttendanceGroupId = @Id

--select @Branch
End
if(@Type = 'UserMapName')
Begin
--set @Type = 'Id'

select @Branch = COALESCE(@Branch + ',' ,'') + Concat(IUDt.FName, ' ', cast(IUDt.LName as varchar(50))) from 
TBL_ET_AttendanceGroupUserMapping(nolock) agum 
inner join User_Detail (nolock) IUDt on agum.UserId = IUDt.User_id
where agum.AttendanceGroupId = @Id

--select @Branch
End
if(@Type = 'UserMapId')
Begin
--set @Type = 'Id'

select @Branch = COALESCE(@Branch + ',' ,'') + cast(IUDt.User_Id as varchar(50)) from 
TBL_ET_AttendanceGroupUserMapping(nolock) agum 
inner join User_Detail (nolock) IUDt on agum.UserId = IUDt.User_id
where agum.AttendanceGroupId = @Id

--select @Branch
End

return @Branch
End

