CREATE   FUNCTION [dbo].[GetNumbersFromText]    
(@String varchar(2000))    
returns nvarchar(100) --bigint    
as    
begin    
    
DECLARE     
@start int,    
@end nvarchar(100), --bigint,    
@len int    
    
--SET @string = 'mobile765432'    
set @string = replace(@string, ' ' , '')    
set @len = len(@string)    
    
set @start = PATINDEX('%[0-9]%',@string)    
if @start > 0    
set @end = substring(@string, @start, @len)    
else  
set @end =  @start  
  
return @end  
end    
GO

