/****** Object:  UserDefinedFunction [dbo].[GetQueryStringValue]    Script Date: 06-06-26 10:46:41 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[GetQueryStringValue] (
    @Url NVARCHAR(MAX),
    @Key NVARCHAR(100)
)
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @SearchPattern NVARCHAR(200) = @Key + '='
    DECLARE @Start INT = CHARINDEX(@SearchPattern, @Url)

    IF @Start = 0 RETURN NULL

    SET @Start = @Start + LEN(@SearchPattern)

    DECLARE @End INT = CHARINDEX('&', @Url, @Start)
    IF @End = 0 SET @End = LEN(@Url) + 1

    RETURN SUBSTRING(@Url, @Start, @End - @Start)
END

GO

