/****** Object:  UserDefinedFunction [dbo].[getShiftNameByDate]    Script Date: 06-06-26 10:46:42 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[getShiftNameByDate]
(@Date date,
@UserId bigint)
RETURNS VARCHAR(30)
AS
BEGIN
Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @UserId  
Declare @WeekDayName varchar(10), @String varchar(30)
set @WeekDayName = DATENAME(WEEKDAY, @Date)

Select top 1 @String = case when (case when @WeekDayName = 'Monday' then sfum.IsMonday 
      when @WeekDayName = 'Tuesday' then sfum.IsTuesday 
	  when @WeekDayName = 'Wednesday' then sfum.IsWednesday 
	  when @WeekDayName = 'Thursday' then sfum.IsThursday 
	  when @WeekDayName = 'Friday' then sfum.IsFriday 
	  when @WeekDayName = 'Saturday' then sfum.IsSaturday 
	  when @WeekDayName = 'Sunday' then sfum.IsSunday 
	  else 0 end) = 1 then sfma.ShiftName
	  else null end
from TBL_ET_ShiftUserMapping (nolock) sfum 
inner join TBL_ET_ShiftMaster (nolock) sfma on sfum.ShiftId = sfma.ShiftId 
where sfum.UserId = @UserId and cast(FromDate as date) <= cast(@Date as Date)

RETURN @String

End

GO

