/****** Object:  UserDefinedFunction [dbo].[HaversineDistance]    Script Date: 06-06-26 10:46:43 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[HaversineDistance] (
    @lat1 FLOAT,
    @lon1 FLOAT,
    @lat2 FLOAT,
    @lon2 FLOAT
)
RETURNS FLOAT
AS
BEGIN
    DECLARE @radius FLOAT;
    SET @radius = 6371; -- Earth's radius in kilometers

    DECLARE @dLat FLOAT = RADIANS(@lat2 - @lat1);
    DECLARE @dLon FLOAT = RADIANS(@lon2 - @lon1);
    DECLARE @a FLOAT = SIN(@dLat / 2) * SIN(@dLat / 2) +
                      COS(RADIANS(@lat1)) * COS(RADIANS(@lat2)) *
                      SIN(@dLon / 2) * SIN(@dLon / 2);
    DECLARE @c FLOAT = 2 * ATN2(SQRT(@a), SQRT(1 - @a));
    DECLARE @distance FLOAT = @radius * @c;

    RETURN @distance;
END;

GO

