        --select dbo.lastagentattended ('1614089194.61198')    
CREATE   FUNCTION [dbo].[lastagentattended] --('1610011434.3766586')      
(@uid VARCHAR(50))                        
RETURNS NVARCHAR(100)                        
as               
begin                  
--declare @uid VARCHAR(50)='1583739575.1601'          
declare @parentid bigint= (select isnull(clientid,(select top 1 parentid from cloud_user_phone (nolock) where phoneno=dnid and Active=1)) from Kit19Calls(nolock) where uniqueid=@uid)                    
declare @agent nvarchar(100)              
DECLARE @status TABLE                      
 (                      
    rn INT,                      
    dialstatus nvarchar(100),              
    agent nvarchar(100)                     
 )                    
 insert into @status                 
 select ROW_NUMBER() over(order by k.id desc) as rn, case when call_answer_time is not null then 'ANSWER' else dialstatus end ,isnull(user_login+' ( '+isnull(fname,'')+' '+ISNULL(lname,'')+' )' ,'') from 
 (select u.*,cloud_no,cloud_countrycode from user_detail(nolock) u left join cloud_call_no cc(nolock) on u.user_id=cc.user_id) u       
 right join Kit19CallsDialled(nolock) k on       
 dbo.fn_trim0prefix(agentnumber)=case when agenttype='mobile' then isnull(cloud_no,str(mobile)) else cast(user_id as nvarchar(50)) end      
 /*      
 str(mobile)=right(callerid,len(callerid)-charindex('/',callerid,5))          
or 'local/'+ltrim(rtrim(str(mobile)))+'@setcalleridpstn/n'= callerid          
or  'local/'+cast(user_id as nvarchar)+'@setcallerid/n'= callerid          
 */      
 where puniqueid=@uid and parentid=@parentid order by k.id desc;              
declare @cnt int,@rn int              
select @cnt=COUNT(rn) from @status               
if @cnt=0              
begin              
set @agent=''              
end                    
else if(@cnt>0)                        
begin                      
if exists(select 1 from @status where dialstatus='ANSWER')              
begin                       
select top 1 @agent=agent from @status where dialstatus='ANSWER' order by rn               
end              
else               
begin              
select top 1 @agent=agent from @status order by rn               
end              
end             
--select @agent =dbo.fn_trim0prefix(@agent)          
return isnull(@agent,'');                        
END
GO

