SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[Price_GetMailCost] 
(
 @mcount int,
 @userId int,
 @optType nvarchar(10)
)
RETURNS decimal(18,4)    
AS    
BEGIN
declare @Actualbalance decimal(18,4),@price decimal(18,4),@OriginCountryID int   
      
--select top 1 @Actualbalance = Balance from dbo.IntCredit_Details where USER_ID = @userid            
-- order by Credit_ID desc   

select @OriginCountryID=Country_ID from user_detail  where User_ID=@userID   

if @optType = 'mail' 
begin
set @price=  
(  
select Price from Price_Base_Mail_Rate_Exception where OriginCountryId=@OriginCountryID and USERID=@userid  
union  
select Price from Price_Base_Mail_Rate where OriginCountryId=@OriginCountryID  
) 

set @Actualbalance =@price * @mcount
end --end of mail
else if @optType = 'landingpage'
Begin
set @price=  
(  
select Price from Price_Base_LandingPage_Rate_Exception where OriginCountryId=@OriginCountryID and USERID=@userid  
union  
select Price from Price_Base_LandingPage_Rate where OriginCountryId=@OriginCountryID  
) 



set @Actualbalance =@price
End ----end of landing page
 

 RETURN  @Actualbalance 
 end

GO

/****** Object:  UserDefinedFunction [dbo].[Price_GetSMSCost]    Script Date: 06-06-26 10:46:47 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[Price_GetSMSCost] 
(
 @message nvarchar(max)='',  
  @unicode bit=0,
  @price decimal(18,4)
)
RETURNS decimal(18,4)    
AS    
BEGIN
 declare @Credit decimal(18,4), @len int          
          
 select @len = len(@message)          
   ,@Credit = (case when @unicode=0 and len(@message)<=160  then 1           
   when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))           
   when @unicode=1           
   and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end ) ,          
   @price = (case when @unicode=0 and len(@message)<=160  then 1           
   when @unicode=0 and LEN(@message)>160 then ceiling(LEN(@message)/cast(153 as FLOat))           
   when @unicode=1           
   and len(@message)<=70 then 1 else ceiling(LEN(@message)/cast(67 as float)) end )*@price          

 RETURN  @price 
 end

GO

/****** Object:  UserDefinedFunction [dbo].[RemoveExtraSpaces]    Script Date: 06-06-26 10:46:47 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO



CREATE   FUNCTION [dbo].[RemoveExtraSpaces] (@Input NVARCHAR(MAX))
RETURNS NVARCHAR(MAX)
AS
BEGIN
    DECLARE @Output NVARCHAR(MAX);
    
    -- Step 1: Trim leading and trailing spaces
    SET @Input = LTRIM(RTRIM(@Input));
    
    -- Step 2: Replace multiple spaces with a single space
    WHILE CHARINDEX('  ', @Input) > 0
    BEGIN
        SET @Input = REPLACE(@Input, '  ', ' ');
    END
    
    -- Set the final cleaned string as output
    SET @Output = @Input;
    
    RETURN @Output;
END;

GO

/****** Object:  UserDefinedFunction [dbo].[RemoveNonASCII]    Script Date: 06-06-26 10:46:48 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[RemoveNonASCII] 
(
    @nstring nvarchar(255)
)
RETURNS varchar(255)
AS
BEGIN

    DECLARE @Result varchar(255)
    SET @Result = ''

    DECLARE @nchar nvarchar(1)
    DECLARE @position int

    SET @position = 1
    WHILE @position <= LEN(@nstring)
    BEGIN
        SET @nchar = SUBSTRING(@nstring, @position, 1)
        --Unicode & ASCII are the same from 1 to 255.
        --Only Unicode goes beyond 255
        --0 to 31 are non-printable characters
        IF UNICODE(@nchar) between 32 and 255
            SET @Result = @Result + @nchar
        SET @position = @position + 1
    END

    RETURN @Result

END

GO

/****** Object:  UserDefinedFunction [dbo].[RETURNPERCENTAGE]    Script Date: 06-06-26 10:46:48 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[RETURNPERCENTAGE](@MSGCOUNT INT,@PER INT,@dnd int)  
RETURNS INT  
AS  
BEGIN  
DECLARE @COUNT INT  
DECLARE @removeDND int  

SET @MSGCOUNT=@MSGCOUNT-@dnd

SET @COUNT=CAST(((@MSGCOUNT*@PER)/100) AS INT)  
if 0>(@COUNT)  
BEGIN  
SET @removeDND= 0  
END  
ELSE  
BEGIN  
SET @removeDND= @COUNT  
END  
RETURN @removeDND  
END
GO

