CREATE   FUNCTION [dbo].[ReturnTotalRow](@tbl_name varchar(50))
returns bigint
as
BEGIN
declare @rowcount bigint
SELECT @rowcount= max(sysindexes.[rows])  
FROM sysindexes INNER JOIN sysobjects ON sysindexes.[id] = sysobjects.[id] 
WHERE sysobjects.[name] = @tbl_name 
GROUP BY sysobjects.[name] 
return @rowcount
END
GO

