CREATE   FUNCTION [dbo].[udf_ce_GetEntityActivityDiscription](
	@InterationTable nvarchar(255),
	@InteractionId bigint
)
returns nvarchar(max)
begin
	declare @eventDescription nvarchar(max) = ''

	if(lower(trim(@InterationTable)) = 'tbl_LeadEventHistory')
	begin
		select top 1 @eventDescription = EventDescription from tbl_LeadEventHistory(nolock) 
			where Historyid = @InteractionId
	end

	if(lower(trim(@InterationTable)) = 'tbl_EnquiryEventHistory')
	begin
		select top 1 @eventDescription = EventDescription from tbl_EnquiryEventHistory(nolock) 
			where Historyid = @InteractionId
	end

	return @eventDescription
end

