GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_ef_GetUserLocattionAddress](
	@UserId bigint,
	@Latitude float,
	@Longitude float	
) 
returns nvarchar(255)
begin
	declare @AddressText nvarchar(255) = ''
	select @AddressText = [Address] from TBL_ET_UserLocationTracking(nolock) 
		where UserId = @UserId 
			and Latitude = @Latitude
			and Longitude = @Longitude

	if(ISNULL(@AddressText, '') = '')
	begin
		select @AddressText = [Address] from TBL_ET_UserLocationTracking_Archived(nolock) 
		where UserId = @UserId 
			and Latitude = @Latitude
			and Longitude = @Longitude
	end

	return @AddressText
end

GO

/****** Object:  UserDefinedFunction [dbo].[udf_em_ReplaceValueOfEmailBody]    Script Date: 06-06-26 10:46:50 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_em_ReplaceValueOfEmailBody](
	@MessageId  nvarchar(255),
	@EmailMessageBody nvarchar(max)
)
returns nvarchar(max)
begin
	
	declare @EmailId nvarchar(255), @UserId bigint

	select @EmailId = e.ToAddr, @UserId = ecs.UserId from MySMST.dbo.Tbl_Email(nolock) e
	inner join  MySMST.dbo.Tbl_EmailConnectionSettings(nolock)  ecs on e.EmailConnectionId = ecs.Id
		where e.MessageId = @MessageId

	select @EmailMessageBody = REPLACE(REPLACE(@EmailMessageBody, '#PersonName#', PersonName), '#CreatedOn#', CreatedOn)
	from MySMS.dbo.UserLeads(nolock) ul
	inner join MySMS.dbo.User_Detail(nolock) ud on ul.ParentId = ud.ParentID
	 where ud.User_ID = @UserId and ( ul.EmailID = @EmailId or ul.EmailID1 = @EmailId or ul.EmailID2 = @EmailId )


	return @EmailMessageBody
end
GO

/****** Object:  UserDefinedFunction [dbo].[udf_es_GetCategoryNameInCsv]    Script Date: 06-06-26 10:46:50 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_es_GetCategoryNameInCsv] (  
 @CategoryName nvarchar(255),  
 @UserId bigint  
)  
RETURNS NVARCHAR(MAX)  
AS
BEGIN
	--declare @CategoryName nvarchar(255) = 'SAFE WASH LIQUIED DETERGENT',  @UserId bigint = 25254
  
	  
        DECLARE @String NVARCHAR(MAX)= '';  
        DECLARE @CategoryId BIGINT= 0;  
          
  SELECT @CategoryId = CategoryID,   @String = CONCAT('''', LTRIM(RTRIM([Name])), '''') FROM Categories WHERE [name] = @CategoryName
      AND User_id = @UserId;  

	  --PRINT @CategoryId

  WHILE(@CategoryId > 0)  
  BEGIN  
        DECLARE @ParentCategoryId BIGINT= 0, @cName NVARCHAR(MAX);  
                  
		SELECT @ParentCategoryId = pc.CategoryID, @cName = Name FROM Categories pc   WHERE pc.ParentCategory = @CategoryId;

		IF(@ParentCategoryId > 0)
			begin
				SET @String = CONCAT(@String, ', ''',  @cName, '''') 
				SET @CategoryId = @ParentCategoryId;  
			end
		ELSE  
			begin
				SET @CategoryId = 0
			end
	END
  
  return @String  
END;  
  


