/****** Object:  UserDefinedFunction [dbo].[udf_et_GetAgentWorkHours]    Script Date: 06-06-26 10:46:51 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_et_GetAgentWorkHours](  
 @UserId bigint,  
 @PunchedDate date  
)  
returns nvarchar(50)  
as  
begin  
	declare @WorkHour nvarchar(50) = ''  

	if(cast(@PunchedDate as date) <= DATEADD(day, -30, getdate()))
	begin
		SELECT @WorkHour = FORMAT(CAST(DATEADD(MINUTE, SUM(DATEDIFF(MINUTE, LagDate, LocationDateTime)), 0 ) AS DATETIME), 'HH:mm:ss') 
		FROM (select *,  
			LAG(LocationDateTime, 1, 0) OVER ( PARTITION BY SNO ORDER BY UserLocationTrackingId asc ) as [LagDate]  
			from (select UserLocationTrackingId, UserId, LocationDateTime, MovementCode,  
			ROW_NUMBER() over (partition by MovementCode, UserId, LocationDateTime   
			order by UserLocationTrackingId ) as sno  
			from TBL_ET_UserLocationTracking_Archived(nolock) where UserId = @UserId  
			and cast(LocationDateTime as date) = cast(@PunchedDate as date)   
			and MovementCode in ('SIGN_IN', 'SIGN_OUT') ) t where t.sno = 1  
			) B  WHERE B.MovementCode = 'SIGN_OUT'   group by  B.UserId  	
	end
	else
	begin
		SELECT @WorkHour = FORMAT(CAST(DATEADD(MINUTE, SUM(DATEDIFF(MINUTE, LagDate, LocationDateTime)), 0 ) AS DATETIME), 'HH:mm:ss') 
		FROM (select *,  
			LAG(LocationDateTime, 1, 0) OVER ( PARTITION BY SNO ORDER BY UserLocationTrackingId asc ) as [LagDate]  
			from (select UserLocationTrackingId, UserId, LocationDateTime, MovementCode,  
			ROW_NUMBER() over (partition by MovementCode, UserId, LocationDateTime   
			order by UserLocationTrackingId ) as sno  
			from TBL_ET_UserLocationTracking(nolock) where UserId = @UserId  
			and cast(LocationDateTime as date) = cast(@PunchedDate as date)   
			and MovementCode in ('SIGN_IN', 'SIGN_OUT') ) t where t.sno = 1  
			) B  WHERE B.MovementCode = 'SIGN_OUT'   group by  B.UserId  	
	end
	return @WorkHour  
end

GO

/****** Object:  UserDefinedFunction [dbo].[udf_et_GetPhyAppointmentTravelData]    Script Date: 06-06-26 10:46:51 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_et_GetPhyAppointmentTravelData](  
 @UserId bigint,  
 @TraveDate date,  
 @PhyAppointId bigint  
)  
returns nvarchar(max)  
as    
begin  
  
 --declare   
 -- @UserId bigint = 43966,  
 -- @TraveDate date = '11-Nov-2024 12:42',  
 -- @PhyAppointId bigint =  57221 --69 --, 87  
  
 declare @json nvarchar(max) = '{}'  
  
 set @json = ( 
 select  top 1
 a.PhysicalAppointmentId,
 a.sno,
  TRY_CONVERT(decimal(18, 3), isnull(ROUND((case 
	when a.sno = 1 and a.cs = 'B' then   
		   ( geography::Point(a.PreLatitudeIn, a.PreLongitudeIn, 4326)
			.STDistance(geography::Point(a.LatitudeIn, a.LongitudeIn, 4326))  
			) 
	when a.sno >= 2 and a.cs = 'B' 
		then 
		( geography::Point(a.PreLatitudeOut, a.PreLongitudeOut, 4326)
			.STDistance(geography::Point(a.LatitudeIn, a.LongitudeIn, 4326))  
  ) end / 1000 ), 2), 0))as [Distance],  

  datediff(minute, a.PreCheckIn, a.CheckIn) as [TimeTaken],  
  --(case when a.sno = 1 and a.cs = 'B' then   
  --  dbo.udf_GetAddressByCordinates(a.PreLatitudeIn, a.PreLongitudeIn)  
  -- when a.sno >= 2 and a.cs = 'B' then   
  --  dbo.udf_GetAddressByCordinates(a.PreLatitudeOut, a.PreLongitudeOut)  
  -- end ) as [FromAddress],  
  --dbo.udf_GetAddressByCordinates(a.LatitudeIn, a.LongitudeIn) as [ToAddress],  
  --dbo.udf_GetAddressByCordinates(a.LatitudeOut, a.LongitudeOut) as [CheckOutAddress],  
  FORMAT(case when a.sno = 1 and a.cs = 'B' then   
    a.PreCheckIn  
   when a.sno >= 2 and a.cs = 'B' then   
    a.PreCheckOut  
   end , 'hh:mm tt') as [CheckIn],  
  FORMAT(a.CheckIn, 'hh:mm tt') as [CheckOut]  
 from (  
 select   
  *,  
  LAG(CheckIn, 1,0) OVER (ORDER BY CheckIn asc) as [PreCheckIn],  
  LAG(CheckOut, 1,0) OVER (ORDER BY CheckIn asc) as [PreCheckOut],  
  LAG(LatitudeIn, 1,0) OVER (ORDER BY CheckIn asc) as [PreLatitudeIn],  
  LAG(LongitudeIn, 1,0) OVER (ORDER BY CheckIn asc) as [PreLongitudeIn],  
  LAG(LatitudeOut, 1,0) OVER (ORDER BY CheckIn asc) as [PreLatitudeOut],  
  LAG(LongitudeOut, 1,0) OVER (ORDER BY CheckIn asc) as [PreLongitudeOut]  
 from (  
  select *,   
  row_number() over ( partition by d.UserId order by d.cs ) as [sno] from (  
   select cast(0 as bigint) as PhysicalAppointmentId, AttendanceIn as [CheckIn], AttendanceOut as [CheckOut], isnull(LatitudeIn, 0) [LatitudeIn], isnull(LongitudeIn, 0) [LongitudeIn],  isnull(LatitudeOut, 0) [LatitudeOut], isnull(LongitudeOut, 0) [LongitudeOut],'A' as [cs], UserId  from v_TBL_ET_Attendance(nolock)   
   where UserId = @UserId and cast(AttendanceIn as date) = @TraveDate  
  union  
   select   
   PhysicalAppointmentId, CheckIn,CheckOut, isnull(LatitudeIn, 0) [LatitudeIn], isnull(LongitudeIn, 0) [LongitudeIn],  isnull(LatitudeOut, 0) [LatitudeOut], isnull(LongitudeOut, 0) [LongitudeOut],  
   'B' as [cs], UserId from TBL_ET_GeoEntityCheckInOut(nolock) where UserId = @UserId  
   and cast(CheckIn as date) = @TraveDate  
 ) d ) t ) a where a.PhysicalAppointmentId = @PhyAppointId for json path, without_array_wrapper )  
  
 return @json 

 --select @json 
   
end  

GO

