/****** Object:  UserDefinedFunction [dbo].[udf_fn_GetUserDetails]    Script Date: 06-06-26 10:46:52 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- exec Use_GetUserDetails @UserId=39702  
-- exec Use_GetUserDetails @UserId=31871  
-- exec Use_GetUserDetails @UserId=39330  
CREATE   FUNCTION [dbo].[udf_fn_GetUserDetails]
(  
 @UserID BIGINT         
) 
returns nvarchar(max)
AS         
BEGIN   

--Declare @UserID BIGINT = 42060         
    
 DECLARE @ParentId BIGINT = 0;                    
 DECLARE @IsAdmin bit = 0;                    
 Declare @TeamCode varchar(10) = ''         
 Declare @ScopeCode varchar(10) = ''         
 Declare @UserIdTeamLst varchar(4000) = ''         
 Declare @HierarchyJSON varchar(Max) = ''      
      
 SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;  
 
   
 if((@ParentId = @UserId or @IsAdmin = 1))      
 Begin     
  --print 'Parent or Admin'    
  
  SELECT 
	@UserIdTeamLst = STRING_AGG( ud.[User_ID], ',')
  --ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]         
  FROM User_Detail(nolock) AS ud       
  WHERE ud.[ParentId] = @ParentId and ud.status = 1         
  --order by User_Login asc         
 End      
 Else if Exists(select 1 from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId)       
 Begin       
 -- print 'User Hierarchy'    
  
  Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId  
  
  --drop table if Exists #TableData2  
  
  declare  @TableData2 as table ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint) 
  Insert into @TableData2 ([user_id], team_name, user_login,username,[parentid])  
  Select [user_id], '', user_login, username, [parentid]   
  from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)  
  
  If not exists(Select * from @TableData2 Where user_id=@UserID)  
  Begin  
   --print 'User does not exist in Hierarchy'    
   
   SELECT 
   @UserIdTeamLst = STRING_AGG( ud.[User_ID], ',')
   --ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]         
   FROM User_Detail(nolock) AS ud         
   WHERE ud.[User_ID] = @UserID    
  End  
  Else  
  Begin  
   --print 'User Hierarchy listing'    
  
   ;with CTE(user_id,team_name,user_login,username,parentid)  
   as   
   (  
    select user_id,team_name,user_login,username,parentid  
    from @TableData2 where User_id = @UserID  
    union all  
    -- recursively add children  
    select c.user_id,c.team_name,c.user_login,c.username,c.parentid  
    from @TableData2 c  
    join CTE on c.parentid = CTE.User_id  
   )  
  
   SELECT 
	@UserIdTeamLst = STRING_AGG( ud.[User_ID], ',')
	--ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]         
   FROM User_Detail(nolock) AS ud inner join CTE  
   ON ud.User_ID=CTE.user_id  
   WHERE ud.status = 1     
  
   --SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast(user_id as varchar(4000))  
   --from #TableData2 where (User_id = @UserId or parentid = @UserId or parentid in (select top 1 parentid from #TableData2 where User_id = @UserId))  
   --FOR XML PATH('')),1,1,'')  
  End  
  
  --, @UserIdTeamLst = ''  
  --select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId)  
  
  --select * from #TableData2  
  --select @UserIdTeamLst   
 End      
 Else      
 Begin      
  select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst   
  from ufn_GetUserRoleScope(@UserId)       
    
  --print '@ScopeCode=' + @ScopeCode    
  --print '@TeamCode=' + isnull(@TeamCode, '')    
  --print '@ParentId=' + cast(@ParentId as varchar(10))    
  --print '@UserId=' + cast(@UserId as varchar(10))    
  --print '@UserIdTeamLst=' + cast(@UserIdTeamLst as varchar)    
   
  if(@ScopeCode = 'TEAM')         
  Begin         
   SELECT @UserIdTeamLst = STRING_AGG( ud.[User_ID], ',') 
   --ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]         
   FROM User_Detail(nolock) AS ud         
   WHERE (ud.[User_ID] in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))) and ud.status = 1   
  End         
  Else         
  Begin         
   SELECT 
		--ud.[User_ID], ud.User_Login + ' ('+ ud.FName +' '+LName +')' [Name], [Image]         
	@UserIdTeamLst = STRING_AGG( ud.[User_ID], ',')
   FROM User_Detail(nolock) AS ud         
   WHERE ud.[User_ID]= @UserID and ud.status = 1     
  End       
 End      
  
  --select @UserIdTeamLst

  return @UserIdTeamLst

END

GO

/****** Object:  UserDefinedFunction [dbo].[udf_GetAddressByCordinates]    Script Date: 06-06-26 10:46:52 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_GetAddressByCordinates](
	@Latitude float,
	@Longigute float
)
returns nvarchar(255)
as
begin
	declare @address nvarchar(255) = '' 

	select top 1 @address = Address from TBL_ET_UserLocationTracking(nolock)
		where round(Latitude, 4) = ROUND(@Latitude, 4) and 
			round(Longitude, 4) = ROUND(@Longigute, 4)
	order by UserLocationTrackingId desc

	if(ISNULL(@address, '') = '')
	begin
		select top 1 @address = Address from TBL_ET_UserLocationTracking_Archived(nolock)
		where round(Latitude, 4) = ROUND(@Latitude, 4) and 
			round(Longitude, 4) = ROUND(@Longigute, 4)
	order by UserLocationTrackingId desc
	end
	
	return @address
end

GO

/****** Object:  UserDefinedFunction [dbo].[udf_getBreakTypeName]    Script Date: 06-06-26 10:46:52 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_getBreakTypeName](
	@UserId bigint = 32222,
	@BreakDateTime datetime = '2023-05-23 11:00:45.000'
)
returns nvarchar(255)
as
begin

	--declare 
	--	@UserId bigint = 32222,
	--	@BreakDateTime datetime = '2023-05-23 11:00:45.000'

	declare @ParentId bigint, @BreakTypeName nvarchar(255) = ''

	select @ParentId = ParentID from User_Detail(nolock) ud where User_ID = @UserId

	select top 1
		@BreakTypeName = BreakTypeName
	from TBL_ET_BreakTransaction(nolock) bt 
		inner join  TBL_ET_BreakTypeMaster(nolock) bm on bt.BreakTypeId = bm.BreakTypeId
	where bm.ParentId = @ParentId and cast(bt.StartDate as date) = cast(@BreakDateTime as date)
	order by ( case 
		when bt.StartDate < @BreakDateTime then datediff(second, bt.StartDate, @BreakDateTime)
		when bt.StartDate > @BreakDateTime then datediff(second, @BreakDateTime, bt.StartDate)
		end ) asc
	return @BreakTypeName
end

GO

/****** Object:  UserDefinedFunction [dbo].[udf_GetClosestUserLocation]    Script Date: 06-06-26 10:46:53 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_GetClosestUserLocation](    
 @UserId bigint,    
 @TravelDate datetime    
)    
returns nvarchar(max)    
as    
begin    
     
	--declare     
	--	@UserId bigint = 44304,    
	--	@TravelDate datetime = N'17-May-2024'
    
	declare @json nvarchar(max) = ''

	if(CAST(@TravelDate as date) <= CAST(getdate() as date))
	begin
		set @json = ( select top 1     
				isnull(LocationDateTime, '') as [LocationDateTime],    
				isnull(MovementCode, '') as [MovementCode],     
				isnull(BatteryPerc, 0) as [BatteryPerc],     
				isnull(NetworkPerc, 0) as[NetworkPerc],  
				isnull(Speed, 0) as [Speed],
				ROUND((  
				TRY_CONVERT(decimal(18,3), isnull((
					select MAX(cast(Distance as float)) from TBL_ET_UserLocationTracking(nolock) iu 
						where iu.UserId = @UserId and cast(iu.LocationDateTime as date) = cast(@TravelDate as date
				)) , 0)) / 1000),  
				3) as [Distance],  
				isnull(Address, '') as [Address]  
				from ( select ( case when @TravelDate < LocationDateTime then     
				DATEDIFF(SECOND, @TravelDate, LocationDateTime)    
				else DATEDIFF(SECOND, LocationDateTime, @TravelDate ) end )as [sec],     
				LocationDateTime, MovementCode, BatteryPerc, NetworkPerc, Speed, Distance, Address  
				from TBL_ET_UserLocationTracking_Archived(nolock) where UserId = @UserId     
				and cast(LocationDateTime as date) = cast(@TravelDate as date)
			) l order by l.sec asc for json auto, include_null_values, without_array_wrapper )         
	end

	if(isnull(@json, '') = '')
	begin
		if(exists(select 1 from TBL_ET_UserLocationTracking(nolock) where UserId = @UserId     
		  and cast(LocationDateTime as date) = cast(@TravelDate as date)))
		begin
			set @json = ( select top 1     
					isnull(LocationDateTime, '') as [LocationDateTime],    
					isnull(MovementCode, '') as [MovementCode],     
					isnull(BatteryPerc, 0) as [BatteryPerc],     
					isnull(NetworkPerc, 0) as[NetworkPerc],  
					isnull(Speed, 0) as [Speed],
					ROUND((  
					TRY_CONVERT(decimal(18,3), isnull((
						select MAX(cast(Distance as float)) from TBL_ET_UserLocationTracking(nolock) iu 
							where iu.UserId = @UserId and cast(iu.LocationDateTime as date) = cast(@TravelDate as date
					)) , 0)) / 1000),  
					3) as [Distance],  
					isnull(Address, '') as [Address]  
					from ( select ( case when @TravelDate < LocationDateTime then     
					DATEDIFF(SECOND, @TravelDate, LocationDateTime)    
					else DATEDIFF(SECOND, LocationDateTime, @TravelDate ) end )as [sec],     
					LocationDateTime, MovementCode, BatteryPerc, NetworkPerc, Speed, Distance, Address  
					from TBL_ET_UserLocationTracking(nolock) where UserId = @UserId     
					and cast(LocationDateTime as date) = cast(@TravelDate as date)
				) l order by l.sec asc for json auto, include_null_values, without_array_wrapper )         
		end
		else
		begin
			set @json = ( 
				select * from (select 
					@TravelDate as [LocationDateTime],    
					'' as [MovementCode],     
					0 as [BatteryPerc],     
					0 as[NetworkPerc],  
					0 as [Speed],  
					0 as [Distance],  
					'' as [Address]  ) ev
				for json auto, include_null_values, without_array_wrapper )
		end
	end
 
	--select @json
	return @json  
end

GO

