CREATE   FUNCTION [dbo].[udf_GetTerritoryDefination](  
 @UserId bigint  
)  
returns nvarchar(max)  
as  
begin  
 declare @managerName nvarchar(max) = ''  
 set @managerName = (select   
  concat( u.User_Login, '(', u.FName, ' ', u.LName, ')') as [DisplayName],  
  u.User_Login as [UserLogin],  
  u.User_Id as [UserId],  
  m.TerritoryName,  
  m.TerritoryId  
 from TBL_ET_TerritoryUserMapping(nolock) um  
 inner join TBL_ET_TerritoryMaster(nolock) m on um.TerritoryId = m.TerritoryId  
 inner join User_Detail(nolock) u on um.UserId = u.User_ID  
  where um.IsActive = 1 and um.IsManager = 1 and um.UserId = @UserId for json path )  
 return @managerName  
end

