CREATE   FUNCTION [dbo].[udf_GetTerritoryManagerName](
	@TerritoryId bigint
)
returns nvarchar(255)
as
begin
	declare @managerName nvarchar(max) = ''
	select 
		@managerName = concat(
			@managerName,
			iif(len(@managerName) > 0, ', ', ''),
			u.User_Login, '(', u.FName, ' ', u.LName, ')'
		) 
	from 
