/****** Object:  UserDefinedFunction [dbo].[udf_ims_GetAssoisatedEntityProfile]    Script Date: 06-06-26 10:46:55 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_ims_GetAssoisatedEntityProfile](
	@EntityName nvarchar(50),
	@EntityId bigint
)
returns nvarchar(max)
as
begin
	declare @EntityProfile table (
		EntityId bigint,
		LeadNo int,
		PersonName nvarchar(250),
		ProfileImgFileName nvarchar(250),
		ParentId bigint,
		EntiyName nvarchar(50)
	)

	declare @pofileJson nvarchar(max) = '{}';

	if(lower(@EntityName) = 'lead')
		begin
			insert into @EntityProfile ( EntityId, LeadNo, PersonName, ProfileImgFileName, ParentId, EntiyName )
				select ID, LeadNo, PersonName, ProfileImgFileName, ParentId, @EntityName
					from UserLeads(nolock) where ID = @EntityId
		end
	else if(lower(@EntityName) = 'enquiry')
		begin
			insert into @EntityProfile ( EntityId, LeadNo, PersonName, ProfileImgFileName, ParentId, EntiyName )
				select EnquiryID, LeadNo, PersonName, ProfileImgFileName, ParentId, @EntityName
					from Userenquiry(nolock) where EnquiryID = @EntityId
		end
	else
		begin
			insert into @EntityProfile ( EntityId, LeadNo, PersonName, ProfileImgFileName, ParentId, EntiyName )
				select top 1 EnquiryID, LeadNo, PersonName, ProfileImgFileName, ParentId, @EntityName
					from Userenquiry(nolock) where EnquiryID < 0
		end

	set @pofileJson = (select * from @EntityProfile for json path, WITHOUT_ARRAY_WRAPPER )
	
	return @pofileJson
end

GO

/****** Object:  UserDefinedFunction [dbo].[udf_ims_GetConvUserDetails]    Script Date: 06-06-26 10:46:55 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[udf_ims_GetConvUserDetails]
(
	@EntityId bigint,
	@EntityName nvarchar(255)
)
returns nvarchar(max)
as
begin
	declare @ProfileJOSN nvarchar(max)

	set @ProfileJOSN = case when @EntityName = 'conversationcontacts'
								then (select  id as [Id], personname as [PersonName], ProfileImgFileName, 'contact' as [Source],
										( IIF(LEN(TRIM(CONCAT(cast(CountryCode as nvarchar), cast(Mobile as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode as nvarchar)), '-', TRIM(cast(Mobile as nvarchar)), ' '), '')
 										) as MobileNo
									from conversationcontacts(nolock) where id = @EntityId for json auto )
							when @EntityName = 'user'
								then (select USER_ID as [Id], concat(ud.FName, ' ', ISNULL(ud.LName, '')) as [PersonName], ud.Image as ProfileImgFileName, 'user' as [Source],
									( IIF(LEN(TRIM(CONCAT(cast(ud.CountryCode as nvarchar), cast(ud.Mobile as nvarchar)))) > 0, 
										CONCAT(TRIM(cast(ud.CountryCode as varchar)), '-', replace(TRIM(cast(convert(varchar, cast(ud.Mobile as money), 0) as varchar(100))), '.00', ''), ' '), '')
 									) as MobileNo
										from channeltokens(nolock) ct inner join  User_Detail(nolock) ud  on ct.parentid = ud.User_ID where ct.id = @EntityId for json auto )
							when @EntityName = 'enquiry'
								then ( select EnquiryID as [Id], PersonName as [PersonName], ProfileImgFileName, 'enquiry' as [Source],
									CONCAT(
										IIF(LEN(TRIM(CONCAT(cast(CountryCode as nvarchar), cast(MobileNo as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode as nvarchar)), '-', TRIM(cast(MobileNo as nvarchar)), ' '), ''),
										IIF(LEN(TRIM(CONCAT(cast(CountryCode1 as nvarchar), cast(MobileNo1 as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode1 as nvarchar)), '-', TRIM(cast(MobileNo1 as nvarchar)), ' '), ''),
										IIF(LEN(TRIM(CONCAT(cast(CountryCode2 as nvarchar), cast(MobileNo2 as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode2 as nvarchar)), '-', TRIM(cast(MobileNo2 as nvarchar)), ' '), '')
 									) as MobileNo
								from UserEnquiry(nolock) where EnquiryID = @EntityId for json auto )
							when @EntityName = 'lead'
								then ( select ID as [Id], PersonName as [PersonName], ProfileImgFileName, 'lead' as [Source], 
									CONCAT(
										IIF(LEN(TRIM(CONCAT(cast(CountryCode as nvarchar), cast(MobileNo as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode as nvarchar)), '-', TRIM(cast(MobileNo as nvarchar)), ' '), ''),
										IIF(LEN(TRIM(CONCAT(cast(CountryCode1 as nvarchar), cast(MobileNo1 as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode1 as nvarchar)), '-', TRIM(cast(MobileNo1 as nvarchar)), ' '), ''),
										IIF(LEN(TRIM(CONCAT(cast(CountryCode2 as nvarchar), cast(MobileNo2 as nvarchar)))) > 0, 
											CONCAT(TRIM(cast(CountryCode2 as nvarchar)), '-', TRIM(cast(MobileNo2 as nvarchar)), ' '), '')
 									) as MobileNo
								from UserLeads(nolock) where ID = @EntityId for json auto)
							when @EntityName = 'team'
								then ( select ud.User_ID as [Id], concat(trim(ud.FName), ' ', trim(ud.LName)) as [PersonName], 
									Image as ProfileImgFileName, 'team' as [Source], 
										CONCAT(
											IIF(LEN(TRIM(CONCAT(cast(ud.wa_country_code as nvarchar), cast(ud.wa_mobile_no as nvarchar)))) > 0, 
												CONCAT(TRIM(cast(ud.wa_country_code as nvarchar)), '-', TRIM(cast(ud.wa_mobile_no as nvarchar)), ''), ''), '') as MobileNo
								from User_Detail(nolock) ud where User_ID = @EntityId for json auto)
							else
								''
								end
	return @ProfileJOSN
end

GO

