/****** Object:  UserDefinedFunction [dbo].[ufn_CheckLeadEnquiryFieldValue]    Script Date: 06-06-26 10:46:57 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- select dbo.ufn_CheckLeadEnquiryFieldValue(32222,'Lead','nextstatusdate','23-Sep-2031')  
CREATE   FUNCTION [dbo].[ufn_CheckLeadEnquiryFieldValue]  
(  
 @ParentId bigint,  
 @EntityType varchar(10),  
 @FieldName varchar(100),  
 @FieldValue nvarchar(max)  
)  
Returns bit  
AS  
Begin  
 -- declare @ParentId bigint=32222, @EntityType varchar(10)='Lead', @FieldName varchar(100)='createdon', @FieldValue nvarchar(max)='20-Dec-2015'  
  
 declare @result bit=0  
 if exists(Select * From customfields(nolock) Where ParentID=@ParentId and isActive=1 and fieldname=@FieldName)  
 Begin  
  Select @result=1   
  From customfields(nolock)  
  Where ParentID=@ParentId  
  and isActive=1  
  and fieldname=@FieldName  
  and @FieldValue=case when ISNULL(minvalue,'')='' then @FieldValue   
   else   
   (  
    case when datatype in ('v','m','c','e') then @FieldValue   
      when datatype='f' and cast(@FieldValue as float) >= cast(minvalue as float) then @FieldValue  
      when datatype='d' and cast(@FieldValue as date) >= cast(minvalue as date) then @FieldValue  
      when datatype in ('r','s','l') and @FieldValue in (select value from dbo.fn_Split(choices,',')) then @FieldValue  
      else null   
    end  
   ) end  
  and @FieldValue=case when ISNULL(maxvalue,'')='' then @FieldValue   
   else   
   (  
    case when datatype in ('v','m','c','e') then @FieldValue   
      when datatype='f' and cast(@FieldValue as float) <= cast(maxvalue as float) then @FieldValue  
      when datatype='d' and cast(@FieldValue as date) <= cast(maxvalue as date) then @FieldValue   
      when datatype in ('r','s','l') and @FieldValue in (select value from dbo.fn_Split(choices,',')) then @FieldValue  
      else null   
    end  
   ) end  
 End  
 Else  
 Begin  
  Select @result=1    
  from INFORMATION_SCHEMA.COLUMNS  
  Where TABLE_NAME=case lower(@EntityType) when 'lead' then 'UserLeads' when 'enquiry' then 'UserEnquiry' else @EntityType end  
    and COLUMN_NAME=@FieldName  
    and 1=(case when COLUMN_NAME='SourceName' then (Select 1 From UserSourceSettings(nolock) where SourceId=@FieldValue and UserId=@ParentId and IsActive=1) else 1 end)  
    and 1=(case when COLUMN_NAME='MediumName' then (Select 1 From UserMediumSettings(nolock) where MediumID=@FieldValue and UserId=@ParentId and IsActive=1) else 1 end)  
    and 1=(case when COLUMN_NAME='CampaignName' then (Select 1 From UserCampaignSettings(nolock) where CampaignID=@FieldValue and UserId=@ParentId and IsActive=1) else 1 end)  
    and 1=(case when COLUMN_NAME='City' then (Select distinct 1 From m_city1(nolock) where City_Name=@FieldValue) else 1 end)  
    and 1=(case when COLUMN_NAME='State' then (Select distinct 1 From m_State1(nolock) where State_Name=@FieldValue) else 1 end)  
    and 1=(case when COLUMN_NAME in ('Country','CountryCode','CountryCode1','CountryCode2') then (Select distinct 1 From m_country1(nolock) where Country_Name=@FieldValue or CountryCode=@FieldValue) else 1 end)  
    and 1=(case when COLUMN_NAME in ('CreatedBy','lastFollowupCreatedBy','AssignedTo','ModifiedBy') then (Select distinct 1 From User_detail(nolock) where User_Id=@FieldValue) else 1 end)  
	and 1=(case when COLUMN_NAME in ('EmailID','EmailID1','EmailID2') and @fieldvalue  LIKE '%_@__%.__%' AND PATINDEX('%[^a-z,0-9,@,.,_]%', REPLACE(@FieldValue, '-', 'a')) = 0 then 1 else 1 end)  
	and 1=(case when COLUMN_NAME in ('MobileNo','MobileNo1','MobileNo2') and dbo.fnGetNumericValue(@fieldvalue) = @fieldvalue and len(@fieldvalue) between 5 and 20 then 1 else 1 end)  
    and 1=case when DATA_TYPE in ('smallint','int','bigint','numeric','float','decimal') then ISNUMERIC(@FieldValue)  
     when DATA_TYPE in ('datetime','date','datetime2','smalldatetime') then ISDATE(@FieldValue)  
      else 1 end  
 End  
   
 --select @result  
 return @result  
  
End  
GO

/****** Object:  UserDefinedFunction [dbo].[ufn_es_GetOrderProductJson]    Script Date: 06-06-26 10:46:58 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[ufn_es_GetOrderProductJson] ( @OrderID bigint )
RETURNS NVARCHAR(MAX)
	BEGIN
		DECLARE @JsonData NVARCHAR(MAX)
		SET @JsonData = (SELECT * FROM( SELECT p.ProductId, p.Name as [ProductName], p.ImageUrl, od.UnitPrice, od.Quantity, od.TotalAmount, od.Variant, od.FulfillmentStatus, od.CancelOrder, od.ReturnOrder, od.OrderNo, od.ReturnDate, od.ExchangeDate, od.OrderDate  from Products p inner join OrderDetails od  on p.ProductID = od.ProductID
	where od.OrderID = @OrderID ) PRODUCT FOR JSON AUTO)
		RETURN @JsonData
	END

GO

/****** Object:  UserDefinedFunction [dbo].[ufn_FetchDataType]    Script Date: 06-06-26 10:46:58 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[ufn_FetchDataType]      
 (       
   @FieldName nvarchar(200),      
   @FieldType nvarchar(200),      
   @ParentID bigint = 0        
 )      
RETURNS nvarchar(200) AS      
BEGIN      
    Declare @DataType nvarchar(200) = ''      
 if(@FieldType = 'Enquiry')      
    begin      
        SELECT @DataType = DATA_TYPE       
   FROM INFORMATION_SCHEMA.COLUMNS      
   WHERE       
     TABLE_NAME = 'UserEnquiry' AND       
     COLUMN_NAME = @FieldName      
    end      
    else if(@FieldType = 'lead'  or @FieldType = 'common')      
     begin      
           SELECT @DataType = DATA_TYPE       
   FROM INFORMATION_SCHEMA.COLUMNS      
   WHERE       
     TABLE_NAME = 'UserLeads' AND       
           COLUMN_NAME = @FieldName      
   end           
    else if(@FieldType = 'Custom')      
    Begin      
        SELECT top 1 @DataType =                 
       UPPER((CASE datatype                
         WHEN 'd'                
         THEN 'DateTime'                
         WHEN 'f'                
         THEN 'Numeric'                
         WHEN 'v'                
         THEN 'VARCHAR'                
         WHEN 'm'                
         THEN 'VARCHAR'                
         WHEN 'e'                
         THEN 'VARCHAR'                
         WHEN 'r'                
         THEN 'VARCHAR'                
         WHEN 'c'                
         THEN 'VARCHAR'                
         WHEN 's'                
         THEN 'VARCHAR'                
        END))               
   FROM customfields NOCOUNT                
   WHERE [ParentID] = isnull(@ParentId,0)  and isActive = 1               
          and fieldname = @FieldName    
  end            
        
      
    RETURN isnull(@DataType,'')      
END;
GO

