/****** Object:  UserDefinedFunction [dbo].[ufn_IsEnquiryConflictsLead]    Script Date: 06-06-26 10:47:00 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- select dbo.ufn_IsEnquiryConflictsLead(2457956)
CREATE   FUNCTION [dbo].[ufn_IsEnquiryConflictsLead]
(
	@EnquiryId bigint
)
Returns Bit
As
Begin
	declare	@MobileNo varchar(100), @MobileNo1 varchar(100), @MobileNo2 varchar(100), @EmailID varchar(100), @EmailID1 varchar(100), 
		@EmailID2 varchar(100),@ParentID bigint,@RetVal bit=0;

	select	@MobileNo=IIf(isnull(MobileNo,'')='','m',MobileNo), 
			@MobileNo1=iif(isnull(MobileNo1,'')='','m1',MobileNo1), 
			@MobileNo2=iif(isnull(MobileNo2,'')='','m2',MobileNo2), 
			@EmailID=iif(isnull(EmailID,'')='','e',EmailID), 
			@EmailID1=iif(isnull(EmailID1,'')='','e1',EmailID1), 
			@EmailID2=iif(isnull(EmailID2,'')='','e2',EmailID2), 
			@ParentID=ParentID
	from	UserEnquiry(nolock)
	Where	EnquiryID=@EnquiryId;

	If exists(
	Select * from UserLeads(nolock) Where ParentID=@ParentID and ( isnull(MobileNo,'*') in (@MobileNo,@MobileNo1,@MobileNo2) or isnull(MobileNo1,'*') in (@MobileNo,@MobileNo1,@MobileNo2) or isnull(MobileNo2,'*') in (@MobileNo,@MobileNo1,@MobileNo2) or isnull(EmailID,'*') in (@EmailID,@EmailID1,@EmailID2) or isnull(EmailID1,'*') in (@EmailID,@EmailID1,@EmailID2) or isnull(EmailID2,'*') in (@EmailID,@EmailID1,@EmailID2) ) 
	)
	Begin
		Set @RetVal = 1
	End
	Else
	Begin
		Set @RetVal = 0
	End

	return @RetVal
End

GO

