CREATE   FUNCTION [dbo].[ufn_IsLeadInUse]    
(        
@LeadID bigint,    
@Mode varchar(20)
)        
returns nvarchar(max)
AS
BEGIN        
--ID, IDList, Parent, User, Import, Criteria         
 Declare @retval NVARCHAR(max)=''
 Declare @ParentID BIGINT        
 Declare @UserID BIGINT        
 DECLARE @sqlquery NVARCHAR(MAX);  

 select @ParentID = ParentID from UserLeads(Nolock) where ID = @LeadID        
 
 If @ParentID is null or @ParentID = 0
 Begin
	return @retval
 End
    
If exists(Select 1 from UserEnquiry (nolock) UE INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'UserEnquiry',',')  
End    
    
If exists(SELECT * FROM  LeadInteractionHistory(nolock) kd INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID  Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'LeadInteractionHistory',',')  
End    
             
If exists(SELECT * FROM  customfieldLeadvalue(nolock) cfv INNER JOIN UserLeads(nolock) ul ON  cfv.LeadID = ul.ID  Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'customfieldLeadvalue',',')  
End    
         
If exists(SELECT LPM.* from LeadPipelineMapping(nolock) LPM inner join  UserLeads(nolock) UL ON LPM.LeadID = UL.ID  Where ul.Id=@LeadID)    
Begin  
	Select @retval=concat(@retval,'LeadPipelineMapping',',')  
End    
            
If exists(SELECT LPH.* from LeadScoreHistory_Pipeline(nolock) LPH inner join  UserLeads(nolock) UL ON LPH.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'LeadScoreHistory_Pipeline',',')  
End    
        
If exists(SELECT * from tbl_tsk_taskhistory(nolock) TSKH inner join  UserLeads(nolock) UL ON TSKH.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'tbl_tsk_taskhistory',',')  
End    
        
If exists(SELECT * from tbl_LeadNotes(nolock) LN inner join  UserLeads(nolock) UL ON LN.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'tbl_LeadNotes',',')  
End    
        
If exists(Select * from tbl_LeadDocumentUpload(nolock) LD inner join  UserLeads(nolock) UL ON LD.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'tbl_LeadDocumentUpload',',')  
End    
               
If exists(Select * from lead_score_history(nolock) LSH inner join  UserLeads(nolock) UL ON LSH.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'lead_score_history',',')  
End    
        
If exists(Select * from FinalLeadScores_Pipeline (nolock) FLP inner join  UserLeads(nolock) UL ON FLP.LeadID = UL.ID Where ul.Id=@LeadID)    
Begin    
	Select @retval=concat(@retval,'FinalLeadScores_Pipeline',',')  
End    
                
If exists(Select * from tbl_wf_WorkflowProcessInitMaster(nolock) TWM inner join  UserLeads(nolock) UL ON TWM.LeadID = UL.ID and TWM.IsActive=0 Where ul.Id=@LeadID)    
Begin   
	Select @retval=concat(@retval,'tbl_wf_WorkflowProcessInitMaster',',')  
End    
    
If exists(select * From [10.0.0.135].MYsmsConversations.dbo.convusers with (NOLOCK) where Entity='Lead' and EntityId=@LeadID)    
Begin   
	Select @retval=concat(@retval,'convusers',',')  
End    
    
If exists(select * From [10.0.0.135].MYsmsConversations.dbo.tbl_ims_schedule_message with (NOLOCK) where entityname='Lead' and EntityId=@LeadID)    
Begin   
	Select @retval=concat(@retval,'tbl_ims_schedule_message',',')  
End

return @retval

END  

