/****** Object:  UserDefinedFunction [dbo].[ufn_tp_DateDiffInDHMS]    Script Date: 06-06-26 10:47:01 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


--select dbo.ufn_tp_DateDiffInDHMS('03-Jan2024 14:55:14',getdate())
CREATE   FUNCTION [dbo].[ufn_tp_DateDiffInDHMS]
(
	@StartDate datetime, 
	@EndDate datetime
)
Returns Varchar(100)
AS
BEGIN
	-- declare @StartDate datetime='03-Jan2024 14:55:14', @EndDate datetime=getdate() 
	declare @DiffInHours bigint, @DiffInMinutes bigint, @DiffInSeconds bigint, @seconds_part bigint,
			@minutes_part bigint, @hours_part bigint;

	SELECT @DiffInSeconds=DATEDIFF(SECOND, @StartDate, @EndDate)
	SELECT @seconds_part=@DiffInSeconds % 60, 
			@minutes_part=@DiffInSeconds % 3600, 
			@hours_part = @DiffInSeconds % (3600 * 24)


	return (SELECT
		CONCAT(
		FLOOR(@DiffInSeconds / 3600 / 24), ' days ',
		FLOOR(@hours_part / 3600), ' hours ',
		FLOOR(@minutes_part / 60), ' minutes ',
		@seconds_part, ' seconds'
		) AS difference)
END

GO

