CREATE   FUNCTION [dbo].[ufunc_GetSMSBalance]
(
	@p_mid AS BIGINT,
	@p_userid AS BIGINT
)
RETURNS BIGINT
AS
BEGIN
	DECLARE @smsbalance BIGINT = 0;

	-- Uncomment this section if there are cases where users have virtual credits or are super resellers
	-- IF EXISTS(SELECT 1 FROM user_detail WHERE HasVirtualCredits=1 AND IsSuperReseller=1 AND USER_ID=@p_userid)
	-- BEGIN      
	--     DECLARE @actualbalance BIGINT = ISNULL(
	--         (SELECT TOP 1 balance FROM superresellercredit_details WHERE m_id=@p_mid AND user_id=@p_userid ORDER BY credit_id DESC), 0);
	--     -- This part of the logic is attempting to return a string, which is incompatible with the BIGINT return type
	--     -- You cannot concatenate strings when the return type is BIGINT. You would need to return just the balance.
	-- END
	-- ELSE
	-- BEGIN
		-- Retrieve the most recent balance from the credit_details table for the given user and merchant
		SELECT TOP 1 @smsbalance = COALESCE(balance, 0) FROM credit_details 
            WHERE m_id = @p_mid AND user_id = @p_userid ORDER BY credit_id DESC;
	-- END    

	-- Ensure @smsbalance always returns 0 if no balance was found
	RETURN COALESCE(@smsbalance, 0);
END;

