BEGIN
	DECLARE @WalletBalance BIGINT = 0;

	select top 1 @WalletBalance = balance from intcredit_details where m_id = @p_mid and user_id = @p_userid  order by Credit_ID  desc

	RETURN COALESCE(@WalletBalance, 0);

END;

