CREATE   FUNCTION [dbo].[ufunc_sm_getUserTranpoints]
(
    @P_TranDate datetime,
	@P_userid bigint
)
RETURNS bigint
AS
BEGIN
	
	Declare @TotalPoints bigint =0;

	SELECT @TotalPoints = sum(PH.points) 
	FROM tbl_SM_Employee_Points_History(NOLOCK) PH
	INNER JOIN User_Detail U ON U.User_ID = PH.UserId  
	WHERE   PH.TRANDATE <= @P_TranDate and u.User_ID =@P_userid
	

    RETURN @TotalPoints;

END

