CREATE   FUNCTION [dbo].[usp_GetNextRunTime_schedule]
(@schedule_id   BIGINT, 
 @last_run_time DATETIME
)
RETURNS DATETIME
AS
     BEGIN
         DECLARE @next_run_time DATETIME;
         DECLARE @is_daily INT, @dayfreq NVARCHAR(10);
         DECLARE @is_weekly INT, @weekno NVARCHAR(20), @weekdays NVARCHAR(20);
         DECLARE @is_monthly INT, @months NVARCHAR(50), @monthdates NVARCHAR(100), @lastmonthday INT;
         DECLARE @is_once INT;
         DECLARE @recur_int INT, @recur_unit NVARCHAR(10);
         DECLARE @start_time TIME, @end_time TIME;
         DECLARE @startdate DATE, @expiry DATE, @schedule_name NVARCHAR(100), @is_active INT;      
         -- Get the schedule details     
         SELECT @schedule_name = schedule_name, 
                @is_daily = is_daily, 
                @dayfreq = dayfreq, 
                @is_weekly = is_weekly, 
                @weekno = weekno, 
                @weekdays = weekdays, 
                @is_monthly = is_monthly, 
                @months = months, 
                @monthdates = monthdates, 
                @lastmonthday = lastmonthday, 
                @is_once = is_once, 
                @recur_int = recur_int, 
                @recur_unit = recur_unit, 
                @start_time = start_time, 
                @end_time = end_time, 
                @startdate = startdate, 
                @expiry = expiry, 
                @is_active = is_active
         FROM schedules
         WHERE id = @schedule_id;      
         -- Set initial next run time based on start date and time     
         SET @next_run_time = ISNULL(CAST(@startdate AS DATETIME) + CAST(@start_time AS DATETIME), GETDATE());      
         -- If last_run_time is not null, use it to calculate the next run time     
         IF @last_run_time IS NOT NULL
             BEGIN
                 SET @next_run_time = @last_run_time;          
                 -- Apply recurrence interval if not a one-time schedule         
                 IF @is_once = 0
                     BEGIN
                         IF @recur_unit = 'minutes'
                             BEGIN
                                 SET @next_run_time = DATEADD(MINUTE, @recur_int, @next_run_time);
                         END;
                             ELSE
                             IF @recur_unit = 'hours'
                                 BEGIN
                                     SET @next_run_time = DATEADD(HOUR, @recur_int, @next_run_time);
                             END;
                 END;
         END;      
         -- Adjust for daily schedules     
         IF @is_daily = 1
             BEGIN
                 WHILE @next_run_time <= @last_run_time
                       OR @next_run_time < GETDATE()
                     BEGIN
                         SET @next_run_time = DATEADD(DAY, CAST(@dayfreq AS INT), @next_run_time);
         END;
         END;      
         -- Adjust for weekly schedules     
         IF @is_weekly = 1
             BEGIN
                 DECLARE @weekdays_table TABLE(day_name NVARCHAR(2));
                 DECLARE @day NVARCHAR(2);
                 DECLARE @next_day DATETIME;
                 DECLARE @day_diff INT;
                 INSERT INTO @weekdays_table
                        SELECT value
                        FROM STRING_SPLIT(@weekdays, ',');
                 WHILE @next_run_time <= @last_run_time
                       OR @next_run_time < GETDATE()
                     BEGIN
                         DECLARE weekday_cursor CURSOR
                         FOR SELECT day_name
                             FROM @weekdays_table
                             ORDER BY CASE day_name
                                          WHEN 'Mo'
                                          THEN 1
                                          WHEN 'Tu'
                                          THEN 2
                                          WHEN 'We'
                                          THEN 3
                                          WHEN 'Th'
                                          THEN 4
                                          WHEN 'Fr'
                                          THEN 5
                                          WHEN 'Sa'
                                          THEN 6
                                          WHEN 'Su'
                                          THEN 7
                                      END;
                         OPEN weekday_cursor;
                         FETCH NEXT FROM weekday_cursor INTO @day;
                         WHILE @@FETCH_STATUS = 0
                             BEGIN
                                 SET @day_diff = (7 + CHARINDEX(@day, 'MoTuWeThFrSaSu') / 2 - DATEPART(WEEKDAY, @next_run_time) + 1) % 7;
                                 IF @day_diff = 0
                                     SET @day_diff = 7;
                                 SET @next_day = DATEADD(DAY, @day_diff, @next_run_time);
                                 IF @next_day > @next_run_time
                                     BEGIN
                                         SET @next_run_time = @next_day;
                                         BREAK;
                                 END;
                                 FETCH NEXT FROM weekday_cursor INTO @day;
         END;
                         CLOSE weekday_cursor;
                         DEALLOCATE weekday_cursor;
                         IF @next_run_time <= @last_run_time
                            OR @next_run_time < GETDATE()
                             BEGIN
                                 SET @next_run_time = DATEADD(WEEK, 1, @next_run_time);
                         END;
         END;
         END;      
         -- Adjust for monthly schedules     
         IF @is_monthly = 1
             BEGIN
                 DECLARE @month_table TABLE(month_num INT);
                 DECLARE @monthdate_table TABLE(month_day INT);
                 DECLARE @month INT, @month_day INT;
                 DECLARE @next_month DATETIME;
                 DECLARE @next_month_day DATETIME;
                 INSERT INTO @month_table
                        SELECT value
                        FROM STRING_SPLIT(@months, ',');
                 INSERT INTO @monthdate_table
                        SELECT value
                        FROM STRING_SPLIT(@monthdates, ',');
                 WHILE @next_run_time <= @last_run_time
                       OR @next_run_time < GETDATE()
                     BEGIN
                         DECLARE month_cursor CURSOR
                         FOR SELECT month_num
                             FROM @month_table
                             ORDER BY month_num;
                         OPEN month_cursor;
                         FETCH NEXT FROM month_cursor INTO @month;
                         WHILE @@FETCH_STATUS = 0
                             BEGIN
                                 DECLARE monthday_cursor CURSOR
                                 FOR SELECT month_day
                                     FROM @monthdate_table
                                     ORDER BY month_day;
                                 OPEN monthday_cursor;
                                 FETCH NEXT FROM monthday_cursor INTO @month_day;
                                 WHILE @@FETCH_STATUS = 0
                                     BEGIN
                                         IF @lastmonthday = 1
                                             BEGIN
                                                 SET @next_month_day = EOMONTH(@next_run_time);
                                         END;
                                             ELSE
                                             BEGIN
                                                 SET @next_month_day = DATEADD(DAY, @month_day - 1, DATEFROMPARTS(YEAR(@next_run_time), @month, 1));
                                         END;
                                         IF @next_month_day > @next_run_time
                                             BEGIN
                                                 SET @next_run_time = @next_month_day;
                                                 BREAK;
                                         END;
                                         FETCH NEXT FROM monthday_cursor INTO @month_day;
         END;
                                 CLOSE monthday_cursor;
                                 DEALLOCATE monthday_cursor;
                                 IF @next_run_time > @last_run_time
                                    AND @next_run_time >= GETDATE()
                                     BEGIN
                                         BREAK;
                                 END;
                                 FETCH NEXT FROM month_cursor INTO @month;
         END;
                         CLOSE month_cursor;
                         DEALLOCATE month_cursor;
                         IF @next_run_time <= @last_run_time
                            OR @next_run_time < GETDATE()
                             BEGIN
                                 SET @next_run_time = DATEADD(MONTH, 1, @next_run_time);
                         END;
         END;
         END;      
         -- Ensure next run time is within the expiry date     
         IF @next_run_time > @expiry
             BEGIN
                 SET @next_run_time = NULL;
         END;
         RETURN @next_run_time;
     END;
GO

/****** Object:  UserDefinedFunction [dbo].[ValidateEmail]    Script Date: 06-06-26 10:47:04 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


CREATE   FUNCTION [dbo].[ValidateEmail](@Email NVARCHAR(255))
RETURNS BIT
AS
BEGIN
    DECLARE @IsValid BIT
    SET @IsValid = 0

    IF @Email LIKE '%_@__%.__%'
        AND PATINDEX('%[^a-zA-Z0-9@._-]%', @Email) = 0
        AND LEN(@Email) - LEN(REPLACE(@Email, '.', '')) >= 1
        AND LEN(@Email) - LEN(REPLACE(@Email, '@', '')) = 1
        AND LEFT(@Email, 1) NOT IN ('.', '@')
        AND RIGHT(@Email, 1) NOT IN ('.', '@')
    BEGIN
        SET @IsValid = 1
    END

    RETURN @IsValid
END



GO

/****** Object:  UserDefinedFunction [dbo].[Levenshtein]    Script Date: 06-06-26 10:47:04 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

CREATE   FUNCTION [dbo].[Levenshtein](
    @s nvarchar(4000)
  , @t nvarchar(4000)
  , @max int
)
RETURNS int
WITH SCHEMABINDING
AS
BEGIN
    DECLARE @distance int = 0 -- return variable
          , @v0 nvarchar(4000)-- running scratchpad for storing computed distances
          , @start int = 1      -- index (1 based) of first non-matching character between the two string
          , @i int, @j int      -- loop counters: i for s string and j for t string
          , @diag int          -- distance in cell diagonally above and left if we were using an m by n matrix
          , @left int          -- distance in cell to the left if we were using an m by n matrix
          , @sChar nchar      -- character at index i from s string
          , @thisJ int          -- temporary storage of @j to allow SELECT combining
          , @jOffset int      -- offset used to calculate starting value for j loop
          , @jEnd int          -- ending value for j loop (stopping point for processing a column)
          -- get input string lengths including any trailing spaces (which SQL Server would otherwise ignore)
          , @sLen int = datalength(@s) / datalength(left(left(@s, 1) + '.', 1))    -- length of smaller string
          , @tLen int = datalength(@t) / datalength(left(left(@t, 1) + '.', 1))    -- length of larger string
          , @lenDiff int      -- difference in length between the two strings
    -- if strings of different lengths, ensure shorter string is in s. This can result in a little
    -- faster speed by spending more time spinning just the inner loop during the main processing.
    IF (@sLen > @tLen) BEGIN
        SELECT @v0 = @s, @i = @sLen -- temporarily use v0 for swap
        SELECT @s = @t, @sLen = @tLen
        SELECT @t = @v0, @tLen = @i
    END
    SELECT @max = ISNULL(@max, @tLen)
         , @lenDiff = @tLen - @sLen
    IF @lenDiff > @max RETURN NULL

    -- suffix common to both strings can be ignored
    WHILE(@sLen > 0 AND SUBSTRING(@s, @sLen, 1) = SUBSTRING(@t, @tLen, 1))
        SELECT @sLen = @sLen - 1, @tLen = @tLen - 1

    IF (@sLen = 0) RETURN @tLen

    -- prefix common to both strings can be ignored
    WHILE (@start < @sLen AND SUBSTRING(@s, @start, 1) = SUBSTRING(@t, @start, 1)) 
        SELECT @start = @start + 1
    IF (@start > 1) BEGIN
        SELECT @sLen = @sLen - (@start - 1)
             , @tLen = @tLen - (@start - 1)

        -- if all of shorter string matches prefix and/or suffix of longer string, then
        -- edit distance is just the delete of additional characters present in longer string
        IF (@sLen <= 0) RETURN @tLen

        SELECT @s = SUBSTRING(@s, @start, @sLen)
             , @t = SUBSTRING(@t, @start, @tLen)
    END

    -- initialize v0 array of distances
    SELECT @v0 = '', @j = 1
    WHILE (@j <= @tLen) BEGIN
        SELECT @v0 = @v0 + NCHAR(CASE WHEN @j > @max THEN @max ELSE @j END)
        SELECT @j = @j + 1
    END

    SELECT @jOffset = @max - @lenDiff
         , @i = 1
    WHILE (@i <= @sLen) BEGIN
        SELECT @distance = @i
             , @diag = @i - 1
             , @sChar = SUBSTRING(@s, @i, 1)
             -- no need to look beyond window of upper left diagonal (@i) + @max cells
             -- and the lower right diagonal (@i - @lenDiff) - @max cells
             , @j = CASE WHEN @i <= @jOffset THEN 1 ELSE @i - @jOffset END
             , @jEnd = CASE WHEN @i + @max >= @tLen THEN @tLen ELSE @i + @max END
        WHILE (@j <= @jEnd) BEGIN
            -- at this point, @distance holds the previous value (the cell above if we were using an m by n matrix)
            SELECT @left = UNICODE(SUBSTRING(@v0, @j, 1))
                 , @thisJ = @j
            SELECT @distance = 
                CASE WHEN (@sChar = SUBSTRING(@t, @j, 1)) THEN @diag                    --match, no change
                     ELSE 1 + CASE WHEN @diag < @left AND @diag < @distance THEN @diag    --substitution
                                   WHEN @left < @distance THEN @left                    -- insertion
                                   ELSE @distance                                        -- deletion
                                END    END
            SELECT @v0 = STUFF(@v0, @thisJ, 1, NCHAR(@distance))
                 , @diag = @left
                 , @j = case when (@distance > @max) AND (@thisJ = @i + @lenDiff) then @jEnd + 2 else @thisJ + 1 end
        END
        SELECT @i = CASE WHEN @j > @jEnd + 1 THEN @sLen + 1 ELSE @i + 1 END
    END
    RETURN CASE WHEN @distance <= @max THEN @distance ELSE NULL END
END
GO


